INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('de6c4654-da30-4ccb-9e9f-50d68d867b9b', 'ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'al_firecracker', 'Çatapat', 'Firecracker', 'Düşmanların kafasını karıştıran ve sağır eden gürültülü bir patlayıcı fırlat.', 'Toss a loud explosive that disorients and deafens enemies.', 'Explosive', 14, 120, 1, '{"al_smoke_bomb"}', '{"x": -449, "y": 536}', '{"damage": "1d8 thunder", "condition": "Deafened", "area": "3m radius"}', '🧨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9f8d0c38-270c-4ba8-9912-5c7aa7c0b05d', 'ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'al_poison_gas_grenade', 'Zehirli Gaz Bombası', 'Poison Gas Grenade', 'Zehirli gaz bulutu yayan bir el bombası at.', 'Lob a grenade that emits a cloud of toxic fumes.', 'Explosive', 23, 220, 2, '{"al_firecracker"}', '{"x": -610, "y": 727}', '{"damage": "3d6 poison/turn", "area": "6m radius", "duration": "1 minute"}', '🤢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('99b11c04-7f5f-4681-972c-485165b45cb1', 'ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'al_caustic_blast', 'Yakıcı Patlama', 'Caustic Blast', 'Bir koni şeklinde yoğunlaştırılmış asit patlaması serbest bırakarak zırhı ve eti erit.', 'Release a concentrated burst of acid in a cone, melting armor and flesh.', 'Explosive', 27, 240, 2, '{"al_poison_gas_grenade"}', '{"x": -771, "y": 919}', '{"damage": "4d8 acid", "area": "9m cone", "debuff": "-2 AC"}', '🟢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8edbb211-ab37-4b77-afa3-104afb17659c', 'ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'al_flashbang', 'Kör Eden Bomba', 'Flashbang', 'Geniş bir yarıçaptaki düşmanları sersemleten kör edici bir karışımı patlat.', 'Detonate a blinding concoction that stuns enemies in a wide radius.', 'Explosive', 34, 270, 2, '{"al_caustic_blast"}', '{"x": -932, "y": 1110}', '{"condition": "Blinded, Stunned", "area": "10m radius", "duration": "1 round"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('827a89d3-dbda-4596-b433-06d182047b53', 'ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'al_incendiary_bomb', 'Yangın Bombası', 'Incendiary Bomb', 'Savaş alanına yapışan ateş yayan uçucu bir patlayıcı.', 'A volatile explosive that spreads clinging fire across the battlefield.', 'Explosive', 43, 420, 3, '{"al_flashbang"}', '{"x": -1092, "y": 1302}', '{"damage": "8d6 fire", "burn": "2d6/turn", "area": "6m radius"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0f4d3a9d-4daa-4bd0-9a64-399873760252', 'ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'al_corrosive_cloud', 'Aşındırıcı Bulut', 'Corrosive Cloud', 'İçeridekilerine ağır hasar veren kalıcı bir asit buharı bulutu oluştur.', 'Create a persistent cloud of acid vapor that heavily damages those inside.', 'Explosive', 47, 440, 3, '{"al_incendiary_bomb"}', '{"x": -1253, "y": 1493}', '{"damage": "6d8 acid/turn", "area": "12m radius", "duration": "10 minutes"}', '☁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f0ede279-d20a-4361-b455-eda76d00fb09', 'ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'al_shrapnel_mine', 'Şarapnel Mayını', 'Shrapnel Mine', 'Ustura keskinliğinde metal parçalarıyla patlayan gizli bir simya mayını yerleştir.', 'Plant a hidden alchemical mine that explodes with razor-sharp metal fragments.', 'Explosive', 54, 470, 3, '{"al_corrosive_cloud"}', '{"x": -1414, "y": 1685}', '{"damage": "10d6 piercing", "trigger": "Proximity", "area": "6m radius"}', '⚙️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ac62ca30-ca1c-46ce-ab23-9c7651fd4b2f', 'ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'al_devastating_inferno', 'Yıkıcı Cehennem', 'Devastating Inferno', 'Yıkıcı bir cehennemi ateşleyen devasa bir bomba fırlat.', 'Launch a massive bomb that ignites a devastating inferno.', 'Explosive', 63, 720, 4, '{"al_shrapnel_mine"}', '{"x": -1574, "y": 1876}', '{"damage": "12d6 fire", "area": "18m radius", "structure_damage": "Double"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f8d9eebc-967d-4b66-905f-9b06c5c6acd6', 'ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'al_neurotoxin_burst', 'Nörotoksin Patlaması', 'Neurotoxin Burst', 'Düşmanları felç eden ve boğan nörotoksik gazın sessiz bir patlaması.', 'A silent explosion of neurotoxic gas that paralyzes and suffocates enemies.', 'Explosive', 67, 770, 4, '{"al_devastating_inferno"}', '{"x": -1735, "y": 2068}', '{"condition": "Paralyzed", "damage": "8d8 poison", "area": "9m radius"}', '🐍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c3c8b606-9d25-4a5e-b6a6-7b517d00e038', 'ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'al_acid_rain', 'Asit Yağmuru', 'Acid Rain', 'Gökyüzüne katalitik bir mermi ateşleyerek devasa bir alana yüksek oranda aşındırıcı asit yağmuru yağdır.', 'Fire a catalytic projectile into the sky, causing a shower of highly corrosive acid over a huge area.', 'Explosive', 74, 820, 4, '{"al_neurotoxin_burst"}', '{"x": -1896, "y": 2259}', '{"damage": "10d8 acid/turn", "area": "30m radius", "duration": "1 minute"}', '🌧️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('281f0276-7889-4046-ad8a-1331b72a5851', 'ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'al_doomsday_device', 'Kıyamet Makinesi', 'Doomsday Device', 'Zamanlayıcılı karmaşık bir simya bombası yerleştirerek devasa bir yarıçaptaki her şeye felaket hasarı ver.', 'Deploy a complex alchemical bomb on a timer, dealing catastrophic damage to everything in a massive radius.', 'Explosive', 83, 1200, 5, '{"al_acid_rain"}', '{"x": -2056, "y": 2451}', '{"damage": "20d10 force/fire", "area": "60m radius", "delay": "3 rounds"}', '💣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('80b9b083-179e-4ffd-8137-5de5b5cefde5', 'ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'al_alchemical_nuke', 'Simyasal Nükleer Bomba', 'Alchemical Nuke', 'NİHAİ: Simyasal atomları kıyamet gibi bir patlama için bölen nihai yıkıcı karışım.', 'ULTIMATE: The ultimate destructive concoction, splitting alchemical atoms for an apocalyptic blast.', 'Explosive', 95, 1500, 5, '{"al_doomsday_device"}', '{"x": -2217, "y": 2642}', '{"damage": "40d10 radiant/fire/force", "area": "100m radius", "aftermath": "Radiation (poison)"}', '☢️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a169c716-23de-4cc4-aa73-c2a6dd85b124', 'ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'al_transmuted_bomb', 'Dönüştürülmüş Bomba', 'Transmuted Bomb', 'Çapraz Dal: Patladığında araziyi dönüştürerek sivri uçlar veya derin çukurlar oluşturan bir bomba.', 'Cross-Branch: A bomb that transmutes the terrain upon exploding, creating jagged spikes or deep pits.', 'Cross-Branch', 35, 280, 2, '{"al_liquefy_solid", "al_flashbang"}', '{"x": -173, "y": -100}', '{"area": "9m radius", "terrain": "Difficult/Hazardous", "damage": "4d6 piercing"}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('459cadd5-2d6c-4adb-96b4-bdf1e99400a7', 'ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'al_healing_vapors', 'İyileştirici Buharlar', 'Healing Vapors', 'Çapraz Dal: Yoğun bir şekilde onarıcı gaz patlamasına dönüşerek içindeki herkesi anında iyileştiren bir el bombası.', 'Cross-Branch: A grenade that explodes into a burst of intensely restorative gas, instantly healing all within.', 'Cross-Branch', 55, 480, 3, '{"al_rejuvenating_mist", "al_shrapnel_mine"}', '{"x": -389, "y": -225}', '{"heal": "6d8", "area": "10m radius"}', '🌸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('339c62a6-38d7-4542-97c7-4d807ef268ee', 'ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'al_poisoned_blade_brew', 'Zehirli Kılıç İksiri', 'Poisoned Blade Brew', 'Çapraz Dal: Bir silaha uygulanan ve kenarını sürekli olarak ölümcül zehir salgılayacak şekilde dönüştüren bir karışım.', 'Cross-Branch: A concoction applied to a weapon, transmuting its edge to constantly secrete deadly venom.', 'Cross-Branch', 58, 500, 3, '{"al_rejuvenating_mist", "al_weapon_transmutation"}', '{"x": -606, "y": -350}', '{"damage_bonus": "3d6 poison", "duration": "1 hour"}', '🗡️🧪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1e20e8c2-68c5-48f9-b7ef-d675f9e11c38', 'ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'al_acidic_transmutation', 'Asidik Dönüşüm', 'Acidic Transmutation', 'Çapraz Dal: Katı bir nesneyi veya yaratığı doğrudan şiddetli bir şekilde patlayan bir asit havuzuna dönüştür.', 'Cross-Branch: Turn a solid object or creature directly into a pool of violently explosive acid.', 'Cross-Branch', 75, 850, 4, '{"al_stone_to_flesh", "al_acid_rain"}', '{"x": -822, "y": -475}', '{"target": "Creature or Object", "damage": "14d8 acid", "aoe_burst": "5m radius"}', '🫠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c4a82d57-a8a7-4945-bfc1-874025bec64f', 'ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'al_explosive_elixir', 'Patlayıcı Eliksir', 'Explosive Elixir', 'Çapraz Dal: Muazzam bir güç kazanmak için bu uçucu eliksiri iç, ancak her vuruşta ateşli patlamalar salıver.', 'Cross-Branch: Drink this volatile elixir to gain immense power, but release fiery explosions with every strike.', 'Cross-Branch', 78, 900, 4, '{"al_panacea", "al_acid_rain"}', '{"x": -1039, "y": -600}', '{"melee_aoe": "3m radius", "damage_bonus": "4d6 fire", "duration": "1 minute"}', '🍹💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c4c7a392-d6cb-4798-bd93-94089e8f216d', 'ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'al_living_metal_construct', 'Yaşayan Metal Yaratık', 'Living Metal Construct', 'Çapraz Dal: Hayat veren eliksirlerle bir sıvı metal birikintisini canlandırarak sadık bir golem yarat.', 'Cross-Branch: Animate a puddle of liquid metal with life-giving elixirs, creating a loyal golem.', 'Cross-Branch', 85, 1300, 5, '{"al_flask_of_immortality", "al_master_transmuter"}', '{"x": -1255, "y": -725}', '{"summon": "Iron Golem", "duration": "1 hour", "hp": 200}', '🤖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('db10f53e-73af-44bb-8434-7a348647d2c1', 'ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'al_caustic_regeneration', 'Aşındırıcı Yenilenme', 'Caustic Regeneration', 'Çapraz Dal: Kanın yenileyici aside dönüşür. Vurulduğunda iyileşirsin ve düşmanlara asit püskürtülür.', 'Cross-Branch: Your blood transmutes into regenerative acid. When struck, you heal and enemies are sprayed with acid.', 'Cross-Branch', 88, 1400, 5, '{"al_flask_of_immortality", "al_master_transmuter", "al_doomsday_device"}', '{"x": -1472, "y": -850}', '{"retribution_damage": "4d10 acid", "heal_on_hit": "2d10", "duration": "1 minute"}', '🩸🟢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('40054633-184a-4a74-b4ad-1bb27480160d', 'ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'al_magnum_opus', 'Başyapıt', 'Magnum Opus', 'BÜYÜK NİHAİ: Simyanın zirvesi. Devasa bir alanda gerçekliği yeniden şekillendir: müttefikleri dirilt, düşmanları parçala ve dünyanın kendisini dönüştür.', 'GRAND ULTIMATE: The pinnacle of alchemy. Reshape reality in a huge area: revive allies, disintegrate enemies, and transmute the world itself.', 'Cross-Branch', 100, 1500, 5, '{"al_philosophers_brew", "al_philosophers_stone", "al_alchemical_nuke"}', '{"x": -1688, "y": -975}', '{"aoe": "200m radius", "allies": "Full Heal & Revive", "enemies": "20d12 damage", "terrain": "Absolute Control"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6af63fe2-6eb9-46db-84c2-136a5338e1af', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_aura_vision', 'Aura Görüşü', 'Aura Vision', '15m içindeki hedeflerin aurasını açığa çıkararak ana sınıf türlerini ve gizlenmiş varlıkları tespit eder.', 'Reveals the aura of targets within 15m, detecting their primary class type and hidden presence.', 'Aura Sense', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"range": "15m", "duration": "10 min", "utility": "Detect class & invisibility"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('470b81fb-9f51-4f89-ac9e-9f12c8a64537', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_intent_reading', 'Niyet Okuma', 'Intent Reading', 'Rakibin ufak kas seğirmelerini okuyarak bir sonraki saldırısına karşı +2 Zırh Sınıfı sağlar.', 'Reads the opponent''s subtle muscle twitches, granting +2 AC against their next attack.', 'Aura Sense', 4, 75, 1, '{"af_aura_vision"}', '{"x": 389, "y": -224}', '{"ac_bonus": "+2", "duration": "1 turn"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c46099c6-6915-452b-9d65-de0f09e88f33', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_weakness_spotter', 'Zayıflık Avcısı', 'Weakness Spotter', 'Zırh veya duruştaki zayıflıkları belirleyerek saldırılara 1d4 isabet hasarı ekler.', 'Identifies vulnerabilities in armor or stance, adding 1d4 precision damage to your attacks.', 'Aura Sense', 8, 100, 1, '{"af_intent_reading"}', '{"x": 606, "y": -349}', '{"damage_bonus": "1d4", "duration": "3 turns"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('98534155-6b66-44a8-a2a4-bc37f978792f', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_vital_tracking', 'Hayati Takip', 'Vital Tracking', '30m içindeki bir hedefin sağlık havuzunu ve dayanıklılık seviyesini 1 dakika boyunca takip eder.', 'Tracks the specific health pool and stamina level of a target within 30m for 1 minute.', 'Aura Sense', 14, 120, 1, '{"af_aura_vision"}', '{"x": 822, "y": -474}', '{"range": "30m", "duration": "1 min"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fa72c42e-84a4-462a-b6b8-79fa29850c12', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_aura_pulse', 'Aura Nabzı', 'Aura Pulse', '10m çapında bir nabız yayarak tüm canlıları vurgular ve düşük seviyeli görsel illüzyonları dağıtır.', 'Emits a 10m pulse that highlights all living creatures and dispels low-level visual illusions.', 'Aura Sense', 22, 180, 2, '{"af_weakness_spotter", "af_vital_tracking"}', '{"x": 1039, "y": -599}', '{"radius": "10m", "utility": "Highlight & dispel"}', '📡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2d53637f-a285-4d67-9709-cf8f2da1daf2', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_class_echo', 'Sınıf Yankısı', 'Class Echo', 'Hedefin belirli alt sınıfını ve en yüksek özellik puanını tanımlar.', 'Identifies the specific subclass and highest attribute score of a target.', 'Aura Sense', 26, 210, 2, '{"af_aura_pulse"}', '{"x": 1255, "y": -724}', '{"range": "20m", "information": "Subclass & Highest Stat"}', '👤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('29ef5efd-284a-485e-895a-8f0061673e7c', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_preemptive_step', 'Öngörülü Adım', 'Preemptive Step', 'Gelen bir yakın dövüş saldırısı isabet etmeden önce tepki olarak 3m''ye kadar hareket edin.', 'Move up to 3m as a reaction before an incoming melee attack connects.', 'Aura Sense', 32, 250, 2, '{"af_class_echo"}', '{"x": 1472, "y": -849}', '{"movement": "3m", "type": "Reaction"}', '👣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('72e35f62-ba15-46a1-bcb6-3fce57dc4e6e', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_mind_glimpse', 'Zihin Pırıltısı', 'Mind Glimpse', 'Hedefin yüzeysel düşüncelerini okuyarak bir sonraki tur kullanacakları büyüyü veya yeteneği tam olarak tahmin edin.', 'Read the target''s surface thoughts to predict the exact spell or skill they will use next turn.', 'Aura Sense', 38, 290, 2, '{"af_class_echo"}', '{"x": 1688, "y": -974}', '{"duration": "1 turn", "utility": "Predict next action"}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('014f19f8-1457-4fc7-a7d0-34a4cd637324', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_flaw_expose', 'Kusur İfşası', 'Flaw Expose', 'Düşmanın dövüş stilindeki kritik bir kusuru ortaya çıkararak Zırh Sınıfını 3 tur boyunca 3 azaltır.', 'Expose a critical flaw in the enemy''s fighting style, reducing their AC by 3 for 3 turns.', 'Aura Sense', 42, 360, 3, '{"af_preemptive_step", "af_mind_glimpse"}', '{"x": 1905, "y": -1099}', '{"ac_reduction": "-3", "duration": "3 turns"}', '🔓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a435fb54-faaf-47ad-90db-d714e5c1405a', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_anticipation_stance', 'Beklenti Duruşu', 'Anticipation Stance', 'Yüksek farkındalık durumuna geçin. Bu tur size yapılan ilk yakın dövüş saldırısına otomatik olarak 1d8 fiziksel hasarla karşılık verirsiniz.', 'Enter a state of hyper-awareness. You automatically counter the first melee attack against you this turn with 1d8 physical damage.', 'Aura Sense', 48, 420, 3, '{"af_flaw_expose"}', '{"x": 2121, "y": -1224}', '{"damage": "1d8", "type": "Auto-counter"}', '🧘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c6c7e9de-ebc2-41ce-a676-2d9c6237698d', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_aura_sever', 'Aura Kesiği', 'Aura Sever', 'Hedefin ki akışına vurarak 1 tur boyunca sınıfa özgü yeteneklerini kullanmalarını engeller.', 'Strike the target''s ki flow, preventing them from using class-specific features for 1 turn.', 'Aura Sense', 56, 480, 3, '{"af_flaw_expose"}', '{"x": 2338, "y": -1349}', '{"duration": "1 turn", "utility": "Disable class features"}', '✂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('955f4416-f806-41c8-8b71-c17ff5e33714', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_absolute_read', 'Mutlak Okuma', 'Absolute Read', 'Hedefin hareketlerini kusursuzca tahmin edin. 3 tur boyunca kritik vuruş yapamazlar veya saldırılarınızdan kaçamazlar.', 'Perfectly predict the target''s movements. They cannot critically strike or dodge your attacks for 3 turns.', 'Aura Sense', 64, 650, 4, '{"af_anticipation_stance", "af_aura_sever"}', '{"x": 2554, "y": -1474}', '{"duration": "3 turns", "debuff": "No crits/dodges"}', '📖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('97ca5b39-cfe5-43b8-8929-569027f3a6dd', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_soul_gaze', 'Ruh Bakışı', 'Soul Gaze', 'Hedefin ruhuna bakarak kesin Can değerini, seviyesini ve tüm yetenek bekleme sürelerini ortaya çıkarın.', 'Peer into the target''s soul, revealing their exact HP, level, and all skill cooldowns.', 'Aura Sense', 74, 800, 4, '{"af_absolute_read"}', '{"x": 2771, "y": -1599}', '{"range": "20m", "utility": "Reveal all stats/cooldowns"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('04fc79bc-8a0f-4917-abb4-9440caf6ab87', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_omniscient_eye', 'Her Şeyi Gören Göz', 'Omniscient Eye', 'Nihai. Tam durumsal farkındalık kazanın. 3 tur boyunca baskınlara ve kritik vuruşlara karşı bağışıklık kazanırsınız ve saldırılarınızın isabet şansı %100 olur.', 'Ultimate. Gain total situational awareness. For 3 turns, you are immune to surprises, critical hits, and your attacks have a 100% hit chance.', 'Aura Sense', 90, 1200, 5, '{"af_soul_gaze"}', '{"x": 2987, "y": -1724}', '{"duration": "3 turns", "hit_chance": "100%", "immunity": "Surprise & Crits"}', '🧿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('06f34978-2811-4a99-9a54-df21829bb1dd', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_shifting_guard', 'Değişken Siper', 'Shifting Guard', 'Hasar aldıktan sonra, bir sonraki turunuzun sonuna kadar o hasar türüne karşı direnç kazanırsınız.', 'After taking damage, gain resistance to that specific damage type until the end of your next turn.', 'Adaptive Combat', 2, 60, 1, '{}', '{"x": 128, "y": 153}', '{"resistance": "Match last damage type", "duration": "1 turn"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6125a081-5a8b-49a7-9d7f-c4f25667342f', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_mimic_strike', 'Taklit Vuruşu', 'Mimic Strike', 'Silah hasarı türünüz, size vuran son düşmanın hasar türüyle eşleşecek şekilde değişir.', 'Your weapon damage type shifts to match the damage type of the last enemy that hit you.', 'Adaptive Combat', 6, 80, 1, '{"af_shifting_guard"}', '{"x": 289, "y": 344}', '{"damage_type": "Matches enemy", "duration": "Until changed"}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5d3f8623-878f-4bad-9c57-3ab925e35622', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_fluid_footwork', 'Akışkan Adımlar', 'Fluid Footwork', 'Zorlu arazi cezalarını görmezden gelin ve 2 tur boyunca +3m hareket hızı kazanın.', 'Ignore difficult terrain penalties and gain +3m movement speed for 2 turns.', 'Adaptive Combat', 10, 110, 1, '{"af_shifting_guard"}', '{"x": 449, "y": 536}', '{"speed_bonus": "+3m", "duration": "2 turns"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d4ff3b60-d3d6-44dc-8a23-920069ebc506', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_reactive_parry', 'Tepkisel Savuşturma', 'Reactive Parry', 'Bir fiziksel saldırıyı veya büyüyü savuşturmak için tepkinizi kullanarak gelen hasarı 1d10 + GÜÇ değiştiricisi kadar azaltın.', 'Use your reaction to parry a physical or spell attack, reducing incoming damage by 1d10 + STR modifier.', 'Adaptive Combat', 16, 140, 1, '{"af_mimic_strike", "af_fluid_footwork"}', '{"x": 610, "y": 727}', '{"damage_reduction": "1d10 + STR", "type": "Reaction"}', '🤺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('30a4456d-3e3e-45d2-9b0d-23ee623460ec', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_elemental_adaptation', 'Elementel Adaptasyon', 'Elemental Adaptation', 'Auranızı odaklayarak 10 dakika boyunca seçili bir elementel hasar türüne karşı direnç kazanın.', 'Focus your aura to gain resistance to one chosen elemental damage type for 10 minutes.', 'Adaptive Combat', 24, 190, 2, '{"af_reactive_parry"}', '{"x": 771, "y": 919}', '{"duration": "10 min", "resistance": "1 chosen element"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('61a67a1c-9cf7-4007-b20c-a4d123073d77', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_form_breaker', 'Form Kırıcı', 'Form Breaker', 'Savunma duruşlarını cezalandırmak için tasarlanmış ağır bir vuruş. 2d8 ezme hasarı verir ve kalkanları yok sayar.', 'A heavy strike designed to punish defensive stances. Deals 2d8 bludgeoning damage and ignores shields.', 'Adaptive Combat', 28, 220, 2, '{"af_elemental_adaptation"}', '{"x": 932, "y": 1110}', '{"damage": "2d8 bludgeoning", "utility": "Ignores shields"}', '🔨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7d9d03f7-027e-4b5e-b05b-2427d59d7db6', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_spell_deflection', 'Büyü Saptırma', 'Spell Deflection', '5m içindeki sihirli bir mermiyi savuşturarak yalnızca yarım hasar alın.', 'Swat away a magical projectile within 5m, taking only half damage.', 'Adaptive Combat', 34, 260, 2, '{"af_elemental_adaptation"}', '{"x": 1092, "y": 1302}', '{"range": "5m", "damage_taken": "Half", "type": "Reaction"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fb076c07-ec17-447a-b8cd-c0c12e09422e', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_counter_tempo', 'Karşı Ritim', 'Counter Tempo', 'Bir rakip size karşı yaptığı yakın dövüş saldırısını ıskalarsa, derhal ona bir saldırı yapın.', 'If an opponent misses a melee attack against you, immediately make one attack against them.', 'Adaptive Combat', 39, 290, 2, '{"af_form_breaker", "af_spell_deflection"}', '{"x": 1253, "y": 1493}', '{"type": "Reaction Attack"}', '⏱️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('321f93e2-c56c-4181-9829-3cdb83e9473b', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_adaptive_plating', 'Adaptif Zırhlanma', 'Adaptive Plating', 'Çarpışmadan hemen önce auranızı katılaştırarak, gelen hasarın %20''si kadar geçici Can kazanın.', 'Solidify your aura just before impact, gaining temporary HP equal to 20% of the incoming damage.', 'Adaptive Combat', 44, 380, 3, '{"af_counter_tempo"}', '{"x": 1414, "y": 1685}', '{"temp_hp": "20% of damage", "duration": "Instant"}', '🦾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('930d9c4b-e58b-429c-aa3c-6beea501fe3b', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_mage_slayer_stance', 'Büyücü Katili Duruşu', 'Mage Slayer Stance', 'Büyülere karşı kurtarma zarlarında avantaj kazanın ve büyü yapan sınıflara karşı +2d6 hasar verin.', 'Gain advantage on saving throws against spells and deal +2d6 damage against magic-casting classes.', 'Adaptive Combat', 50, 440, 3, '{"af_adaptive_plating"}', '{"x": 1574, "y": 1876}', '{"damage_bonus": "+2d6 vs casters", "advantage": "Spell saves"}', '🧙‍♂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e746ce91-32ca-4b9a-b21b-34cc9910c321', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_beast_tamer_stance', 'Canavar Terbiyecisi Duruşu', 'Beast Tamer Stance', 'Vahşi yaratıkların hareketlerinde ustalaşarak canavarlara, çağrılan varlıklara ve druid formlarına +2d6 hasar verin.', 'Master the movements of wild creatures, dealing +2d6 damage to beasts, summoned entities, and druidic forms.', 'Adaptive Combat', 58, 490, 3, '{"af_adaptive_plating"}', '{"x": 1735, "y": 2068}', '{"damage_bonus": "+2d6 vs beasts/summons"}', '🦁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bbd5e8ff-fbd4-4963-83f8-55f87891da09', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_mirror_stance', 'Ayna Duruşu', 'Mirror Stance', 'Rakibinizin bir pasif yeteneğini veya duruşunu 1 dakika boyunca kusursuzca kopyalayın.', 'Perfectly copy one passive skill or stance of your opponent for 1 minute.', 'Adaptive Combat', 66, 680, 4, '{"af_mage_slayer_stance", "af_beast_tamer_stance"}', '{"x": 1896, "y": 2259}', '{"duration": "1 min", "utility": "Copy passive"}', '🎭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('19c843da-d088-49e3-ac61-692c21d117ba', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_perfect_counter', 'Kusursuz Karşılık', 'Perfect Counter', 'Gelen bir fiziksel saldırıyı tamamen sıfırlayın ve anında 4d10 fiziksel hasar veren bir vuruşla misilleme yapın.', 'Nullify one incoming physical attack completely and instantly retaliate with a strike dealing 4d10 physical damage.', 'Adaptive Combat', 76, 820, 4, '{"af_mirror_stance"}', '{"x": 2056, "y": 2451}', '{"damage": "4d10 physical", "nullify": "1 attack"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7bb1f540-28ba-4c70-9125-52ab835776f9', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_chameleon_warrior', 'Bukalemun Savaşçı', 'Chameleon Warrior', 'Nihai. Herhangi bir rakibin sınıfına anında uyum sağlayın. 1 dakika boyunca onlara karşı tüm zarlarda avantaj elde eder ve yeteneklerinden yarım hasar alırsınız.', 'Ultimate. Instantly adapt to any opponent''s class. For 1 minute, you have advantage on all rolls against them and take half damage from their abilities.', 'Adaptive Combat', 92, 1250, 5, '{"af_perfect_counter"}', '{"x": 2217, "y": 2642}', '{"duration": "1 min", "advantage": "All rolls vs target", "damage_reduction": "50%"}', '🦎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6e6bb7a2-6428-48ea-a423-4359b5220037', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_ki_fist', 'Ki Yumruğu', 'Ki Fist', 'Auranızı vuruşlarınıza yönlendirerek 3 tur boyunca yakın dövüş saldırılarınıza 1d6 güç hasarı ekleyin.', 'Channel aura into your strikes, adding 1d6 force damage to your melee attacks for 3 turns.', 'Ki Strike', 1, 50, 1, '{}', '{"x": -128, "y": 153}', '{"damage_bonus": "1d6 force", "duration": "3 turns"}', '👊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b8641be2-238b-4e18-9424-a073d1028c18', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_aura_slash', 'Aura Kesik', 'Aura Slash', 'Silahınızı sallayarak kiden oluşan bir hilal fırlatın ve 10m uzağa kadar 1d8 kesici hasar verin.', 'Swing your weapon to launch a crescent of ki, dealing 1d8 slashing damage up to 10m away.', 'Ki Strike', 5, 75, 1, '{"af_ki_fist"}', '{"x": -289, "y": 344}', '{"damage": "1d8 slashing", "range": "10m"}', '🌙');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e317c743-1005-4a6f-a40b-c8ff1460977b', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_pressure_point', 'Basınç Noktası', 'Pressure Point', 'Düşmanın hayati bir ki düğümüne vurarak hareket hızını 2 tur boyunca 3m azaltın.', 'Strike a vital ki node on the enemy, reducing their movement speed by 3m for 2 turns.', 'Ki Strike', 9, 100, 1, '{"af_ki_fist"}', '{"x": -449, "y": 536}', '{"speed_reduction": "-3m", "duration": "2 turns"}', '👈');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('72741a84-a548-4dc5-a09d-a98dd776c19e', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_spirit_shove', 'Ruh İtişi', 'Spirit Shove', 'Avucunuzdan saf ki patlaması salıvererek hedefi sizden 5m geriye doğru itin.', 'Unleash a blast of pure ki from your palm, pushing the target 5m directly away from you.', 'Ki Strike', 15, 130, 1, '{"af_aura_slash", "af_pressure_point"}', '{"x": -610, "y": 727}', '{"push": "5m"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('84890c35-01b3-4c5d-b908-542683a34ef9', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_ki_surge', 'Ki Dalgalanması', 'Ki Surge', 'Bacaklarınızı ki ile güçlendirerek aynı eylem içinde depar atıp saldırı yapmanızı sağlar, +2d6 hasar verir.', 'Empower your legs with ki, allowing you to dash and make an attack in the same action, dealing +2d6 damage.', 'Ki Strike', 21, 175, 2, '{"af_spirit_shove"}', '{"x": -771, "y": 919}', '{"damage_bonus": "+2d6", "utility": "Dash + Attack"}', '🏃‍♂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f87fd6b2-fa22-463f-ba85-bf1c87529380', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_aura_shockwave', 'Aura Şok Dalgası', 'Aura Shockwave', 'Yere vurarak 5m yarıçapında tüm yakın düşmanlara 3d6 güç hasarı veren bir şok dalgası yaratın.', 'Slam the ground, creating a 5m radius shockwave that deals 3d6 force damage to all nearby enemies.', 'Ki Strike', 25, 200, 2, '{"af_ki_surge"}', '{"x": -932, "y": 1110}', '{"damage": "3d6 force", "radius": "5m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('95a33804-1fe3-419b-a77a-d4170c4ade6e', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_nerve_strike', 'Sinir Vuruşu', 'Nerve Strike', 'Hassas bir ki vuruşuyla hedefin sinir sistemini bozarak bir sonraki saldırılarında dezavantaj almalarına neden olun.', 'Disrupt the target''s nervous system with a precise ki strike, imposing disadvantage on their next attack.', 'Ki Strike', 31, 240, 2, '{"af_ki_surge"}', '{"x": -1092, "y": 1302}', '{"debuff": "Disadvantage on next attack"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9e795a49-424d-4cbc-bd80-e34ec56a11c1', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_phantom_blow', 'Hayalet Vuruş', 'Phantom Blow', 'Kiniz silahınızı kısa bir süreliğine fazdan geçirerek bir sonraki saldırınızın fiziksel zırhı tamamen yok saymasını sağlar.', 'Your ki phase-shifts your weapon briefly, causing your next attack to completely ignore physical armor.', 'Ki Strike', 37, 280, 2, '{"af_aura_shockwave", "af_nerve_strike"}', '{"x": -1253, "y": 1493}', '{"utility": "Ignores armor", "duration": "1 attack"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8f82f3d2-068a-427e-ba2a-d37b7ad79397', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_ki_explosion', 'Ki Patlaması', 'Ki Explosion', '10m içindeki bir noktayı ki enerjisiyle aşırı yükleyerek patlatın ve 8m alan hasarı içinde 5d8 güç hasarı verin.', 'Overload a point within 10m with ki energy, detonating it for an 8m AoE dealing 5d8 force damage.', 'Ki Strike', 41, 350, 3, '{"af_phantom_blow"}', '{"x": -1414, "y": 1685}', '{"damage": "5d8 force", "range": "10m", "radius": "8m"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('51754314-5362-4584-b461-b44295141e57', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_aura_bind', 'Aura Bağlama', 'Aura Bind', 'Hedefin gölgesine ki kollarını göndererek, GÜÇ kurtarmasını geçemezlerse 1 tur boyunca felç edin.', 'Send tendrils of ki into the target''s shadow, paralyzing them for 1 turn unless they pass a STR save.', 'Ki Strike', 47, 410, 3, '{"af_ki_explosion"}', '{"x": -1574, "y": 1876}', '{"duration": "1 turn", "status": "Paralyzed"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5f269019-5207-4d0f-8780-d055115a6dc3', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_resonating_strike', 'Yankılanan Vuruş', 'Resonating Strike', 'Hedefin içine gizli ki yerleştirin. Hedef, sonraki 3 turunun başında 2d6 güç hasarı alır.', 'Plant latent ki inside the target. They take 2d6 force damage at the start of their next 3 turns.', 'Ki Strike', 55, 470, 3, '{"af_ki_explosion"}', '{"x": -1735, "y": 2068}', '{"damage": "2d6 force per turn", "duration": "3 turns"}', '🔔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6adf6e75-b22a-4f8c-84dc-6b9e005bc485', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_ki_meteor', 'Ki Meteoru', 'Ki Meteor', 'Havaya sıçrayın ve yoğun kiye bürünmüş halde yere çarparak 15m yarıçapında 8d10 güç hasarı verin.', 'Leap into the air and crash down clad in dense ki, dealing 8d10 force damage in a 15m radius.', 'Ki Strike', 62, 620, 4, '{"af_aura_bind", "af_resonating_strike"}', '{"x": -1896, "y": 2259}', '{"damage": "8d10 force", "radius": "15m"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b00c4b82-c571-4b45-bfb9-28027ef70c00', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_soul_shatter', 'Ruh Parçalama', 'Soul Shatter', 'Doğrudan merkeze yönelik yıkıcı bir vuruş. 6d12 güç hasarı verir ve hedefin maksimum canını alınan hasar kadar azaltır.', 'A devastating strike directly to the core. Deals 6d12 force damage and reduces the target''s maximum HP by the damage taken.', 'Ki Strike', 72, 780, 4, '{"af_ki_meteor"}', '{"x": -2056, "y": 2451}', '{"damage": "6d12 force", "debuff": "Max HP reduction"}', '💔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('990f0847-5198-49f4-84aa-0091edcb9095', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_asura_strike', 'Asura Vuruşu', 'Asura Strike', 'Nihai. Kinizin tamamını tek, dünyayı sarsan bir vuruşa yönlendirin. 15d10 güç hasarı verir ve tüm dirençleri ve bağışıklıkları aşar.', 'Ultimate. Channel the totality of your ki into a single, world-shaking blow. Deals 15d10 force damage and bypasses all resistances and immunities.', 'Ki Strike', 90, 1200, 5, '{"af_soul_shatter"}', '{"x": -2217, "y": 2642}', '{"damage": "15d10 force", "utility": "Ignores resistances/immunities"}', '👹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('93b1120c-493f-4529-8501-9c53fc679ff1', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_insightful_blow', 'İçgörülü Vuruş', 'Insightful Blow', 'Bir auranın açığa çıkmış zayıf noktasına tam olarak vurarak +3d6 isabet hasarı ekler.', 'Strike exactly at the revealed weak point of an aura, adding +3d6 precision damage.', 'Cross-Branch', 30, 230, 2, '{"af_weakness_spotter", "af_aura_slash"}', '{"x": -173, "y": -100}', '{"damage_bonus": "+3d6"}', '💡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8401868e-51ec-4c2a-ba84-45f8a2c921f0', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_adaptive_ki', 'Adaptif Ki', 'Adaptive Ki', 'Ki hasar türünüzü 1 dakika boyunca hedefin en derin zayıflığıyla eşleşecek şekilde değiştirin.', 'Change your ki damage type to match the target''s deepest vulnerability for 1 minute.', 'Cross-Branch', 45, 390, 3, '{"af_elemental_adaptation", "af_ki_surge"}', '{"x": -389, "y": -225}', '{"duration": "1 min", "damage_type": "Target Vulnerability"}', '🌈');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4f2a86f2-9754-4e3d-953f-d4fe9b9a6093', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_predictive_dodge', 'Öngörülü Kaçınma', 'Predictive Dodge', 'Bir saldırıyı başlamadan önce hissederek %100 başarıyla kaçının. Çatışma başına bir kez kullanılabilir.', 'Sense an attack before it begins, dodging it with 100% success. Usable once per combat.', 'Cross-Branch', 52, 450, 3, '{"af_preemptive_step", "af_form_breaker"}', '{"x": -606, "y": -350}', '{"dodge_chance": "100%", "limit": "Once per combat"}', '🕊️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('52552661-1da1-41c1-b21d-a5133ed6372e', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_aura_theft', 'Aura Hırsızlığı', 'Aura Theft', 'Düşmanın aurasını delip geçerek onların aktif sınıf güçlendirmelerinden birini kendiniz için çalın.', 'Strike through the enemy''s aura to steal one of their active class buffs for yourself.', 'Cross-Branch', 65, 660, 4, '{"af_flaw_expose", "af_phantom_blow"}', '{"x": -822, "y": -475}', '{"utility": "Steal 1 active buff"}', '🧛‍♂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('12bc15b8-2f38-4870-a41f-440282127aca', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_class_breaker', 'Sınıf Kırıcı', 'Class Breaker', 'Düşmanın temel kimliğini bozarak alt sınıf özelliklerini 2 tur devre dışı bırakın ve 6d8 hasar verin.', 'Disrupt the enemy''s core identity, disabling their subclass features for 2 turns and dealing 6d8 damage.', 'Cross-Branch', 70, 750, 4, '{"af_mage_slayer_stance", "af_resonating_strike"}', '{"x": -1039, "y": -600}', '{"damage": "6d8 force", "duration": "2 turns", "debuff": "Disable subclass features"}', '🚫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6aa18fb5-4ed3-4c9a-bbbc-e7587bea3686', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_mind_body_sync', 'Zihin Beden Senkronu', 'Mind Body Sync', 'Düşmanı okumanızı savunmanızla anında senkronize edin. Bir saldırıya karşı sıfır hasar alarak karşılık verin.', 'Instantly sync your read of the enemy with your defense. Counter an attack while taking zero damage from it.', 'Cross-Branch', 78, 850, 4, '{"af_anticipation_stance", "af_adaptive_plating"}', '{"x": -1255, "y": -725}', '{"damage_taken": "0", "type": "Counterattack"}', '☯️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c4ae5933-e6f2-4d66-9289-65d8d272ec53', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_karmic_retribution', 'Karmik İlahi Adalet', 'Karmic Retribution', 'Yıkıcı bir vuruşu tahmin edin ve amaçlanan hasarının %200''ünü saf güç hasarı olarak saldırgana geri yansıtın.', 'Predict a devastating blow and reflect 200% of its intended damage back at the attacker as pure force damage.', 'Cross-Branch', 88, 1100, 5, '{"af_absolute_read", "af_perfect_counter"}', '{"x": -1472, "y": -850}', '{"damage_reflect": "200% as force damage"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('36ee5c86-7888-4fc9-a0b2-1e3f4f4cad8c', '30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'af_aura_god_incarnate', 'Aura Tanrısı Enkarnasyonu', 'Aura God Incarnate', 'Büyük Nihai. Tüm dövüş formlarının aşkın ustası olun. 1 dakika boyunca tüm sınıfa özgü etkilere bağışıklık kazanırsınız, 30m ışınlanma hızı kazanırsınız ve tüm vuruşlarda 10d10+50 hasar verirsiniz.', 'Grand Ultimate. Become the transcendent master of all combat forms. For 1 minute, you are immune to all class-specific effects, gain a 30m teleport speed, and deal 10d10+50 damage on all hits.', 'Cross-Branch', 100, 1500, 5, '{"af_omniscient_eye", "af_chameleon_warrior", "af_asura_strike"}', '{"x": -1688, "y": -975}', '{"duration": "1 min", "immunity": "Class effects", "speed": "30m teleport", "damage_bonus": "10d10+50"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b9b9fe4c-7697-4fe6-9c58-adcf55d17a72', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_summon_companion', 'Yoldaş Çağırma', 'Summon Companion', 'Yanınızda savaşması için sadık bir canavar yoldaş çağırır. Yoldaşın istatistikleri seviyenizle artar.', 'Summons a loyal beast companion to fight by your side. Companion stats scale with your level.', 'Companion', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"duration": "Permanent", "range": "5m"}', '🐺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a5c858e1-4321-44f9-92a4-0d17ec8d9255', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_mend_companion', 'Yoldaşı İyileştir', 'Mend Companion', 'Doğanın büyüsünü kullanarak yoldaşınızı iyileştirir.', 'Heals your companion using nature''s magic.', 'Companion', 3, 75, 1, '{"bt_summon_companion"}', '{"x": 389, "y": -224}', '{"healing": "2d8 + WIS modifier", "range": "5m"}', '🩹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5a078cf9-c659-49f5-acf7-d65f4abaaa55', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_guard_command', 'Koruma Emri', 'Guard Command', 'Yoldaşınıza yakındaki bir müttefike yönelik saldırıları engellemesini emreder.', 'Commands your companion to intercept attacks against a nearby ally.', 'Companion', 5, 100, 1, '{"bt_summon_companion"}', '{"x": 606, "y": -349}', '{"bonus_ac": 2, "range": "5m"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('67a1bf87-a0d5-4d69-b923-9566f25395db', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_fetch', 'Getir', 'Fetch', 'Yoldaşınıza düşmanları silahsızlandırmasını veya uzaktan eşya getirmesini emreder.', 'Commands your companion to disarm enemies or retrieve items from afar.', 'Companion', 8, 120, 1, '{"bt_summon_companion"}', '{"x": 822, "y": -474}', '{"range": "20m", "duration": "Instant"}', '🦴');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b40fa590-71e6-4909-b8a8-edbc24e58328', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_companion_fury', 'Yoldaş Öfkesi', 'Companion Fury', 'Yoldaşınızı kör edici bir hızla saldırmaya kışkırtır.', 'Incites your companion to attack with blinding speed.', 'Companion', 22, 200, 2, '{"bt_guard_command"}', '{"x": 1039, "y": -599}', '{"attacks": 2, "duration": "3 turns"}', '💢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d60d10d4-1e57-48a0-ac6b-54a7a0a0e3b6', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_shared_senses', 'Ortak Duyular', 'Shared Senses', 'Yoldaşınızın duyuları aracılığıyla görmenizi ve duymanızı sağlar.', 'Allows you to see and hear through your companion''s senses.', 'Companion', 25, 220, 2, '{"bt_summon_companion"}', '{"x": 1255, "y": -724}', '{"range": "1000m", "duration": "1 hour"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d6fd7dba-2e37-4650-82b4-ed8c15dfb88c', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_revive_companion', 'Yoldaşı Dirilt', 'Revive Companion', 'Düşen bir yoldaşı sağlığının bir kısmıyla hayata döndürür.', 'Brings a fallen companion back to life with a portion of its health.', 'Companion', 30, 280, 2, '{"bt_mend_companion"}', '{"x": 1472, "y": -849}', '{"healing": "50% Max HP", "range": "Touch"}', '🌟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('06dbe0ed-5060-4196-8d64-99f68ebf6188', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_bestial_enlargement', 'Vahşi Büyüme', 'Bestial Enlargement', 'Yoldaşınızın boyutunu geçici olarak büyüterek devasa hasar ve canlılık kazandırır.', 'Temporarily increases your companion''s size, granting massive damage and vitality.', 'Companion', 42, 400, 3, '{"bt_companion_fury"}', '{"x": 1688, "y": -974}', '{"bonus_damage": "2d6", "temp_hp": 10, "duration": "10 minutes"}', '🦍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f848ff13-98a0-4d99-9a65-76dcdd45d9e3', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_companion_armor', 'Yoldaş Zırhı', 'Companion Armor', 'Yoldaşınıza kalın, ağaç kabuğu gibi doğal bir zırh kazandırır.', 'Grants your companion thick, bark-like natural armor.', 'Companion', 45, 420, 3, '{"bt_guard_command"}', '{"x": 1905, "y": -1099}', '{"bonus_ac": 4, "duration": "1 hour"}', '🪵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('30cb2bdf-b96b-4979-bac5-ca0b9b02ba7d', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_coordinated_strike', 'Koordineli Saldırı', 'Coordinated Strike', 'Bir hedefe vurduğunuzda, yoldaşınız anında ücretsiz bir saldırı ile takip eder.', 'When you hit a target, your companion instantly follows up with a free attack.', 'Companion', 50, 450, 3, '{"bt_companion_fury"}', '{"x": 2121, "y": -1224}', '{"bonus_damage": "3d6", "range": "Weapon Range"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ed83c8a8-5b71-4784-ad4d-72faee55c7d2', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_mythic_companion', 'Efsanevi Yoldaş', 'Mythic Companion', 'Yoldaşınızı efsanevi bir yaratığa evrimleştirerek elementsel hasar ve artırılmış sağlık kazandırır.', 'Evolves your companion into a mythic creature, granting elemental damage and increased health.', 'Companion', 62, 700, 4, '{"bt_bestial_enlargement"}', '{"x": 2338, "y": -1349}', '{"bonus_damage": "1d8 elemental", "bonus_hp": 20, "duration": "Permanent"}', '🐉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('503f7b8c-fce3-4a12-aacf-7fe9802ad354', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_soul_bond', 'Ruh Bağı', 'Soul Bond', 'Siz ve yoldaşınız tek bir yaşam havuzunu paylaşırsınız. Alınan hasar eşit olarak bölünür.', 'You and your companion share a single life pool. Any damage taken is split evenly.', 'Companion', 68, 750, 4, '{"bt_revive_companion", "bt_companion_armor"}', '{"x": 2554, "y": -1474}', '{"damage_split": "50%", "range": "30m", "duration": "Permanent"}', '💞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('22963d84-440d-46d6-963c-929bd56d92ae', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_ferocious_roar', 'Vahşi Kükreme', 'Ferocious Roar', 'Yoldaşınız korkutucu bir kükreme salarak geniş bir yarıçaptaki tüm düşmanları korkutur.', 'Your companion unleashes a terrifying roar, frightening all enemies in a wide radius.', 'Companion', 75, 800, 4, '{"bt_bestial_enlargement"}', '{"x": 2771, "y": -1599}', '{"radius": "15m", "duration": "1 minute"}', '🦁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c0448cee-6ac7-4142-87eb-ab62443cd278', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_alpha_predator', 'Alfa Yırtıcı', 'Alpha Predator', 'Nihai Yetenek. Yoldaşınız mutlak zirvesine ulaşır, devasa büyür, yıkıcı hasar verir ve hızla yenilenir.', 'Ultimate. Your companion reaches its absolute pinnacle, growing massive, dealing devastating damage, and regenerating rapidly.', 'Companion', 90, 1200, 5, '{"bt_mythic_companion", "bt_soul_bond"}', '{"x": 2987, "y": -1724}', '{"bonus_damage": "5d10", "regeneration": "20 HP/turn", "duration": "10 minutes"}', '🦖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9fb47ce0-8460-4f9a-8889-900f2d3b3294', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_animal_friendship', 'Hayvan Dostluğu', 'Animal Friendship', 'Vahşi bir canavarı efsunlayarak saldırmasını engeller ve size dost olmasını sağlar.', 'Charms a wild beast, preventing it from attacking and making it friendly to you.', 'Beastmaster', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"max_cr": "User Level", "duration": "24 hours"}', '🦌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('01a21a56-39c0-4398-ba24-de766452369b', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_speak_with_animals', 'Hayvanlarla Konuşma', 'Speak with Animals', 'Tüm doğal canavarları anlama ve onlarla iletişim kurma yeteneği kazandırır.', 'Grants the ability to understand and communicate with all natural beasts.', 'Beastmaster', 2, 60, 1, '{}', '{"x": 289, "y": 344}', '{"duration": "10 minutes"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('87031a5d-a7b3-4648-9971-349cd542f209', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_summon_swarm', 'Sürü Çağırma', 'Summon Swarm', 'Bir alandaki düşmanları ısırmak ve sokmak için bir böcek veya fare sürüsü çağırır.', 'Summons a swarm of insects or rats to bite and sting enemies in an area.', 'Beastmaster', 5, 100, 1, '{}', '{"x": 449, "y": 536}', '{"damage": "2d4 piercing", "radius": "5m", "duration": "1 minute"}', '🐝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2c4075c1-799f-4ef4-ba4f-8fd914caa0cd', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_beast_lure', 'Vahşi Çekim', 'Beast Lure', 'Yakındaki tüm canavarları yavaşça bulunduğunuz yere çeken bir feromon yayar.', 'Emits a pheromone that slowly attracts all nearby beasts to your location.', 'Beastmaster', 10, 120, 1, '{}', '{"x": 610, "y": 727}', '{"radius": "500m", "duration": "10 minutes"}', '🥩');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('634a5ee6-2dda-477d-b722-c5fa5bd3e7d9', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_call_of_the_wild', 'Doğanın Çağrısı', 'Call of the Wild', 'Savaşta size yardım etmeleri için vahşi doğadan 2 küçük canavar çağırır.', 'Summons 2 minor beasts from the wilderness to aid you in combat.', 'Beastmaster', 21, 200, 2, '{"bt_animal_friendship"}', '{"x": 771, "y": 919}', '{"summons": 2, "max_cr": 1, "duration": "1 hour"}', '🐾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b4f524da-6f34-4d51-9033-65c60cc06212', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_pack_tactics', 'Sürü Taktikleri', 'Pack Tactics', 'Siz ve müttefikleriniz, hedefin yakınında dost bir canavar varsa saldırı zarlarında avantaj kazanırsınız.', 'You and your allies gain advantage on attack rolls if an allied beast is near the target.', 'Beastmaster', 26, 240, 2, '{"bt_summon_swarm"}', '{"x": 932, "y": 1110}', '{"radius": "2m", "advantage": true}', '👥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('68b790ce-2d01-4725-bd08-5132a36b4a22', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_calm_beast', 'Canavarı Sakinleştir', 'Calm Beast', 'Düşman bir canavarı anında sakinleştirir, saldırganlığını kırar ve saldırılarını durdurur.', 'Instantly pacifies any hostile beast, breaking its aggro and halting its attacks.', 'Beastmaster', 30, 260, 2, '{"bt_animal_friendship"}', '{"x": 1092, "y": 1302}', '{"range": "18m", "duration": "1 minute"}', '🕊️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('98b905a0-8046-47ca-9ad7-4feac5ab62ae', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_stampede', 'İzdiham', 'Stampede', 'Düşmanları uzun bir hat boyunca ezmek için hayalet bir canavar sürüsü çağırır.', 'Summons a spectral herd of beasts to trample enemies in a long line.', 'Beastmaster', 41, 400, 3, '{"bt_call_of_the_wild"}', '{"x": 1253, "y": 1493}', '{"damage": "4d8 bludgeoning", "area": "10m x 30m line"}', '🦬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7bba91b5-92a0-46c1-9705-f9a9b62830c2', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_dominate_beast', 'Canavara Hükmet', 'Dominate Beast', 'Vahşi bir canavarın üzerinde tam telepatik kontrol kurarak her hareketine hükmeder.', 'Takes total telepathic control over a wild beast, commanding its every move.', 'Beastmaster', 48, 450, 3, '{"bt_calm_beast"}', '{"x": 1414, "y": 1685}', '{"range": "18m", "duration": "1 hour"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d0804bfa-97c8-429f-bdd8-7a4638cbab93', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_feral_frenzy', 'Vahşi Çılgınlık', 'Feral Frenzy', 'Tüm dost canavarları çılgına çevirerek onlara hız ve ekstra hasar kazandırır.', 'Drives all allied beasts into a frenzy, granting them haste and bonus damage.', 'Beastmaster', 55, 480, 3, '{"bt_pack_tactics"}', '{"x": 1574, "y": 1876}', '{"bonus_damage": "2d4", "haste": true, "duration": "1 minute"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0ca81a00-28ce-41c2-a254-e1e2fd33b776', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_summon_dire_beast', 'Ulu Canavar Çağırma', 'Summon Dire Beast', 'Düşmanlarınızı ezmek için devasa ve inanılmaz derecede güçlü ulu bir canavar çağırır.', 'Calls forth a massive, incredibly powerful dire beast to crush your foes.', 'Beastmaster', 64, 700, 4, '{"bt_call_of_the_wild"}', '{"x": 1735, "y": 2068}', '{"summons": 1, "max_cr": 5, "duration": "10 minutes"}', '🐻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d6a5146c-6782-4a7e-8e32-7fb45f11b543', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_bestial_ward', 'Vahşi Koruma', 'Bestial Ward', 'Dost canavarlara koruyucu bir çember oluşturmalarını emrederek size gelen hasarı yarıya indirir.', 'Commands allied beasts to form a protective ring, halving incoming damage to you.', 'Beastmaster', 70, 750, 4, '{"bt_dominate_beast"}', '{"x": 1896, "y": 2259}', '{"damage_reduction": "50%", "radius": "10m"}', '🐾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('be4f8a86-1431-42e9-a417-76894dec96e7', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_call_avian_flock', 'Kuş Sürüsü Çağırma', 'Call Avian Flock', 'Geniş bir alandaki düşmanları gagalamak ve yönlerini şaşırtmak için kör edici bir kuş sürüsü çağırır.', 'Summons a blinding flock of birds to peck and disorient enemies in a large area.', 'Beastmaster', 76, 800, 4, '{"bt_stampede"}', '{"x": 2056, "y": 2451}', '{"damage": "3d6 slashing", "radius": "20m", "duration": "3 turns"}', '🦅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2f22d72a-ab9f-44a6-9f4a-18ca0169065e', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_beast_lord', 'Canavar Lordu', 'Beast Lord', 'Nihai Yetenek. Seçkin bir canavar sürüsü çağırır ve kilometrelerce uzaktaki tüm doğal vahşi yaşama pasif olarak hükmeder.', 'Ultimate. Summons a pack of elite beasts and passively commands all natural wildlife for kilometers.', 'Beastmaster', 92, 1300, 5, '{"bt_summon_dire_beast", "bt_call_avian_flock"}', '{"x": 2217, "y": 2642}', '{"summons": "1d4+2 CR 5 beasts", "control_radius": "1000m", "duration": "1 hour"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('eed2e513-5e36-4d7a-b0dc-8c1584dabbb1', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_hunters_mark', 'Avcının İşareti', 'Hunter''s Mark', 'Bir hedefi avınız olarak işaretler, ekstra hasar verir ve izini kaybetmeyi imkansız hale getirir.', 'Marks a target as your prey, dealing extra damage and making them impossible to lose track of.', 'Instinct', 1, 50, 1, '{}', '{"x": -128, "y": 153}', '{"bonus_damage": "1d6", "range": "30m", "duration": "1 hour"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f2f4eb8d-5042-4a10-81c2-ddaaf34fe10c', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_keen_senses', 'Keskin Duyular', 'Keen Senses', 'İşitmenizi ve koklama duyunuzu keskinleştirerek yakındaki görünmez düşmanları tespit etme yeteneği kazandırır.', 'Heightens your hearing and smell, granting the ability to detect invisible enemies nearby.', 'Instinct', 4, 80, 1, '{}', '{"x": -289, "y": 344}', '{"detection_radius": "10m", "duration": "1 hour"}', '👃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0ca01fbd-4bae-4ed3-bc67-c25eb47fd9cc', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_predators_stride', 'Yırtıcının Adımı', 'Predator''s Stride', 'Hareket hızınızı artırır ve yavaşlamadan zorlu arazilerden geçmenizi sağlar.', 'Increases your movement speed and allows you to pass through difficult terrain without slowing down.', 'Instinct', 7, 100, 1, '{}', '{"x": -449, "y": 536}', '{"bonus_speed": "3m", "duration": "Permanent"}', '🐆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ce7e2f64-e851-437f-a33d-65058d84514b', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_survival_instinct', 'Hayatta Kalma İçgüdüsü', 'Survival Instinct', 'Aşırı hava koşullarına karşı doğal dayanıklılık ve hayatta kalma uzmanlığı kazandırır.', 'Grants natural resilience against extreme weather conditions and survival expertise.', 'Instinct', 12, 120, 1, '{}', '{"x": -610, "y": 727}', '{"resistance": "Weather", "duration": "Permanent"}', '🏕️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('422c8843-7737-4138-9613-48a09c0dce77', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_aspect_of_the_bear', 'Ayının Sureti', 'Aspect of the Bear', 'Ayının ruhunu kanalize ederek muazzam güç ve geçici sağlık puanı kazandırır.', 'Channels the spirit of the bear, granting immense strength and temporary hit points.', 'Instinct', 23, 220, 2, '{"bt_survival_instinct"}', '{"x": -771, "y": 919}', '{"bonus_str": 2, "temp_hp": 20, "duration": "1 hour"}', '🐻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('768a3fc1-ee9f-4da5-9c54-241064b736ab', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_aspect_of_the_wolf', 'Kurdun Sureti', 'Aspect of the Wolf', 'Kurdun ruhunu kanalize ederek iz sürmeyi geliştirir ve yakındaki müttefiklere hız güçlendirmeleri kazandırır.', 'Channels the spirit of the wolf, enhancing tracking and granting speed buffs to nearby allies.', 'Instinct', 28, 250, 2, '{"bt_hunters_mark", "bt_predators_stride"}', '{"x": -932, "y": 1110}', '{"bonus_speed": "2m for allies", "radius": "5m", "duration": "1 hour"}', '🐺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ad19670f-04cc-4c07-aec2-42638239dccc', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_aspect_of_the_cheetah', 'Çitanın Sureti', 'Aspect of the Cheetah', 'Çitanın ruhunu kanalize ederek hızlı deparlar atmanızı ve fırsat saldırılarından kaçınmanızı sağlar.', 'Channels the spirit of the cheetah, allowing rapid dashes and evading opportunity attacks.', 'Instinct', 35, 290, 2, '{"bt_predators_stride"}', '{"x": -1092, "y": 1302}', '{"bonus_action_dash": true, "duration": "10 minutes"}', '🐆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a8bea463-16c2-4965-977d-98bcb73834db', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_camouflage', 'Kamuflaj', 'Camouflage', 'Doğal çevreye kusursuz bir şekilde karışarak, hareket etmediğiniz sürece sizi görünmez kılar.', 'Blends seamlessly into natural surroundings, rendering you invisible as long as you do not move.', 'Instinct', 44, 420, 3, '{"bt_keen_senses"}', '{"x": -1253, "y": 1493}', '{"invisibility": true, "duration": "Until moved"}', '🍃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2a3fea02-1baa-441c-8df8-0880298546fd', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_feral_leap', 'Vahşi Sıçrama', 'Feral Leap', 'Büyük bir mesafe sıçrar ve yere çarparak yakındaki tüm düşmanlara hasar verir.', 'Leaps a massive distance and slams the ground, damaging all nearby enemies.', 'Instinct', 52, 460, 3, '{"bt_aspect_of_the_cheetah"}', '{"x": -1414, "y": 1685}', '{"damage": "3d8", "jump_distance": "15m", "radius": "3m"}', '🦘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a34604c2-be2c-4d6b-8e81-500423d44a23', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_venom_resistance', 'Zehir Direnci', 'Venom Resistance', 'Vücudunuz zehirlere ve toksik ortamlara karşı tam bir bağışıklık geliştirir.', 'Your body develops complete immunity to poisons, venoms, and toxic environments.', 'Instinct', 58, 490, 3, '{"bt_aspect_of_the_bear"}', '{"x": -1574, "y": 1876}', '{"immunity": "Poison", "duration": "Permanent"}', '🐍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1b9b9cf8-f650-4ede-9e51-c2b05c4586c0', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_apex_predator', 'Zirve Yırtıcı', 'Apex Predator', 'Acımasızlaşırsınız. Yaralı hedeflere yönelik saldırılar daha sık kritik hasar verir.', 'You become ruthless. Attacks against wounded targets deal critical damage more often.', 'Instinct', 66, 750, 4, '{"bt_aspect_of_the_wolf", "bt_hunters_mark"}', '{"x": -1735, "y": 2068}', '{"bonus_damage": "3d8", "crit_range": "19-20", "threshold": "<50% HP"}', '🦈');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1ce1cdf8-6018-4672-9e8e-5f03b8fc6012', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_bestial_regeneration', 'Vahşi Yenilenme', 'Bestial Regeneration', 'Savaşta yaralarınız hızla iyileşir ve sağlığınız sürekli olarak yenilenir.', 'Your wounds heal rapidly in combat, recovering health continuously.', 'Instinct', 72, 800, 4, '{"bt_aspect_of_the_bear"}', '{"x": -1896, "y": 2259}', '{"regeneration": "10 HP/turn", "duration": "1 minute"}', '🦎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a7705a36-aabf-4d62-99d2-d5f60e207779', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_eagle_eye', 'Kartal Gözü', 'Eagle Eye', 'Görüşünüz eşsiz hale gelir. Menzilli saldırıların mesafesi iki katına çıkar ve siperleri yok sayar.', 'Your vision becomes unmatched. Ranged attacks double in distance and ignore cover.', 'Instinct', 78, 850, 4, '{"bt_keen_senses"}', '{"x": -2056, "y": 2451}', '{"range_multiplier": 2, "bonus_hit": 2, "duration": "1 hour"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('374147f6-d1e3-44bd-be3f-73b688e63650', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_primal_avatar', 'İlkel Avatar', 'Primal Avatar', 'Nihai Yetenek. Doğanın melez fiziksel bir tanrısına dönüşerek hızı, dayanıklılığı ve hasarı en üst düzeye çıkarır.', 'Ultimate. Transform into a hybrid physical god of nature, maximizing speed, resilience, and damage.', 'Instinct', 95, 1400, 5, '{"bt_apex_predator", "bt_bestial_regeneration"}', '{"x": -2217, "y": 2642}', '{"bonus_stats": "+6 STR/DEX/CON", "bonus_damage": "4d10 force", "bonus_speed": "30m", "duration": "1 minute"}', '🦍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('39011344-a425-4fa4-a63c-3e690c16df46', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_pack_hunter', 'Sürü Avcısı', 'Pack Hunter', 'Sinerji. Siz ve yoldaşınız tam olarak aynı hedefe saldırdığınızda yıkıcı bonus hasar verirsiniz.', 'Synergy. You and your companion deal devastating bonus damage when assaulting the exact same target.', 'Cross-Branch', 25, 250, 2, '{"bt_guard_command", "bt_hunters_mark"}', '{"x": -173, "y": -100}', '{"bonus_damage": "1d6", "condition": "Attacking same target"}', '🤝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dff07f13-409f-4c25-8f26-9c3881723184', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_wild_stampede', 'Vahşi İzdiham', 'Wild Stampede', 'Sinerji. Hayalet canavarlarla sarılı bir şekilde fiziksel olarak ileri atılır, yolunuzdaki her şeyi ezersiniz.', 'Synergy. You physically dash forward enveloped in spectral beasts, trampling everything in your path.', 'Cross-Branch', 45, 450, 3, '{"bt_call_of_the_wild", "bt_feral_leap"}', '{"x": -389, "y": -225}', '{"damage": "5d8", "dash_distance": "20m", "area": "Line"}', '🐗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a31e09ed-3be9-412c-985a-cc6287637294', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_bestial_telepathy', 'Vahşi Telepati', 'Bestial Telepathy', 'Sinerji. Zihninizi kalıcı olarak tüm dost canavarlara bağlayarak geniş mesafeler boyunca bir orduyu sessizce yönetirsiniz.', 'Synergy. Permanently link your mind with all allied beasts, commanding an army silently over vast distances.', 'Cross-Branch', 50, 480, 3, '{"bt_shared_senses", "bt_dominate_beast"}', '{"x": -606, "y": -350}', '{"radius": "1000m", "duration": "Permanent"}', '📡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('39a16ba3-6c59-4ef1-aaea-1027a3de28c2', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_shared_frenzy', 'Ortak Çılgınlık', 'Shared Frenzy', 'Sinerji. Siz, yoldaşınız ve çağrılan tüm canavarlar kan susuzluğu durumuna girer, acıyı görmezden gelir ve acımasızca saldırırsınız.', 'Synergy. You, your companion, and all summoned beasts enter a bloodlust state, ignoring pain and striking relentlessly.', 'Cross-Branch', 65, 750, 4, '{"bt_feral_frenzy", "bt_companion_fury", "bt_apex_predator"}', '{"x": -822, "y": -475}', '{"bonus_attacks": 2, "resistance": "All damage", "duration": "3 turns"}', '👹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5d95116d-1860-4de6-a073-fbd7307ac378', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_nature_wrath', 'Doğanın Gazabı', 'Nature''s Wrath', 'Sinerji. Bölgedeki flora ve fauna düşmanlarınızı ezmek ve dolaştırmak için ayaklanır.', 'Synergy. The very flora and fauna in the area rise up to crush and entangle your enemies.', 'Cross-Branch', 75, 850, 4, '{"bt_stampede", "bt_apex_predator"}', '{"x": -1039, "y": -600}', '{"damage": "6d8 bludgeoning", "radius": "50m", "condition": "Restrained"}', '🌲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0b11576c-09b7-44b1-8455-2ceebd42d993', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_spirit_beast', 'Ruhani Canavar', 'Spirit Beast', 'Sinerji. Yoldaşınız geçici olarak ruhani bir varlık haline gelir, katı maddelerden geçer ve zararlara direnir.', 'Synergy. Your companion temporarily becomes an ethereal spirit, phasing through solid matter and resisting harm.', 'Cross-Branch', 80, 900, 4, '{"bt_mythic_companion", "bt_camouflage"}', '{"x": -1255, "y": -725}', '{"resistance": "Non-magical", "ethereal": true, "duration": "10 minutes"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('40c7e6b3-cabc-45fb-a96e-0f71da5c9ddb', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_master_of_the_hunt', 'Avın Efendisi', 'Master of the Hunt', 'Sinerji. Sahadaki tüm müttefikleri ve canavarları muazzam iz sürme hassasiyeti, hızı ve infaz hasarıyla güçlendirir.', 'Synergy. Empowers all allies and beasts on the field with massive tracking precision, speed, and execute damage.', 'Cross-Branch', 85, 950, 4, '{"bt_soul_bond", "bt_summon_dire_beast", "bt_eagle_eye"}', '{"x": -1472, "y": -850}', '{"bonus_speed": "+50%", "bonus_damage": "2d8", "see_invisibility": true, "duration": "10 minutes"}', '🏹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e4a69069-6c05-4cfe-aa37-e41207f41512', '0f19284d-34cf-4a90-b78c-558c600bb543', 'bt_wild_gods_blessing', 'Vahşi Tanrıların Lütfu', 'Blessing of the Wild Gods', 'Görkemli Nihai. Vahşi doğanın seçilmişi olarak yükselirsiniz. Siz ve müttefikleriniz tam dokunulmazlık kazanırken, savaş alanını kasıp kavurması için 3 Kadim Canavar Tanrısı çağırırsınız.', 'Grand Ultimate. You ascend as the chosen of the wilds. Summon 3 Ancient Beast Gods to ravage the battlefield while you and your allies gain total invulnerability.', 'Cross-Branch', 100, 1500, 5, '{"bt_alpha_predator", "bt_beast_lord", "bt_primal_avatar"}', '{"x": -1688, "y": -975}', '{"invulnerability": "2 turns", "summons": "3 Ancient Beast Gods", "damage": "Maximized"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1710d635-9fec-4322-9c05-b3e057ccdf5a', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_furious_strike', 'Öfkeli Vuruş', 'Furious Strike', '1d10 fiziksel hasar veren, öfke dolu güçlü bir vuruş. 10 Öfke üretir.', 'A powerful, anger-fueled strike that deals 1d10 physical damage. Generates 10 Rage.', 'Rage', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d10", "range": "2m"}', '💢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cb7ba883-f609-4534-979e-b38b9c14bec8', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_adrenaline_rush', 'Adrenalin Patlaması', 'Adrenaline Rush', 'Adrenalin patlaması yaşayarak 3 tur boyunca hareket hızını 5m, saldırı hızını ise %15 artırır.', 'Gain a burst of adrenaline, increasing movement speed by 5m and attack speed by 15% for 3 turns.', 'Rage', 5, 80, 1, '{}', '{"x": 389, "y": -224}', '{"buff": "+5m speed, +15% attack speed", "duration": "3 turns"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a6f06ca3-fd94-4568-80c3-65f0a35a7d3a', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_reckless_swing', 'Pervasız Savurma', 'Reckless Swing', 'Savunmayı hiçe sayarak saldırın. 3m''lik bir kavis içinde 2d8 fiziksel hasar verir, ancak 1 tur boyunca Zırhınızı 10 azaltır.', 'Attack with no regard for defense. Deals 2d8 physical damage in a 3m arc, but reduces your Armor by 10 for 1 turn.', 'Rage', 10, 120, 1, '{}', '{"x": 606, "y": -349}', '{"damage": "2d8", "range": "3m arc", "debuff": "-10 Armor", "duration": "1 turn"}', '🪓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('746f555d-2b4c-413c-ac13-bca7fd7e67e4', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_enrage', 'Hiddet', 'Enrage', 'Saf bir öfke durumuna girin. 5 tur boyunca fiziksel hasarınız %25 artar ancak tüm kaynaklardan %15 daha fazla hasar alırsınız.', 'Enter a state of pure anger. For 5 turns, your physical damage is increased by 25% but you take 15% more damage from all sources.', 'Rage', 21, 180, 2, '{"bk_adrenaline_rush"}', '{"x": 822, "y": -474}', '{"buff": "+25% physical damage", "debuff": "+15% damage taken", "duration": "5 turns"}', '🤬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('43c72ac9-47a8-4db2-b6cc-5c140df68c34', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_frenzy', 'Cinnet', 'Frenzy', 'Vahşi saldırılar serbest bırakın. Bir hedefe her biri 1d8 fiziksel hasar veren 3 vuruş yapın. 20 Öfke tüketir.', 'Unleash a flurry of wild attacks. Strike a target 3 times, each dealing 1d8 physical damage. Costs 20 Rage.', 'Rage', 25, 200, 2, '{"bk_reckless_swing"}', '{"x": 1039, "y": -599}', '{"damage": "3x 1d8", "range": "2m"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('47d04c8b-43a5-4401-bace-6810c8e9e156', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_pain_tolerance', 'Acı Toleransı', 'Pain Tolerance', 'Yaraların acısını görmezden gelin. 4 tur boyunca alınan fiziksel hasarı %20 azaltır. Canınız %30''un altındaysa etki %40''a çıkar.', 'Ignore the pain of wounds. Reduce incoming physical damage by 20% for 4 turns. Effect increases to 40% if your HP is below 30%.', 'Rage', 35, 280, 2, '{"bk_enrage"}', '{"x": 1255, "y": -724}', '{"buff": "20-40% damage reduction", "duration": "4 turns"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('03fe9b11-573f-40df-9296-dcee9eb2c496', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_wrathful_blow', 'Gazap Darbesi', 'Wrathful Blow', 'Öfkenizi 4d10 fiziksel hasar veren yıkıcı tek bir vuruşta yoğunlaştırın. Hedefi 1 tur sersemletir.', 'Concentrate your anger into a single, devastating hit dealing 4d10 physical damage. Stuns the target for 1 turn.', 'Rage', 41, 360, 3, '{"bk_frenzy"}', '{"x": 1472, "y": -849}', '{"damage": "4d10", "range": "2m", "status": "Stun 1 turn"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5cb76e26-54fa-4492-871d-e9380f3fafb9', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_blind_rage', 'Kör Öfke', 'Blind Rage', 'Kontrolünüzü öfkenize kaptırın. 3 tur boyunca saldırılarınız otomatik olarak kritik hasar verir, ancak en yakındaki hedefe (dost veya düşman) saldırmak zorundasınızdır.', 'Lose control to your fury. For 3 turns, your attacks deal critical hits automatically, but you must attack the nearest target (friend or foe).', 'Rage', 50, 420, 3, '{"bk_pain_tolerance"}', '{"x": 1688, "y": -974}', '{"buff": "100% Critical Chance", "debuff": "Forced targeting", "duration": "3 turns"}', '😵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('49d8d88e-5545-434d-8f7c-a7d603d815b8', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_unyielding_anger', 'Boyun Eğmez Öfke', 'Unyielding Anger', 'Pasif: Hasar aldığınızda 5 Öfke kazanırsınız ve bir sonraki saldırınız fazladan 1d6 hasar verir.', 'Passive: Whenever you take damage, you gain 5 Rage and your next attack deals an additional 1d6 damage.', 'Rage', 55, 480, 3, '{"bk_wrathful_blow"}', '{"x": 1905, "y": -1099}', '{"passive": "+5 Rage on hit taken", "damage": "+1d6 next attack"}', '😤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ff64c131-70f1-44db-88a6-6a312de55f4c', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_seismic_slam', 'Sismik Çarpma', 'Seismic Slam', 'Yere inanılmaz bir güçle vurun. 6m yarıçapındaki tüm düşmanlara 6d8 fiziksel hasar verir ve onları yere serer.', 'Smash the ground with incredible force. Deals 6d8 physical damage to all enemies within a 6m radius and knocks them prone.', 'Rage', 65, 650, 4, '{"bk_unyielding_anger"}', '{"x": 2121, "y": -1224}', '{"damage": "6d8", "radius": "6m", "status": "Prone"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('621c83aa-7008-49ab-8749-9a01af30f40b', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_death_defiance', 'Ölüme Meydan Okuma', 'Death Defiance', 'Canınız 0''a düştüğünde, bunun yerine 1 Cana düşersiniz ve 2 tur boyunca hasar görmez olursunuz. Savaş başına bir kez kullanılabilir.', 'When your HP drops to 0, you instead drop to 1 HP and become invulnerable for 2 turns. Usable once per battle.', 'Rage', 75, 800, 4, '{"bk_blind_rage"}', '{"x": 2338, "y": -1349}', '{"buff": "Invulnerable", "duration": "2 turns", "limit": "Once per battle"}', '☠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('667baf17-38f4-488f-9e8a-4caedbee902b', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_avatar_of_wrath', 'Gazabın Avatarı', 'Avatar of Wrath', '5 tur boyunca öfkenin tecessümüne dönüşün. Boyutunuz büyür, saldırılarınız iki kat hasar verir ve 100 geçici Can kazanırsınız.', 'Transform into the embodiment of anger for 5 turns. Your size increases, attacks deal double damage, and you gain 100 temporary HP.', 'Rage', 85, 1100, 5, '{"bk_seismic_slam"}', '{"x": 2554, "y": -1474}', '{"buff": "+100 Temp HP, x2 Damage", "duration": "5 turns"}', '👹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('35afac82-b547-427d-9694-ce5fac9b5693', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_raging_juggernaut', 'Öfkeli İlah', 'Raging Juggernaut', 'Durdurulamaz bir güce dönüşün. Düz bir çizgide 15m''ye kadar hücum ederek tüm engelleri yok edin ve yolunuzdaki herkese 10d10 fiziksel hasar verin. Hedefler bundan kaçınamaz.', 'Become an unstoppable force. Charge up to 15m in a straight line, destroying all obstacles and dealing 10d10 physical damage to anyone in the path. Targets cannot evade.', 'Rage', 95, 1400, 5, '{"bk_avatar_of_wrath", "bk_death_defiance"}', '{"x": 2771, "y": -1599}', '{"damage": "10d10", "range": "15m line", "special": "Unavoidable, destroys terrain"}', '🚂');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ab065b13-45ba-4f0e-acb6-0b768b9761da', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_blood_slash', 'Kanlı Kesiş', 'Blood Slash', 'Maksimum canınızın %5''ini feda ederek hedefe 1d12 fiziksel hasar verin. 3 tur boyunca tur başına 1d4 hasar veren bir kanama etkisi uygular.', 'Sacrifice 5% of your max HP to deal 1d12 physical damage to a target. Applies a bleed effect dealing 1d4 damage per turn for 3 turns.', 'Bloodlust', 2, 60, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "1d12", "status": "1d4 Bleed", "cost": "5% HP", "duration": "3 turns"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e665f81d-dc4a-48ac-a625-65a909ea1e5b', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_vampiric_thirst', 'Vampirik Susuzluk', 'Vampiric Thirst', 'Pasif: Yakın dövüş saldırılarınız, verdiğiniz fiziksel hasarın %10''u kadar sizi iyileştirir.', 'Passive: Your melee attacks heal you for 10% of the physical damage dealt.', 'Bloodlust', 8, 100, 1, '{}', '{"x": 289, "y": 344}', '{"passive": "10% Lifesteal"}', '🦇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ab908006-35c9-4dbc-8a49-438b10b1de53', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_crimson_cleave', 'Kızıl Yarma', 'Crimson Cleave', '4m''lik bir koni içindeki düşmanlara 2d6 fiziksel hasar veren geniş açılı bir vuruş. Vurulan her düşman için 5 Can yeniler.', 'A sweeping strike that deals 2d6 physical damage to enemies in a 4m cone. Restores 5 HP for each enemy hit.', 'Bloodlust', 15, 140, 1, '{}', '{"x": 449, "y": 536}', '{"damage": "2d6", "area": "4m cone", "heal": "5 HP per target"}', '🔪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0c8a5f30-f68e-421b-96db-980770a75f1a', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_hemorrhage', 'Kanamalı Yara', 'Hemorrhage', 'Hedefin hayati damarına vurarak 2d8 fiziksel hasar verin ve 4 tur boyunca tur başına 2d6 hasar alarak kanamalarına neden olun.', 'Strike a target''s vital vein, dealing 2d8 physical damage and causing them to bleed for 2d6 damage per turn for 4 turns.', 'Bloodlust', 22, 190, 2, '{"bk_blood_slash"}', '{"x": 610, "y": 727}', '{"damage": "2d8", "status": "2d6 Bleed", "duration": "4 turns"}', '💉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('84ac8de0-2223-4c4c-87a2-8b453ea4b1a2', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_blood_sacrifice', 'Kan Kurbanı', 'Blood Sacrifice', 'Anında mevcut canınızın %20''sini tüketerek sonraki 2 saldırınız için %50 hasar artışı kazanın.', 'Instantly consume 20% of your current HP to grant yourself a 50% damage boost on your next 2 attacks.', 'Bloodlust', 30, 250, 2, '{"bk_crimson_cleave"}', '{"x": 771, "y": 919}', '{"cost": "20% current HP", "buff": "+50% Damage", "duration": "2 attacks"}', '🫀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0fc2f471-7a40-4615-8b99-99c2d862f535', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_sanguine_feast', 'Kan Ziyafeti', 'Sanguine Feast', 'Kanayan bir hedefe ısırık atın, kanama yüklerini tüketerek yük başına anında kendinizi 20 Can iyileştirin ve 3d8 fiziksel hasar verin.', 'Bite a bleeding target, consuming their bleed stacks to instantly heal yourself for 20 HP per stack and dealing 3d8 physical damage.', 'Bloodlust', 38, 300, 2, '{"bk_vampiric_thirst"}', '{"x": 932, "y": 1110}', '{"damage": "3d8", "heal": "20 HP per bleed stack", "range": "1m"}', '🍷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e69e0401-cbe1-4bd9-bae9-6b916d0c725e', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_vital_strike', 'Hayati Vuruş', 'Vital Strike', 'Bir düşmanın zayıf noktasına nişan alın. 4d8 fiziksel hasar verir. Hedef kanıyorsa, bu saldırı hedefin Zırhının %50''sini yok sayar.', 'Target an enemy''s weak point. Deals 4d8 physical damage. If the target is bleeding, this attack ignores 50% of their Armor.', 'Bloodlust', 45, 380, 3, '{"bk_hemorrhage"}', '{"x": 1092, "y": 1302}', '{"damage": "4d8", "special": "Ignores 50% Armor if bleeding"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('21d93232-a256-469f-8a8c-72d5a955bf61', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_gore_spatter', 'Kan Sıçraması', 'Gore Spatter', 'Bir düşmanı parçalayarak 5d6 fiziksel hasar verin. Ortaya çıkan kan sıçraması, hedefin 3m yakınındaki tüm düşmanları 1 tur kör eder.', 'Rip through an enemy, dealing 5d6 physical damage. The resulting spray of blood blinds all enemies within 3m of the target for 1 turn.', 'Bloodlust', 52, 450, 3, '{"bk_blood_sacrifice"}', '{"x": 1253, "y": 1493}', '{"damage": "5d6", "status": "Blind 3m AoE", "duration": "1 turn"}', '🥀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f65f481f-16f0-427e-b03a-5a9b13efe213', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_blood_frenzy', 'Kan Cinneti', 'Blood Frenzy', 'Pasif: 10m içindeki her kanayan düşman için +%5 saldırı hızı ve +2m hareket hızı kazanırsınız.', 'Passive: For every bleeding enemy within 10m, you gain +5% attack speed and +2m movement speed.', 'Bloodlust', 58, 500, 3, '{"bk_sanguine_feast"}', '{"x": 1414, "y": 1685}', '{"passive": "+5% ATK Speed and +2m Speed per bleeding foe"}', '🦈');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a2bdc9de-7121-428a-af97-23cabece63e5', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_life_drain_aura', 'Yaşam Emişi Aurası', 'Life Drain Aura', '4 tur boyunca nabız gibi atan bir kan büyüsü aurası yayın. 5m içindeki tüm düşmanlar tur başına 3d6 nekrotik hasar alır ve siz verilen hasarın %100''ü kadar iyileşirsiniz.', 'Emit a pulsing aura of blood magic for 4 turns. All enemies within 5m take 3d6 necrotic damage per turn, and you heal for 100% of the damage dealt.', 'Bloodlust', 68, 680, 4, '{"bk_gore_spatter"}', '{"x": 1574, "y": 1876}', '{"damage": "3d6 necrotic/turn", "heal": "100% of damage", "radius": "5m", "duration": "4 turns"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5e70001f-73ea-475a-a3a5-5a2303f08d58', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_crimson_storm', 'Kızıl Fırtına', 'Crimson Storm', 'Bıçaklardan oluşan bir girdapta dönerek bir kan kasırgası yaratın. 8m yarıçapındaki tüm düşmanlara 8d6 fiziksel hasar verir ve 2 kanama yükü uygular.', 'Spin in a whirlwind of blades, creating a tornado of blood. Deals 8d6 physical damage to all enemies within an 8m radius and applies 2 stacks of bleeding.', 'Bloodlust', 78, 850, 4, '{"bk_vital_strike", "bk_blood_frenzy"}', '{"x": 1735, "y": 2068}', '{"damage": "8d6", "radius": "8m", "status": "2 Bleed stacks"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('405bf20f-7014-4135-9f29-62141ee2cbea', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_blood_lord', 'Kan Lordu', 'Blood Lord', 'Kanlı doğanızda ustalaşın. 5 tur boyunca maksimum canınız iki katına çıkar ve tüm saldırılarınız sizi iyileştiren fazladan 2d10 nekrotik hasar verir.', 'Master your sanguine nature. For 5 turns, your max HP is doubled, and all your attacks deal an additional 2d10 necrotic damage that heals you.', 'Bloodlust', 88, 1150, 5, '{"bk_life_drain_aura"}', '{"x": 1896, "y": 2259}', '{"buff": "Max HP x2, +2d10 lifesteal damage", "duration": "5 turns"}', '🧛');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a8d9bea1-27a1-4a16-b1db-707b43e47c84', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_carnage_incarnate', 'Katliam Tecessümü', 'Carnage Incarnate', 'Tam bir yıkım açığa çıkarmak için mevcut canınızın %50''sini feda edin. Tek bir hedefe 15d10 fiziksel hasar verir. Hedef ölürse, fazla hasar 10m içindeki tüm düşmanlara zincirleme sıçrar ve sizi tamamen iyileştirir.', 'Sacrifice 50% of your current HP to unleash total devastation. Deals 15d10 physical damage to a single target. If the target dies, the excess damage chains to all enemies within 10m and heals you fully.', 'Bloodlust', 95, 1450, 5, '{"bk_blood_lord", "bk_crimson_storm"}', '{"x": 2056, "y": 2451}', '{"cost": "50% current HP", "damage": "15d10", "special": "Chain on death, Full Heal"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0f1cb2b4-aad4-4a86-ba26-d073403ca718', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_savage_pounce', 'Vahşi Atılım', 'Savage Pounce', 'Bir hedefin üzerine 6m''ye kadar atlayarak 2d6 fiziksel hasar verin. Hedef sizden küçükse yere serilir.', 'Leap up to 6m onto a target, dealing 2d6 physical damage. If the target is smaller than you, they are knocked prone.', 'Primal', 3, 70, 1, '{}', '{"x": -128, "y": 153}', '{"damage": "2d6", "range": "6m", "status": "Prone if smaller"}', '🐅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('344ca4aa-c5b8-4ea6-930b-5ee424e08890', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_primal_howl', 'İlkel Uluma', 'Primal Howl', 'Korkunç bir kükreme salın. 5m içindeki düşmanlar bir İrade zarı başarmalıdır, aksi takdirde 2 tur boyunca korkarlar ve saldırı zarları 2 azalır.', 'Let out a terrifying roar. Enemies within 5m must succeed on a Will save or be frightened for 2 turns, reducing their attack rolls by 2.', 'Primal', 9, 110, 1, '{}', '{"x": -289, "y": 344}', '{"radius": "5m", "status": "Frightened (-2 ATK)", "duration": "2 turns"}', '🐺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dc71ae42-5bc6-47bf-9baf-43e54235a09b', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_feral_instincts', 'Vahşi İçgüdüler', 'Feral Instincts', 'Pasif: Duyularınız keskinleşir. İnisiyatif zarlarına +3 kazanırsınız ve gafil avlanamazsınız. 5m içindeki görünmez düşmanları tespit edersiniz.', 'Passive: Your senses heighten. You gain +3 to Initiative rolls and cannot be surprised. You detect invisible enemies within 5m.', 'Primal', 18, 150, 1, '{}', '{"x": -449, "y": 536}', '{"passive": "+3 Initiative, Unsurprisable, Truesight 5m"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3348f3c7-5cc6-47b6-bf2a-27f8b17e226c', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_beast_charge', 'Canavar Hücumu', 'Beast Charge', '8m''ye kadar ileri atılın. Vurulan ilk düşman 3d6 fiziksel hasar alır ve 3m geriye itilir.', 'Dash forward up to 8m. The first enemy hit takes 3d6 physical damage and is pushed back 3m.', 'Primal', 24, 210, 2, '{"bk_savage_pounce"}', '{"x": -610, "y": 727}', '{"damage": "3d6", "range": "8m", "status": "Push 3m"}', '🦏');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('40164c82-86fa-4549-aae1-87a91ce0a5d8', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_rending_claws', 'Parçalayan Pençeler', 'Rending Claws', 'Bir düşmanı iki kez kesmek için hayalet pençeler büyütün. Her vuruş 1d10 fiziksel hasar verir ve 3 tur boyunca 5 Zırh parçalar.', 'Grow spectral claws to slash an enemy twice. Each strike deals 1d10 physical damage and shreds 5 Armor for 3 turns.', 'Primal', 32, 260, 2, '{"bk_feral_instincts"}', '{"x": -771, "y": 919}', '{"damage": "2x 1d10", "debuff": "-10 Armor total", "duration": "3 turns"}', '🐾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('11aff239-e389-4fc2-bd82-14c425a27b19', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_intimidating_roar', 'Gözdağı Veren Kükreme', 'Intimidating Roar', 'Moralleri bozan sağır edici bir kükreme. 8m içindeki düşmanlar 2d8 gök gürültüsü hasarı alır ve 2 tur boyunca %50 yavaşlar.', 'A deafening roar that damages morale. Enemies within 8m take 2d8 thunder damage and are slowed by 50% for 2 turns.', 'Primal', 40, 290, 2, '{"bk_primal_howl"}', '{"x": -932, "y": 1110}', '{"damage": "2d8 thunder", "radius": "8m", "status": "50% Slow", "duration": "2 turns"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9f09d653-2116-464b-b5ee-c843acf2699e', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_wild_leap', 'Yabani Sıçrayış', 'Wild Leap', '12m''ye kadar uzaklıktaki bir konuma zıplayın. Yere inerken 4m içindeki tüm düşmanlara 4d6 fiziksel hasar veren bir şok dalgası yaratın.', 'Jump to a location up to 12m away. Upon landing, create a shockwave that deals 4d6 physical damage to all enemies within 4m.', 'Primal', 48, 400, 3, '{"bk_beast_charge"}', '{"x": -1092, "y": 1302}', '{"damage": "4d6", "range": "12m jump", "radius": "4m"}', '🦘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2d00db57-81cf-4d81-8819-0b517e0ab081', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_animalistic_vitality', 'Hayvani Zindelik', 'Animalistic Vitality', 'Doğanın direncinden faydalanın. Tüm zehirleri ve hastalıkları anında temizleyin ve 3 tur boyunca tur başına maksimum canınızın %10''unu yenileyin.', 'Tap into the resilience of nature. Instantly remove all poisons and diseases, and regenerate 10% of your max HP per turn for 3 turns.', 'Primal', 54, 460, 3, '{"bk_rending_claws"}', '{"x": -1253, "y": 1493}', '{"heal": "10% Max HP/turn", "status": "Cure poison/disease", "duration": "3 turns"}', '🌿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b73f06ef-4711-487a-98a4-85c649f600be', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_predator_strike', 'Yırtıcı Vuruşu', 'Predator Strike', 'Zayıflamış bir düşmandan faydalanın. 5d8 fiziksel hasar verir. Hedefin Canı %50''nin altındaysa, bu saldırı otomatik bir kritik vuruştur.', 'Exploit a weakened foe. Deals 5d8 physical damage. If the target is below 50% HP, this attack is an automatic critical hit.', 'Primal', 60, 490, 3, '{"bk_intimidating_roar"}', '{"x": -1414, "y": 1685}', '{"damage": "5d8", "special": "Auto-crit if HP < 50%"}', '🦅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('213a522e-f276-47fa-a04d-7b594a1ef0d5', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_apex_predator', 'Zirve Yırtıcı', 'Apex Predator', 'Pasif: Korkan, kanayan veya yere serilmiş düşmanlara %20 daha fazla hasar verirsiniz. Hareketleriniz zorlu arazileri yok sayar.', 'Passive: You deal 20% more damage to enemies that are frightened, bleeding, or prone. Your movement ignores difficult terrain.', 'Primal', 70, 700, 4, '{"bk_predator_strike"}', '{"x": -1574, "y": 1876}', '{"passive": "+20% Damage to debuffed foes", "buff": "Ignore difficult terrain"}', '🦁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ed69fa8d-812c-4b7b-b559-07eccbeabeda', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_savage_stampede', 'Vahşi İzdiham', 'Savage Stampede', 'Bir canavar sürüsünün ruhlarını çağırın. Bir ruh canavarı dalgası 15m ileri hücum ederek 6d10 fiziksel hasar verir ve tüm düşmanları yere serer.', 'Summon the spirits of a beast herd. A wave of spirit beasts charges forward 15m, dealing 6d10 physical damage and knocking all enemies prone.', 'Primal', 80, 880, 4, '{"bk_wild_leap", "bk_animalistic_vitality"}', '{"x": -1735, "y": 2068}', '{"damage": "6d10", "range": "15m line", "status": "Prone"}', '🐗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fa53d76b-7c10-4184-9edc-44e8603639b0', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_behemoth_form', 'Behemoth Formu', 'Behemoth Form', '4 tur boyunca devasa bir tarih öncesi canavara dönüşün. +10 Güç, +5m menzil kazanırsınız ve saldırılarınız hedefinizin 3m yakınındaki düşmanlara sıçrama hasarı verir.', 'Transform into a towering prehistoric beast for 4 turns. You gain +10 Strength, +5m reach, and your attacks deal splash damage to enemies within 3m of your target.', 'Primal', 90, 1200, 5, '{"bk_savage_stampede"}', '{"x": -1896, "y": 2259}', '{"buff": "+10 STR, +5m Reach", "damage": "Splash 3m", "duration": "4 turns"}', '🦖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ae92747f-cce5-4825-9690-e29e8ece4844', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_primal_aspect', 'İlkel Suret', 'Primal Aspect', 'Vahşi doğanın nihai ruhunu cisimleştirin. 5 tur boyunca tüm kitle kontrollerine karşı bağışık olursunuz, hareket hızınız iki katına çıkar ve her saldırı hedefe biriken %10''luk bir savunma düşüşü uygular.', 'Embody the ultimate spirit of the wild. For 5 turns, you are immune to all crowd control, your movement speed is doubled, and every attack applies a stacking 10% defense reduction to the target.', 'Primal', 95, 1480, 5, '{"bk_behemoth_form", "bk_apex_predator"}', '{"x": -2056, "y": 2451}', '{"buff": "CC Immunity, 2x Speed", "debuff": "10% Def shred/hit", "duration": "5 turns"}', '🐉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5d4c31b8-9b5d-4175-8d16-cdcf46d6377b', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_bloody_rage', 'Kanlı Öfke', 'Bloody Rage', 'Öfkenizi ve susuzluğunuzu birleştirin. Anında 30 Öfke kazanmak ve 3m içindeki tüm düşmanlara 2d4 kanama uygulamak için %10 Can feda edersiniz.', 'Combine your anger and thirst. You sacrifice 10% HP to instantly gain 30 Rage and apply a 2d4 bleed to all enemies within 3m.', 'Cross-Branch', 35, 280, 2, '{"bk_frenzy", "bk_blood_sacrifice"}', '{"x": -173, "y": -100}', '{"cost": "10% HP", "buff": "+30 Rage", "status": "2d4 Bleed (3m AoE)"}', '👺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e459cbaf-af4c-4bb1-b65c-016cfc01af0b', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_furious_roar', 'Öfkeli Kükreme', 'Furious Roar', 'Öfkenizi dışa vuran bir kükreme. 6m''lik bir koni içinde 3d6 gök gürültüsü hasarı verir ve vurulan her düşman için 10 Öfke üretir.', 'A roar that channels your rage outward. Deals 3d6 thunder damage in a 6m cone and generates 10 Rage for each enemy hit.', 'Cross-Branch', 36, 290, 2, '{"bk_frenzy", "bk_intimidating_roar"}', '{"x": -389, "y": -225}', '{"damage": "3d6 thunder", "area": "6m cone", "buff": "+10 Rage per hit"}', '🗯️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ae8f60e5-729c-44b7-bcaf-afc131e82797', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_feral_thirst', 'Vahşi Susuzluk', 'Feral Thirst', 'Hayvani doğanız kan arzular. Pasif: Kanayan bir düşmanı öldürdüğünüzde, anında maksimum canınızın %15''i kadar iyileşirsiniz ve sıçrama/hücum yeteneklerinizin bekleme süresini sıfırlarsınız.', 'Your animalistic nature craves blood. Passive: Whenever you kill a bleeding enemy, you instantly heal for 15% of your max HP and reset the cooldown of your leap/charge abilities.', 'Cross-Branch', 50, 430, 3, '{"bk_sanguine_feast", "bk_animalistic_vitality"}', '{"x": -606, "y": -350}', '{"passive": "Heal 15% Max HP on kill", "special": "Reset mobility CDs"}', '🤤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d3a4e1a0-d3d7-4c50-8c54-2a30672ccb65', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_berserkers_trance', 'Vahşinin Transı', 'Berserker''s Trance', 'Öfke, kan susuzluğu ve ilkel içgüdüyü harmanlayan bir transa girin. 3 tur boyunca gelen hasarın %50''sini yok sayarsınız ve verdiğiniz hasarın %50''si Can olarak geri döner.', 'Enter a trance that blends rage, bloodlust, and primal instinct. For 3 turns, you ignore 50% of incoming damage, and 50% of the damage you deal is returned as HP.', 'Cross-Branch', 60, 500, 3, '{"bk_unyielding_anger", "bk_blood_frenzy", "bk_predator_strike"}', '{"x": -822, "y": -475}', '{"buff": "50% Damage Reduction, 50% Lifesteal", "duration": "3 turns"}', '👁️‍🗨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('649b114d-2245-46e2-af87-af738c0fb16d', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_wrathful_blood_eruption', 'Gazaplı Kan Patlaması', 'Wrathful Blood Eruption', 'Yere vurarak 6m yarıçapında kristalize kan dikenlerinin fışkırmasına neden olun. 7d8 fiziksel hasar verir ve 3 kanama yükü uygular. 30 Öfke tüketir.', 'Slam the ground, causing spikes of crystallized blood to erupt in a 6m radius. Deals 7d8 physical damage and applies 3 stacks of bleeding. Consumes 30 Rage.', 'Cross-Branch', 72, 750, 4, '{"bk_seismic_slam", "bk_life_drain_aura"}', '{"x": -1039, "y": -600}', '{"damage": "7d8", "status": "3 Bleed stacks", "radius": "6m", "cost": "30 Rage"}', '🧨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b0e262bc-cb7b-4689-be1d-6599fae4c914', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_earthshattering_leap', 'Dünyayı Sarsan Sıçrayış', 'Earthshattering Leap', '15m''ye kadar zıplayın ve kıyamet gibi bir güçle yere çarpın. 8m yarıçapında 8d8 fiziksel hasar verir ve zorlu arazi sayılan bir krater bırakır.', 'Jump up to 15m and crash down with apocalyptic force. Deals 8d8 physical damage in an 8m radius and leaves a crater that counts as difficult terrain.', 'Cross-Branch', 75, 820, 4, '{"bk_death_defiance", "bk_apex_predator"}', '{"x": -1255, "y": -725}', '{"damage": "8d8", "range": "15m jump", "radius": "8m", "special": "Creates difficult terrain"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bfd697d6-03e1-4713-a793-6b39d8e33a17', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_crimson_beast_slash', 'Kızıl Canavar Kesişi', 'Crimson Beast Slash', 'İleriye doğru 10m ilerleyen, canavar pençesi şeklinde devasa bir kan dalgası serbest bırakın. 6d10 fiziksel hasar verir ve verilen hasarın %50''si kadar sizi iyileştirir.', 'Unleash a massive wave of blood in the shape of a beast''s claw, traveling forward 10m. Deals 6d10 physical damage and heals you for 50% of the damage dealt.', 'Cross-Branch', 78, 860, 4, '{"bk_crimson_storm", "bk_savage_stampede"}', '{"x": -1472, "y": -850}', '{"damage": "6d10", "range": "10m line", "heal": "50% of damage"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9ab2d611-459a-45f0-9f64-f2a7114e37ac', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_immortal_carnage', 'Ölümsüz Katliam', 'Immortal Carnage', 'Pasif: Canınız %20''nin altındayken, maksimum canınızın %30''undan daha az hasar veren hiçbir saldırıyla öldürülemezsiniz. Ayrıca, yakın dövüş saldırılarınız yakındaki 3 düşmana kadar biçer.', 'Passive: While your HP is below 20%, you cannot be killed by any attack that deals less than 30% of your max HP. Additionally, your melee attacks cleave up to 3 nearby enemies.', 'Cross-Branch', 85, 1100, 5, '{"bk_avatar_of_wrath", "bk_blood_lord"}', '{"x": -1688, "y": -975}', '{"passive": "Death resist (<30% Max HP attacks)", "buff": "Melee cleaves 3 targets"}', '♾️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f8768fbd-a31f-434c-b326-eb3aad300929', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_sanguine_behemoth', 'Kanlı Behemoth', 'Sanguine Behemoth', '4 tur boyunca kaynayan kandan yapılmış devasa bir canavara dönüşün. 200 geçici Can kazanırsınız, saldırılarınız şiddetli kanama (tur başına 4d6) uygular ve süreyi uzatmak için dökülen tüm kanı emersiniz.', 'Transform into a massive beast made of boiling blood for 4 turns. You gain 200 temporary HP, your attacks apply severe bleeding (4d6 per turn), and you absorb all blood spilled to extend the duration.', 'Cross-Branch', 90, 1250, 5, '{"bk_blood_lord", "bk_behemoth_form"}', '{"x": -1905, "y": -1100}', '{"buff": "+200 Temp HP", "status": "4d6 Bleed on hit", "duration": "4 turns (extendable)"}', '🦍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5d515eea-988c-4a57-ac1f-2cbd8dfff0c4', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_juggernaut_stampede', 'İlahın İzdihamı', 'Juggernaut Stampede', '20m''ye kadar vahşice hücum ederek bir yıkım izi bırakın. Yoldaki herkes 12d10 fiziksel hasar alır ve 2 tur sersemler. Bir duvara çarparsanız, duvar paramparça olur.', 'Charge wildly for up to 20m, leaving a trail of destruction. Anyone in the path takes 12d10 physical damage and is stunned for 2 turns. If you hit a wall, it shatters.', 'Cross-Branch', 92, 1350, 5, '{"bk_avatar_of_wrath", "bk_behemoth_form"}', '{"x": -2121, "y": -1225}', '{"damage": "12d10", "range": "20m line", "status": "Stun 2 turns"}', '🐘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('85decf0e-d081-4c4f-b02b-b9f8931a63de', '24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'bk_world_ender', 'Dünya Yıkan', 'World Ender', 'Vahşi öfkenin zirvesi. Gökyüzüne sıçrayıp yere çarparak 20m yarıçapındaki her şeyi yok edin. 20d12 fiziksel hasar ve 10d12 nekrotik hasar verir. Canınız 1''e düşer ancak 3 tur boyunca tüm hasarlara karşı bağışıklık kazanırsınız.', 'The pinnacle of berserker fury. Leap into the sky and crash down, destroying everything within a 20m radius. Deals 20d12 physical damage and 10d12 necrotic damage. You are reduced to 1 HP but gain immunity to all damage for 3 turns.', 'Cross-Branch', 100, 1500, 5, '{"bk_raging_juggernaut", "bk_carnage_incarnate", "bk_primal_aspect"}', '{"x": -2338, "y": -1350}', '{"damage": "20d12 physical, 10d12 necrotic", "radius": "20m", "cost": "Reduce to 1 HP", "buff": "Immunity for 3 turns"}', '🌍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5577c27c-2a33-49ae-985d-25970b9d4574', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_heat_metal', 'Metal Isıtma', 'Heat Metal', 'Hedeflenen düşmanın metal ekipmanını ısıtarak 2d6 ateş hasarı verir ve eğer kurtarma zarında başarısız olurlarsa eşyayı düşürmelerine sebep olur.', 'Heats a targeted enemy''s metal equipment, dealing 2d6 fire damage and causing them to drop it if they fail a save.', 'Forge', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "2d6 fire", "range": "15m", "save": "WIS or drop weapon"}', '♨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5c942f41-80aa-4cfc-8299-6dee4a572fef', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_sharpen_blade', 'Bıçak Bileme', 'Sharpen Blade', 'Bir müttefikin silahını geçici olarak biler, 10 dakika boyunca +1d4 hasar ve isabet zarına +1 kazandırır.', 'Temporarily sharpens an ally''s weapon, granting it +1d4 damage and +1 to hit for 10 minutes.', 'Upgrade', 2, 50, 1, '{}', '{"x": 128, "y": 153}', '{"buff": "+1d4 damage, +1 to hit", "range": "Touch", "duration": "10 mins"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('02e0ba49-9b30-4b93-b071-61e92193758e', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_throw_hammer', 'Çekiç Fırlatma', 'Throw Hammer', 'Büyüyle dövülmüş bir çekiçi 15m içindeki bir hedefe fırlatır, 2d8 ezici hasar verir ve çekiç elinize geri döner.', 'Hurls a magically forged hammer at a target within 15m, dealing 2d8 bludgeoning damage and returning to your hand.', 'Weaponry', 3, 60, 1, '{}', '{"x": -128, "y": 153}', '{"damage": "2d8 bludgeoning", "range": "15m", "effect": "Returns to hand"}', '🔨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b14e128a-fe11-4ac6-ae51-912c82df20b9', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_smelt_ore', 'Cevher Eritme', 'Smelt Ore', 'Bir hedefe yanan, erimiş cüruf parçası fırlatarak 2d8 ateş hasarı verir ve hareket hızlarını 2m azaltır.', 'Hurls a lump of burning, molten slag at a target, dealing 2d8 fire damage and reducing their movement speed by 2m.', 'Forge', 5, 80, 1, '{"bs_heat_metal"}', '{"x": 389, "y": -224}', '{"damage": "2d8 fire", "range": "12m", "speed_reduction": "-2m"}', '🪨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('196f4de5-ac88-4094-9718-07501bd00f7a', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_mend_armor', 'Zırh Onarımı', 'Mend Armor', 'Bir zırh parçasını hızla onararak giyene 2d8 geçici HP kazandırır ve ''Kırık'' durumunu kaldırır.', 'Quickly repairs a piece of armor, restoring 2d8 temporary HP to the wearer and removing the ''Broken'' condition.', 'Upgrade', 8, 90, 1, '{"bs_sharpen_blade"}', '{"x": 289, "y": 344}', '{"heal": "2d8 temp HP", "effect": "Removes Broken condition", "range": "Touch"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('37db3c9d-0780-40ba-875d-2fec1839a6c3', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_phantom_dagger', 'Hayalet Hançer', 'Phantom Dagger', 'Zırhı delip geçen yarı saydam bir hançer fırlatır. Zırhtan gelen AC bonuslarını yok sayarak 2d4 delici hasar verir.', 'Throws a translucent dagger that pierces through armor, dealing 2d4 piercing damage and ignoring AC bonuses from armor.', 'Weaponry', 10, 100, 1, '{"bs_throw_hammer"}', '{"x": -289, "y": 344}', '{"damage": "2d4 piercing", "range": "15m", "effect": "Ignores Armor AC"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('92ee4ed1-1da1-48d0-a8f6-1bde5dc325dc', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_forge_sparks', 'Ocak Kıvılcımları', 'Forge Sparks', '5m''lik bir koni alanına kör edici kıvılcımlar saçarak 3d4 ateş hasarı verir ve düşmanları 1 turluğuna kör eder.', 'Emits a blast of blinding sparks in a 5m cone, dealing 3d4 fire damage and blinding enemies for 1 turn.', 'Forge', 12, 120, 1, '{"bs_smelt_ore"}', '{"x": 606, "y": -349}', '{"damage": "3d4 fire", "area": "5m cone", "status": "Blinded (1 turn)"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('46033614-f2c7-4138-bb8f-7c7c543d2dbe', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_reinforce_shield', 'Kalkan Güçlendirme', 'Reinforce Shield', 'Bir müttefikin kalkanını güçlendirir, 3 tur boyunca onlara +2 AC ve fiziksel saldırıları tamamen bloklamak için %10 şans verir.', 'Strengthens an ally''s shield, granting them +2 AC and a 10% chance to completely block physical attacks for 3 turns.', 'Upgrade', 15, 130, 1, '{"bs_mend_armor"}', '{"x": 449, "y": 536}', '{"buff": "+2 AC, 10% block chance", "duration": "3 turns", "range": "Touch"}', '🧿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6461e225-1d11-4211-b0d8-663ed5e07418', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_iron_grip', 'Demir Kavrama', 'Iron Grip', 'Elleriniz demir bir mengene gibi olur. 2m içindeki bir düşmanı kavrayarak her tur 1d10 ezici hasar verir ve onları kısıtlarsınız.', 'Your hands become like iron vises. You grapple an enemy within 2m, dealing 1d10 bludgeoning damage per turn and restraining them.', 'Weaponry', 18, 140, 1, '{"bs_phantom_dagger"}', '{"x": -449, "y": 536}', '{"damage": "1d10 bludgeoning/turn", "range": "2m", "status": "Restrained"}', '🦾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f18723ff-d21d-4440-ae7a-470de4f23781', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_molten_splash', 'Erimiş Sıçrama', 'Molten Splash', '4m''lik bir yarıçapa sıvı metal sıçratır, 4d6 ateş hasarı verir ve 3 tur boyunca 1d6 hasar veren yanma etkisi uygular.', 'Splashes liquid metal in a 4m radius, dealing 4d6 fire damage and applying a burning effect that deals 1d6 damage for 3 turns.', 'Forge', 22, 180, 2, '{"bs_forge_sparks"}', '{"x": 822, "y": -474}', '{"damage": "4d6 fire", "area": "4m radius", "status": "Burning (1d6/3 turns)"}', '💦');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b2398695-02d4-4638-8d43-96ed4439e70a', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_heavy_plating', 'Ağır Kaplama', 'Heavy Plating', 'Bir müttefikin zırhını kalın metalle kaplar. +4 AC ve kesici/delici hasarlara direnç kazandırır, ancak hareket hızını 3m düşürür.', 'Coats an ally''s armor in thick metal. Grants +4 AC and resistance to slashing/piercing damage, but reduces movement speed by 3m.', 'Upgrade', 24, 190, 2, '{"bs_reinforce_shield"}', '{"x": 610, "y": 727}', '{"buff": "+4 AC, Physical Resist", "debuff": "-3m speed", "duration": "10 mins"}', '🪨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a13e1ce5-35a5-4bbb-864e-5b562d4841a7', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_summon_anvil', 'Örs Çağırma', 'Summon Anvil', '20m içinde belirlenen 3m yarıçaplı bir alana gökyüzünden 500kg''lık bir örs düşürür. 4d10 ezici hasar verir ve düşmanları yere serer.', 'Drops a 500kg anvil from the sky onto a 3m radius area within 20m. Deals 4d10 bludgeoning damage and knocks enemies prone.', 'Weaponry', 25, 210, 2, '{"bs_iron_grip"}', '{"x": -610, "y": 727}', '{"damage": "4d10 bludgeoning", "area": "3m radius within 20m", "status": "Prone"}', '🏗️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8a1f5930-ee57-416c-814d-37330fd33f1b', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_shape_iron', 'Demir Şekillendirme', 'Shape Iron', 'Saldırıları engellemek veya dar geçitleri kapatmak için yerden 3m genişliğinde, 2m yüksekliğinde som demirden bir duvar yükseltir.', 'Summons a 3m wide, 2m tall wall of solid iron from the ground to block attacks or narrow passages.', 'Forge', 28, 200, 2, '{"bs_smelt_ore"}', '{"x": 1039, "y": -599}', '{"area": "3m wide, 2m tall wall", "duration": "5 turns", "hp": "50"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('32764415-4120-477a-a3b2-1f70026ed0b7', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_alloy_coating', 'Alaşım Kaplama', 'Alloy Coating', 'Bir silahı veya zırhı özel bir alaşımla kaplar, onu 1 saatliğine pas, asit ve bozulmaya karşı bağışık hale getirir.', 'Coats a weapon or armor in a special alloy, making it immune to rust, acid, and degradation for 1 hour.', 'Upgrade', 30, 220, 2, '{"bs_reinforce_shield"}', '{"x": 771, "y": 919}', '{"buff": "Immune to rust/acid/degradation", "duration": "1 hour", "range": "Touch"}', '🧪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fa25227e-d0fa-4476-a1bb-72574517389e', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_flying_axes', 'Uçan Baltalar', 'Flying Axes', 'İki balta döver ve onları bir kavisle fırlatır. Her balta 15m içindeki farklı bir hedefi bularak 3d6 kesici hasar verir.', 'Forges two axes and throws them in an arc. Each axe targets a different enemy within 15m, dealing 3d6 slashing damage.', 'Weaponry', 32, 240, 2, '{"bs_iron_grip"}', '{"x": -771, "y": 919}', '{"damage": "3d6 slashing per axe (x2)", "range": "15m"}', '🪓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c7576fd4-9d17-4d51-b901-4f2048929e2a', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_bellows_breath', 'Körük Nefesi', 'Bellows'' Breath', '10m''lik bir hat boyunca kavurucu sıcak hava üfler, düşmanları 3m geriye savurur ve 3d8 ateş hasarı verir.', 'Blows a 10m line of searing hot air, pushing enemies back 3m and dealing 3d8 fire damage.', 'Forge', 35, 250, 2, '{"bs_molten_splash", "bs_shape_iron"}', '{"x": 1255, "y": -724}', '{"damage": "3d8 fire", "area": "10m line", "knockback": "3m"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('81c2d900-0b70-422f-aaf0-fd2a6d38e72b', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_molten_armor', 'Erimiş Zırh', 'Molten Armor', 'Bir müttefiki koruyucu erimiş metal bir katmanla kaplar. +3 AC kazandırır ve 2m içindeki yakın dövüş saldırganları 2d8 ateş hasarı alır. 3 tur sürer.', 'Coats an ally in a layer of defensive molten metal. Grants +3 AC, and any melee attacker within 2m takes 2d8 fire damage. Lasts 3 turns.', 'Forge', 36, 270, 2, '{"bs_shape_iron", "bs_heavy_plating"}', '{"x": 1472, "y": -849}', '{"buff": "+3 AC", "damage": "2d8 fire to attackers within 2m", "duration": "3 turns"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b5da6f16-1378-4319-89f8-4adc59c60715', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_weightless_steel', 'Ağırlıksız Çelik', 'Weightless Steel', 'Bir müttefikin ekipmanını büyüyle doldurarak ağırlığını sıfıra indirir. 5 tur boyunca +3m hareket hızı ve Çeviklik kurtarma zarlarında avantaj sağlar.', 'Infuses an ally''s gear with magic, reducing its weight to zero. Grants +3m movement speed and advantage on Dexterity saving throws for 5 turns.', 'Upgrade', 38, 280, 2, '{"bs_heavy_plating", "bs_alloy_coating"}', '{"x": 932, "y": 1110}', '{"buff": "+3m speed, Advantage on DEX saves", "duration": "5 turns", "range": "Touch"}', '🪶');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5ab37220-a396-4f3a-9e1b-926b5bc8388d', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_shattering_strike', 'Parçalayan Vuruş', 'Shattering Strike', 'Hedefe 4d8 ezici hasar veren ve Zırh Sınıfını (AC) kalıcı olarak 2 düşüren yıkıcı bir yakın dövüş vuruşu yapar.', 'A devastating melee strike that deals 4d8 bludgeoning damage and permanently reduces the target''s AC by 2.', 'Weaponry', 40, 300, 2, '{"bs_summon_anvil", "bs_flying_axes"}', '{"x": -932, "y": 1110}', '{"damage": "4d8 bludgeoning", "range": "Melee", "debuff": "-2 AC permanently"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0fdacbcb-42f2-4121-8243-1afcf4d476e6', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_magma_pool', 'Magma Havuzu', 'Magma Pool', '10m yarıçaplı bir alanı 5 turluğuna fokurdayan magmaya çevirir. İçeride turuna başlayan düşmanlar 5d6 ateş hasarı alır ve hızları yarıya iner.', 'Transforms a 10m radius area of the ground into bubbling magma for 5 turns. Enemies starting their turn inside take 5d6 fire damage and have their speed halved.', 'Forge', 42, 350, 3, '{"bs_bellows_breath"}', '{"x": 1688, "y": -974}', '{"damage": "5d6 fire", "area": "10m radius", "duration": "5 turns", "speed": "Halved"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('13e13f42-b4b0-4c07-840b-d9edb39b6edd', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_elemental_edge', 'Elementel Keskinlik', 'Elemental Edge', 'Bir silaha elementsel güç (Ateş, Soğuk veya Yıldırım) aşılar. Silah 1 dakika boyunca fazladan 2d6 elementsel hasar verir.', 'Imbues a weapon with elemental power (Fire, Cold, or Lightning). The weapon deals an additional 2d6 elemental damage for 1 minute.', 'Upgrade', 44, 360, 3, '{"bs_weightless_steel"}', '{"x": 1092, "y": 1302}', '{"damage": "+2d6 elemental", "duration": "1 min", "range": "Touch"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cf16173b-86ef-4a2a-8cd6-284fed09a7ac', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_whirlwind_blades', 'Bıçak Kasırgası', 'Whirlwind of Blades', '2 tur boyunca etrafınızda 5m yarıçapında uçuşan kılıçlardan oluşan bir girdap çağırır. İçeri giren veya turuna başlayan düşmanlar 4d8 kesici hasar alır.', 'Summons a vortex of flying swords around yourself in a 5m radius for 2 turns. Enemies entering or starting their turn take 4d8 slashing damage.', 'Weaponry', 46, 380, 3, '{"bs_shattering_strike"}', '{"x": -1092, "y": 1302}', '{"damage": "4d8 slashing", "area": "5m radius aura", "duration": "2 turns"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fa5d70bd-b882-457e-ab94-5a1dd4393747', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_forge_fire', 'Ocak Ateşi', 'Forge Fire', 'Lokal bir mistik ocak ateşi yakar. 8m içindeki müttefikler %50 ateş direnci kazanırken düşmanlar her tur 2d6 ateş hasarı alır.', 'Ignites a localized mystical fire. Allies within 8m gain 50% fire resistance, while enemies take 2d6 fire damage per turn.', 'Forge', 48, 400, 3, '{"bs_bellows_breath"}', '{"x": 1905, "y": -1099}', '{"buff": "50% Fire Resist", "damage": "2d6 fire/turn to enemies", "area": "8m radius"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4ee8edc7-16e7-4582-b105-a755f05ad5f4', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_reflecting_polish', 'Yansıtan Cila', 'Reflecting Polish', 'Bir müttefikin zırhını ayna parlaklığında cilalar. 3 tur boyunca tek hedefine alınan büyülerin büyücüye geri sekmesi için %30 şans tanır.', 'Polishes an ally''s armor to a mirror finish. For 3 turns, single-target magic spells have a 30% chance to bounce back at the caster.', 'Upgrade', 50, 420, 3, '{"bs_weightless_steel"}', '{"x": 1253, "y": 1493}', '{"buff": "30% chance to reflect spells", "duration": "3 turns", "range": "Touch"}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6c97e050-d7e3-4af0-8b4a-06f03c964874', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_chain_whip', 'Dövme Zincir Kırbaç', 'Forged Chain Whip', '15m uzunluğunda çivili bir zincir yaratır. Bir hedefe 3d10 kesici hasar verir ve onları 5m size doğru çeker.', 'Creates a 15m long spiked chain. Deals 3d10 slashing damage to a target and pulls them 5m towards you.', 'Weaponry', 52, 440, 3, '{"bs_shattering_strike"}', '{"x": -1253, "y": 1493}', '{"damage": "3d10 slashing", "range": "15m", "effect": "Pulls target 5m"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f7a34a8d-0997-488b-ba25-bb640d5180ff', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_flaming_hammer', 'Alevli Çekiç', 'Flaming Hammer', 'Ocakta aşırı ısıtılmış bir çekiç fırlatır. 4d8 ezici ve 4d8 ateş hasarı verir, çarptığında 8m yarıçapında patlar.', 'Throws a hammer superheated by the forge. Deals 4d8 bludgeoning and 4d8 fire damage, exploding in an 8m radius on impact.', 'Weaponry', 54, 460, 3, '{"bs_magma_pool", "bs_summon_anvil"}', '{"x": -1414, "y": 1685}', '{"damage": "4d8 bludgeoning + 4d8 fire", "area": "8m radius explosion", "range": "15m"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('42a0fd34-4671-4987-8b76-6e2706c11cca', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_slag_eruption', 'Cüruf Püskürmesi', 'Slag Eruption', '6m''lik bir alanda keskin, yanan cürufların yerden püskürmesine neden olur. 6d6 delici ve ateş hasarı verir, düşmanları 1 turluğuna yere mıhlar.', 'Causes sharp, burning slag to erupt from the ground in a 6m radius, dealing 6d6 piercing and fire damage, pinning enemies to the ground for 1 turn.', 'Forge', 55, 450, 3, '{"bs_magma_pool", "bs_forge_fire"}', '{"x": 2121, "y": -1224}', '{"damage": "6d6 piercing/fire", "area": "6m radius", "status": "Pinned (1 turn)"}', '🎆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7b48e77d-7c2c-433c-a280-43afc8983b1e', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_dancing_swords', 'Dans Eden Kılıçlar', 'Dancing Swords', 'Otomatik olarak savaşmaları için 3 geçici kılıcı geliştirir. 10m içindeki müttefiklerin etrafında süzülerek saldırıları savuşturur ve yakındaki düşmanlara 3d6 kesici hasar verirler.', 'Upgrades 3 temporary swords to fight automatically. They hover around allies within 10m, parrying attacks and dealing 3d6 slashing damage to nearby enemies.', 'Upgrade', 56, 470, 3, '{"bs_elemental_edge", "bs_whirlwind_blades"}', '{"x": 1414, "y": 1685}', '{"summons": "3 automated swords (3d6 slashing)", "area": "10m aura", "duration": "3 turns"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('46a59e4f-a7aa-42f7-a645-749a3dbd65a5', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_adamantine_rivets', 'Adamantiyum Perçinler', 'Adamantine Rivets', 'Bir müttefikin zırhını adamantiyum ile güçlendirir. Giyen kişi 10 dakika boyunca kritik vuruşlara karşı bağışık olur ve gelen tüm fiziksel hasarı 5 azaltır.', 'Reinforces an ally''s armor with adamantine. The wearer becomes immune to critical hits and reduces all incoming physical damage by 5 for 10 minutes.', 'Upgrade', 58, 480, 3, '{"bs_elemental_edge", "bs_reflecting_polish"}', '{"x": 1574, "y": 1876}', '{"buff": "Crit Immunity, 5 Physical Damage Reduction", "duration": "10 mins"}', '💎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('554f711a-ae3c-4178-a71e-9968a5efa3fa', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_heavy_impact', 'Ağır Darbe', 'Heavy Impact', 'Devasa bir çekiçle yere vurur. 8m''lik bir koni içindeki herkese 5d10 ezici hasar verir ve tüm düşmanları 6m geriye savurur.', 'Slams the ground with a massive hammer. Deals 5d10 bludgeoning damage in an 8m cone and knocks all enemies back 6m.', 'Weaponry', 60, 500, 3, '{"bs_whirlwind_blades", "bs_chain_whip"}', '{"x": -1574, "y": 1876}', '{"damage": "5d10 bludgeoning", "area": "8m cone", "knockback": "6m"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7be61e66-4bf6-44f3-959a-2b96a7567639', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_liquid_steel', 'Sıvı Çelik', 'Liquid Steel', '12m içindeki bir hedefin üzerine sıvı çelik selini boşaltır. 8d8 ateş hasarı verir ve anında katılaşarak hedefi 2 turluğuna hareketsiz bırakır.', 'Pours a torrent of liquid steel onto a target within 12m. Deals 8d8 fire damage and hardens instantly, immobilizing them for 2 turns.', 'Forge', 62, 650, 4, '{"bs_slag_eruption"}', '{"x": 2338, "y": -1349}', '{"damage": "8d8 fire", "range": "12m", "status": "Immobilized (2 turns)"}', '🫗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3a085c29-127d-4197-b6a0-d67b8e1e2e85', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_enchanted_alloy', 'Efsunlu Alaşım', 'Enchanted Alloy', 'Bir silahı veya zırhı 1 saatliğine +2 büyülü statüye yükseltir ve ona normal büyü dirençlerini aşan özellikler kazandırır.', 'Upgrades a weapon or armor to +2 magical status for 1 hour, granting it properties that bypass normal magical resistances.', 'Upgrade', 64, 680, 4, '{"bs_adamantine_rivets"}', '{"x": 1735, "y": 2068}', '{"buff": "+2 Magical Status, Magic Resist", "duration": "1 hour"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cfb20475-2ac7-43ff-a7ab-83d477a48068', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_rain_of_spears', 'Mızrak Yağmuru', 'Rain of Spears', '12m''lik bir alana yağmur gibi yağan yüzlerce mızrak yaratır. 8d6 delici hasar verir ve düşmanları 1 turluğuna yere mıhlar.', 'Conjures hundreds of spears that rain down in a 12m radius, dealing 8d6 piercing damage and pinning enemies to the ground for 1 turn.', 'Weaponry', 65, 700, 4, '{"bs_heavy_impact"}', '{"x": -1735, "y": 2068}', '{"damage": "8d6 piercing", "area": "12m radius", "status": "Pinned (1 turn)"}', '🌧️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6a150f90-d6ab-4588-a95b-97d2202d5f5b', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_obsidian_forge', 'Obsidyen Ocağı', 'Obsidian Forge', '15m''lik bir alana jilet gibi keskin obsidyen parçaları saçar. İçinden geçen herkes hareket ettiği her 2m için 2d8 kesici hasar alır.', 'Scatters razor-sharp obsidian shards over a 15m area. Anyone moving through it takes 2d8 slashing damage per 2m moved.', 'Forge', 68, 750, 4, '{"bs_slag_eruption"}', '{"x": 2554, "y": -1474}', '{"damage": "2d8 slashing per 2m moved", "area": "15m radius", "duration": "5 turns"}', '🖤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b95ea915-9693-43ce-9d77-46e396708a17', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_volcanic_shield', 'Volkanik Kalkan', 'Volcanic Shield', 'Sertleşmiş magmadan 5m genişliğinde bir barikat kurar. Gelen tüm mermileri engeller ve ona saldıran herkese 3d6 hasarlık bir ateş topu fırlatır.', 'Erects a 5m wide barricade of hardened magma. It blocks all incoming projectiles, and shoots a 3d6 fireball back at anyone who attacks it.', 'Forge', 70, 750, 4, '{"bs_liquid_steel", "bs_enchanted_alloy"}', '{"x": 2771, "y": -1599}', '{"effect": "Blocks projectiles, counterattacks with 3d6 fireballs", "area": "5m wide", "duration": "3 turns"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('26bd21d5-84fd-438d-bcdc-f60d4432ed6d', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_unbreakable_ward', 'Kırılmaz Tılsım', 'Unbreakable Ward', 'Bir müttefikin donanımına koruyucu bir mühür yerleştirir. 1 turluğuna tüm hasarlara karşı dokunulmazlık kazanırlar ve ekipmanları çıkarılamaz veya yok edilemez.', 'Places a protective seal on an ally''s gear. They gain invulnerability to all damage for 1 turn, and their gear cannot be unequipped or destroyed.', 'Upgrade', 72, 780, 4, '{"bs_adamantine_rivets"}', '{"x": 1896, "y": 2259}', '{"buff": "Invulnerability, Gear cannot be destroyed", "duration": "1 turn"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1a602a37-6de9-4f69-af84-759014870576', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_colossal_hammer', 'Devasa Çekiç', 'Colossal Hammer', 'İnanılmaz büyüklükte bir çekiç döver. 10m içinde 5m yarıçaplı bir alana tek bir vuruş yaparak 10d10 ezici hasar verir ve hayatta kalanları sersemletir.', 'Forges an impossibly large hammer. Deals a single strike on a 5m radius area within 10m, dealing 10d10 bludgeoning damage and stunning survivors.', 'Weaponry', 74, 800, 4, '{"bs_heavy_impact"}', '{"x": -1896, "y": 2259}', '{"damage": "10d10 bludgeoning", "area": "5m radius within 10m", "status": "Stunned"}', '⚒️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9bd6f8d6-bb6c-4869-a1a9-3cf916ab6f86', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_core_temperature', 'Çekirdek Isısı', 'Core Temperature', 'Aşırı bir ısı yayar. 3 tur boyunca, 20m içindeki tüm büyülü olmayan metal silah ve zırhlar erimeye başlar, yok olur ve giyenlere 4d10 ateş hasarı verir.', 'Radiates extreme heat. For 3 turns, all non-magical metal weapons and armor within 20m begin to melt, destroying them and dealing 4d10 fire damage to wearers.', 'Forge', 75, 850, 4, '{"bs_liquid_steel", "bs_obsidian_forge"}', '{"x": 2987, "y": -1724}', '{"damage": "4d10 fire", "area": "20m radius", "effect": "Melts non-magical metal"}', '🌡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('498fc07f-aba8-4b90-84b4-6fb2964b14e7', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_meteor_strike', 'Meteor Çarpması', 'Meteor Strike', 'Ölen bir yıldızın çekirdeğinden bir örs döver. Onu 20m''lik bir alana düşürerek 8d10 ezici ve 8d10 ateş hasarı verir, arkasında bir magma havuzu bırakır.', 'Forges an anvil from the core of a dying star. Drops it on a 20m area, dealing 8d10 bludgeoning and 8d10 fire damage, leaving a pool of magma behind.', 'Weaponry', 76, 850, 4, '{"bs_core_temperature", "bs_colossal_hammer"}', '{"x": -2056, "y": 2451}', '{"damage": "8d10 bludgeoning + 8d10 fire", "area": "20m radius", "effect": "Leaves magma pool"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2b349449-7832-45ae-b2d6-d40a6bf0ec60', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_runic_etching', 'Rün İşlemesi', 'Runic Etching', 'Bir müttefikin silahına parlayan rünler kazır. Saldırıları isabet ettiğinde 3m yarıçapında 4d6 güç hasarı veren bir patlamayı tetikler.', 'Carves glowing runes into an ally''s weapon, causing their attacks to trigger an explosion of 4d6 force damage in a 3m radius on hit.', 'Upgrade', 78, 880, 4, '{"bs_enchanted_alloy", "bs_unbreakable_ward"}', '{"x": 2056, "y": 2451}', '{"damage": "4d6 force explosion on hit", "area": "3m radius on hit", "duration": "1 min"}', '🔣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a4276c56-fa4a-410b-99cb-7d48931bbf91', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_mastercrafted_arsenal', 'Usta İşi Cephanelik', 'Mastercrafted Arsenal', 'Grubunuz için efsanevi silahlardan oluşan bir raf çağırır. 5 tur boyunca tüm müttefiklerin silah saldırıları fazladan 4d8 güç hasarı verir ve 18-20 zarlarında kritik vurur.', 'Summons a rack of legendary weapons for your party. For 5 turns, all allies'' weapon attacks deal an extra 4d8 force damage and score a critical hit on a 18-20.', 'Upgrade', 79, 890, 4, '{"bs_runic_etching", "bs_phantom_armory"}', '{"x": 2217, "y": 2642}', '{"buff": "+4d8 force damage, Crit on 18-20", "area": "Party within 20m", "duration": "5 turns"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('94ab06cd-724b-474c-b15e-cb67f3067824', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_phantom_armory', 'Hayalet Cephanelik', 'Phantom Armory', '4 tur boyunca sizinle birlikte savaşan 5 hareketli ruhani silah çağırır. Her biri bağımsız saldırarak tur başına 2d8 hasar verir.', 'Summons 5 animated spectral weapons that fight alongside you for 4 turns. Each makes an independent attack dealing 2d8 damage per turn.', 'Weaponry', 80, 900, 4, '{"bs_rain_of_spears", "bs_colossal_hammer"}', '{"x": -2217, "y": 2642}', '{"summons": "5 spectral weapons (2d8 damage each)", "duration": "4 turns"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('81f71ecb-5e70-4f44-a12a-78d5def75602', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_heart_of_the_forge', 'Ocağın Kalbi', 'Heart of the Forge', 'Efsanevi bir ocağın ateşli çekirdeğini çağırır. 25m içindeki tüm düşmanları kendine çeker, 10d10 ateş hasarı verir ve savunmalarını eritir (Zırh Sınıfını 5 düşürür).', 'Summons the fiery core of a legendary forge. It pulls all enemies within 25m towards it, dealing 10d10 fire damage and melting their defenses (reduces AC by 5).', 'Forge', 82, 1100, 5, '{"bs_core_temperature"}', '{"x": 3204, "y": -1849}', '{"damage": "10d10 fire", "area": "25m radius", "effect": "Pulls enemies, -5 AC"}', '❤️‍🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9408b264-7924-4351-8a2c-279c871c3c69', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_aegis_craft', 'Kalkan Zanaatı', 'Aegis Craft', '15m içindeki tüm grup için ruhani bir Koruyucu kalkan döver. 3 tur boyunca +5 AC, 50 geçici HP ve tüm kurtarma zarlarında avantaj sağlar.', 'Forges an ethereal Aegis shield for the entire party within 15m. Grants +5 AC, 50 temporary HP, and advantage on all saving throws for 3 turns.', 'Upgrade', 84, 1150, 5, '{"bs_runic_etching"}', '{"x": 2378, "y": 2834}', '{"buff": "+5 AC, 50 temp HP, Advantage on Saves", "area": "15m radius party", "duration": "3 turns"}', '🔰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('23083b56-ff7a-4a5a-a96d-96b8b140a574', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_blade_storm', 'Kılıç Fırtınası', 'Blade Storm', 'Dövülmüş binlerce kılıçtan oluşan 30m yarıçaplı devasa bir fırtına yaratır. İçerideki tüm düşmanlara 8d10 kesici hasar verir ve zırhlarını tamamen parçalar.', 'Creates a massive 30m radius storm of thousands of forged blades. Deals 8d10 slashing damage to all enemies inside, shredding their armor completely.', 'Weaponry', 86, 1200, 5, '{"bs_phantom_armory"}', '{"x": -2378, "y": 2834}', '{"damage": "8d10 slashing", "area": "30m radius", "effect": "Shreds armor completely"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('587bc571-6fef-41c0-b676-4de89b9d40cf', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_forge_gods_avatar', 'Ocak Tanrısının Avatarı', 'Forge God''s Avatar', '3 turluğuna mükemmel çelikten ve erimiş çekirdekten oluşan 5m boyunda bir varlığa dönüşürsünüz. 200 geçici HP kazanırsınız, fiziksel/ateş hasarına bağışık olursunuz ve yakın dövüş saldırılarınız 10d10 karma hasar verir.', 'You transform into a 5m tall being of perfect steel and molten core for 3 turns. You gain 200 temporary HP, immunity to physical/fire damage, and your melee attacks deal 10d10 mixed damage.', 'Weaponry', 88, 1250, 5, '{"bs_heart_of_the_forge", "bs_aegis_craft", "bs_blade_storm"}', '{"x": -2539, "y": 3025}', '{"buff": "200 temp HP, Immune to physical/fire", "damage": "10d10 mixed", "duration": "3 turns"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('675053cc-db91-4b6f-940f-2f70801c839d', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_master_of_metals_ult', 'Metallerin Efendisi', 'Master of Metals', 'Ocak Ultisi. Metal ve ısı üzerinde mutlak kontrol kazanırsınız. 5 tur boyunca tüm ateş hasarlarınız dirençleri yok sayar, ateşe bağışık olursunuz ve 50m içindeki herhangi bir metal nesneyi istediğiniz gibi şekillendirebilirsiniz.', 'Forge Ultimate. You gain absolute control over metal and heat. For 5 turns, all your fire damage ignores resistance, you become immune to fire, and you can mold any metallic object within 50m at will.', 'Forge', 90, 1300, 5, '{"bs_heart_of_the_forge"}', '{"x": 3420, "y": -1974}', '{"buff": "Immune to fire, ignore fire res, control metal", "duration": "5 turns", "area": "50m"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('aa0e87f4-c8d0-4988-8724-a9efdcf1714a', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_perfectionist_ult', 'Mükemmeliyetçinin Dokunuşu', 'Perfectionist''s Touch', 'Geliştirme Ultisi. Tüm grup üyelerinin silahlarını ve zırhlarını 5 turluğuna anında Efsanevi statüye yükseltir. Tüm zarlara +3 kazandırır, hasar zarlarını ikiye katlar ve devasa hasar azaltma sağlar.', 'Upgrade Ultimate. Instantly upgrades all party members'' weapons and armor to Legendary status for 5 turns. Grants +3 to all rolls, double damage dice, and massive damage reduction.', 'Upgrade', 92, 1350, 5, '{"bs_aegis_craft"}', '{"x": 2539, "y": 3025}', '{"buff": "+3 to rolls, double damage dice, massive reduction", "duration": "5 turns", "area": "Party"}', '🌟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('be459b81-108f-47b6-9016-36da855051ee', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_gods_anvil_ult', 'Tanrının Örsü', 'God''s Anvil', 'Silahşörlük Ultisi. Bir bina büyüklüğünde ilahi bir örs çağırır. 25m''lik bir alana düşerek 15d10 ezici hasar verir, tüm dirençleri yok sayar ve kalıcı bir krater oluşturur.', 'Weaponry Ultimate. Summons a divine anvil the size of a building. Drops onto a 25m radius area, dealing 15d10 bludgeoning damage, ignoring all resistances, and creating a permanent crater.', 'Weaponry', 94, 1400, 5, '{"bs_blade_storm"}', '{"x": -2699, "y": 3217}', '{"damage": "15d10 bludgeoning", "area": "25m radius", "effect": "Ignores resistances, permanent crater"}', '⛪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1b7aacae-c8c6-4ecd-9759-f41a685e1c14', '5fb3736e-08b0-417b-aa15-f791f4d8e136', 'bs_creation_engine_grand_ult', 'Yaratılış Motoru', 'The Creation Engine', 'Büyük Ulti. Savaş alanına devasa, karmaşık bir savaş fabrikası-motoru çağırır. Müttefikleri sürekli olarak geliştirir (AC/hasarı maksimuma çıkarır), düşmanların üzerine örsler yağdırır ve 50m''lik arenayı kavurucu magmayla doldurur. 5 tur sürer.', 'Grand Ultimate. Summons a massive, intricate factory-engine of war on the battlefield. It continuously upgrades allies (maxing AC/damage), rains anvils on enemies, and floods the 50m arena with searing magma. Lasts 5 turns.', 'Forge', 100, 1500, 5, '{"bs_master_of_metals_ult", "bs_perfectionist_ult", "bs_gods_anvil_ult"}', '{"x": 3637, "y": -2099}', '{"effect": "Maxes AC/dmg, rains anvils, floods 50m with magma", "duration": "5 turns"}', '⚙️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4b4b9deb-2b52-45fb-be62-dea5c6d19fb8', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_blood_bolt', 'Kan Mermisi', 'Blood Bolt', 'Sertleşmiş kandan bir mermi fırlatır. 20m içindeki bir hedefe 2d6 nekrotik hasar vermek için 2 SP feda eder.', 'Fires a bolt of hardened blood. Costs 2 HP to cast, dealing 2d6 necrotic damage to a target within 20m.', 'Blood Sacrifice', 1, 100, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "2d6 necrotic", "range": "20m", "cost": "2 HP"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2316a2ba-4eb6-46ec-acc5-3daf6cd42a59', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_crimson_slash', 'Kızıl Kesik', 'Crimson Slash', 'Kandan bir bıçakla 5m''lik bir koni alanını keser. 5 SP feda ederek 3d6 kesici hasar verir.', 'Swipes with a blade of blood in a 5m cone. Costs 5 HP, dealing 3d6 slashing damage.', 'Blood Sacrifice', 5, 120, 1, '{"bm_blood_bolt"}', '{"x": 389, "y": -224}', '{"damage": "3d6 slashing", "area": "5m cone", "cost": "5 HP"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a7e255f1-47fa-4fb2-ba30-cffa264168ae', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_boiling_blood', 'Kaynayan Kan', 'Boiling Blood', 'Bir düşmanın kanını kaynatmak için 8 SP feda eder. 3 tur boyunca her tur 1d8 ateş hasarı verir.', 'Sacrifices 8 HP to boil an enemy''s blood. Deals 1d8 fire damage per turn for 3 turns.', 'Blood Sacrifice', 10, 150, 1, '{"bm_crimson_slash"}', '{"x": 606, "y": -349}', '{"damage": "1d8 fire/turn", "duration": "3 turns", "cost": "8 HP"}', '🌡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('37223038-d442-41fe-9d07-d42eb40c8d86', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_blood_nova', 'Kan Novası', 'Blood Nova', 'Kendi kanınızı dışa doğru patlatır. 15 SP feda ederek 10m içindeki tüm düşmanlara 4d8 nekrotik hasar verir.', 'Explodes your own blood outwards. Costs 15 HP, dealing 4d8 necrotic damage to all enemies within 10m.', 'Blood Sacrifice', 22, 250, 2, '{"bm_boiling_blood"}', '{"x": 822, "y": -474}', '{"damage": "4d8 necrotic", "area": "10m radius", "cost": "15 HP"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('db16e960-00c7-46db-a91f-8613fe0f7028', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_scarlet_frenzy', 'Kızıl Çılgınlık', 'Scarlet Frenzy', 'Bir çılgınlık haline girer, tur başına fazladan bir saldırı kazandırır ancak her tur 5 SP feda ettirir. 3 tur sürer.', 'Enters a frenzy, granting an extra attack per turn but costing 5 HP per turn. Lasts 3 turns.', 'Blood Sacrifice', 28, 280, 2, '{"bm_blood_nova"}', '{"x": 1039, "y": -599}', '{"buff": "+1 Attack/turn", "duration": "3 turns", "cost": "5 HP/turn"}', '💢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dcada060-0def-4400-995b-eff7aa47b2a3', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_sacrifice_pact', 'Kurban Anlaşması', 'Sacrifice Pact', 'Sonraki Kan Büyücüsü büyünüzün hasar zarlarını en üst düzeye çıkarmak için 25 SP feda eder.', 'Sacrifices 25 HP to maximize the damage dice of your next Blood Mage spell.', 'Blood Sacrifice', 35, 300, 2, '{"bm_scarlet_frenzy"}', '{"x": 1255, "y": -724}', '{"buff": "Maximized Damage", "duration": "Next spell", "cost": "25 HP"}', '🤝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('79af736a-dabf-4222-8c42-06b79d204ae5', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_hemorrhage_blast', 'Kanama Patlaması', 'Hemorrhage Blast', '15m''lik bir hatta 6d10 hasar veren, 20 SP bedelli devasa bir kan patlaması fırlatır.', 'Fires a massive blast of blood costing 20 HP, dealing 6d10 damage in a 15m line.', 'Blood Sacrifice', 42, 400, 3, '{"bm_sacrifice_pact"}', '{"x": 1472, "y": -849}', '{"damage": "6d10 necrotic", "area": "15m line", "cost": "20 HP"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1b1c6e14-20c6-409b-ad99-79db7e4cb759', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_blood_eruption', 'Kan Patlaması', 'Blood Eruption', 'Bir kan gayzeri yaratmak için 30 SP feda eder. 10m yarıçapında 8d8 nekrotik hasar verir.', 'Sacrifices 30 HP to create a geyser of blood. Deals 8d8 necrotic damage in a 10m radius.', 'Blood Sacrifice', 50, 450, 3, '{"bm_hemorrhage_blast"}', '{"x": 1688, "y": -974}', '{"damage": "8d8 necrotic", "area": "10m radius", "cost": "30 HP"}', '⛲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e66cdb93-25f1-4729-b523-8c0f4abba24b', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_vital_surge', 'Hayati Akım', 'Vital Surge', 'Anında fazladan bir eylem ve bonus eylem yapmak için 40 SP feda eder.', 'Sacrifices 40 HP to immediately take an additional action and bonus action.', 'Blood Sacrifice', 58, 500, 3, '{"bm_blood_eruption"}', '{"x": 1905, "y": -1099}', '{"buff": "+1 Action, +1 Bonus Action", "duration": "Instant", "cost": "40 HP"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('964ec1ca-03be-4871-ba43-c0925e28f237', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_crimson_meteor', 'Kızıl Meteor', 'Crimson Meteor', 'Kristalleşmiş kandan bir meteor indirir. 50 SP feda ederek 20m yarıçapında 12d10 ezici hasar verir.', 'Calls down a meteor of crystallized blood. Costs 50 HP, dealing 12d10 bludgeoning damage in a 20m radius.', 'Blood Sacrifice', 65, 750, 4, '{"bm_vital_surge"}', '{"x": 2121, "y": -1224}', '{"damage": "12d10 bludgeoning", "area": "20m radius", "cost": "50 HP"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9ccf66cb-df9e-47e5-9cc2-9ce30c722f06', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_blood_oath', 'Kan Yemini', 'Blood Oath', 'Kaderinizi bir hedefe bağlar. 60 SP feda eder. 3 tur boyunca hedef tüm kaynaklardan iki kat hasar alır.', 'Binds your fate to a target. Costs 60 HP. For 3 turns, the target takes double damage from all sources.', 'Blood Sacrifice', 75, 850, 4, '{"bm_crimson_meteor"}', '{"x": 2338, "y": -1349}', '{"debuff": "Double damage taken", "duration": "3 turns", "cost": "60 HP"}', '📜');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cd451a7c-2c3d-474b-8c2b-ff090e9a82b5', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_heart_rend', 'Kalp Söken', 'Heart Rend', 'Bir hedefin kalbini telekinetik olarak ezmek için 80 SP feda eder ve 15d12 nekrotik hasar verir.', 'Sacrifices 80 HP to telekinetically crush a target''s heart, dealing 15d12 necrotic damage.', 'Blood Sacrifice', 85, 1200, 5, '{"bm_blood_oath"}', '{"x": 2554, "y": -1474}', '{"damage": "15d12 necrotic", "range": "20m", "cost": "80 HP"}', '🫀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4eaa7e2a-5c45-4632-8c02-8a42052b591e', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_blood_god_wrath', 'Kan Tanrısının Gazabı', 'Wrath of the Blood God', 'Mevcut SP''nizin yarısını feda eder. 30m içindeki tüm düşmanlara feda edilen SP''nin 4 katı kadar nekrotik hasar verir.', 'Sacrifices half your current HP. Deals necrotic damage equal to 4 times the HP sacrificed to all enemies within 30m.', 'Blood Sacrifice', 95, 1500, 5, '{"bm_heart_rend"}', '{"x": 2771, "y": -1599}', '{"damage": "4x Sacrificed HP", "area": "30m radius", "cost": "50% Current HP"}', '👺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3e5e7277-d43b-4c35-bec1-78ee0c45c19e', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_vampiric_touch', 'Vampir Dokunuşu', 'Vampiric Touch', '2d6 nekrotik hasar veren bir yakın dövüş büyü saldırısı. Verilen hasar kadar SP iyileşirsiniz.', 'A melee spell attack dealing 2d6 necrotic damage. You heal HP equal to the damage dealt.', 'Life Drain', 2, 100, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "2d6 necrotic", "heal": "100% of damage", "range": "Melee"}', '🦇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3dbea7ef-e6ac-4d0d-bd2a-755abf457d64', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_leeching_swarm', 'Sömüren Sürü', 'Leeching Swarm', '10m yarıçapında kan emici yarasalar çağırır. 3d4 hasar verir ve verilen hasarın yarısı kadar sizi iyileştirir.', 'Summons blood-sucking bats in a 10m radius. Deals 3d4 damage and heals you for half the damage dealt.', 'Life Drain', 8, 130, 1, '{"bm_vampiric_touch"}', '{"x": 289, "y": 344}', '{"damage": "3d4 piercing", "heal": "50% of damage", "area": "10m radius"}', '🦟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b19cc11f-44c4-43ad-92ce-4a610fc203b0', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_siphon_life', 'Yaşam Sömürüsü', 'Siphon Life', '15m uzaktaki bir hedeften yaşam sömürerek 4d6 nekrotik hasar verir ve hasarın %100''ü kadar sizi iyileştirir.', 'Drains life from a target up to 15m away, dealing 4d6 necrotic damage and healing you for 100% of the damage.', 'Life Drain', 15, 150, 1, '{"bm_leeching_swarm"}', '{"x": 449, "y": 536}', '{"damage": "4d6 necrotic", "heal": "100% of damage", "range": "15m"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9ea8ae55-cc8c-4e67-9fe9-5461cd6ecb7f', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_blood_thirst', 'Kan Susuzluğu', 'Blood Thirst', '5 tur boyunca silah saldırılarınız fazladan 1d6 nekrotik hasar verir ve sizi bu miktar kadar iyileştirir.', 'For 5 turns, your weapon attacks deal an extra 1d6 necrotic damage and heal you for that amount.', 'Life Drain', 24, 250, 2, '{"bm_siphon_life"}', '{"x": 610, "y": 727}', '{"buff": "+1d6 necrotic & heal", "duration": "5 turns"}', '🧛');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c9a41efc-0e21-47cb-bf0a-e5ac1d26f764', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_crimson_tether', 'Kızıl Bağ', 'Crimson Tether', '20m içindeki bir düşmana bağlanır. 3 tur boyunca tur başına 3d6 hasar verir ve sizi aynı miktarda iyileştirir.', 'Links to an enemy within 20m. Deals 3d6 damage per turn for 3 turns, healing you for the same amount.', 'Life Drain', 32, 290, 2, '{"bm_blood_thirst"}', '{"x": 771, "y": 919}', '{"damage": "3d6 necrotic/turn", "heal": "100% of damage", "duration": "3 turns"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e8241824-146d-416e-9c4f-ff761877a489', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_feast_of_souls', 'Ruhların Ziyafeti', 'Feast of Souls', '10m yarıçapındaki tüm düşmanlardan 2d8 SP sömürerek toplam sömürülen miktar kadar sizi iyileştirir.', 'Drains 2d8 HP from all enemies within a 10m radius, healing you for the total amount drained.', 'Life Drain', 38, 300, 2, '{"bm_crimson_tether"}', '{"x": 932, "y": 1110}', '{"damage": "2d8 necrotic", "heal": "100% of total damage", "area": "10m radius"}', '🍽️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f884d74d-d0bc-4b28-86f5-9d23085dd3e4', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_exsanguinate', 'Kanını Çekme', 'Exsanguinate', 'Bir hedefin kanını vücudundan zorla çıkarır. 20m menzilde 6d8 nekrotik hasar verir ve sizi yarısı kadar iyileştirir.', 'Forces a target''s blood out of their body. Deals 6d8 necrotic damage at 20m range, healing you for half.', 'Life Drain', 45, 400, 3, '{"bm_feast_of_souls"}', '{"x": 1092, "y": 1302}', '{"damage": "6d8 necrotic", "heal": "50% of damage", "range": "20m"}', '💉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('599c17ad-23d6-4b7c-a0ba-c47aff772854', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_vampiric_aura', 'Vampirik Hale', 'Vampiric Aura', '3 tur boyunca 15m''lik bir hale yayar. Siz ve müttefikleriniz, düşmanlara verdiğiniz tüm hasarın %50''si kadar iyileşirsiniz.', 'Emits a 15m aura for 3 turns. You and allies heal for 50% of all damage you deal to enemies.', 'Life Drain', 52, 460, 3, '{"bm_exsanguinate"}', '{"x": 1253, "y": 1493}', '{"aura": "Heal 50% of damage dealt", "area": "15m radius", "duration": "3 turns"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('16eabc56-edd2-4971-9cc7-a7eacecaf344', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_life_funnel', 'Yaşam Hunisi', 'Life Funnel', 'Bir düşmandan 50 SP sömürür ve bunu 15m içindeki bir müttefike aktarır.', 'Drains 50 HP from an enemy and transfers it to an ally within 15m.', 'Life Drain', 59, 500, 3, '{"bm_vampiric_aura"}', '{"x": 1414, "y": 1685}', '{"damage": "50 necrotic", "heal": "50 to ally", "range": "15m"}', '🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5476d4b6-2022-4131-936a-85b1de42ad89', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_devour_vitality', 'Canlılığı Yutmak', 'Devour Vitality', '10d8 nekrotik hasar verir. Hedefin maksimum SP''si alınan hasar kadar azalır ve bu miktarı geçici SP olarak kazanırsınız.', 'Deals 10d8 necrotic damage. The target''s maximum HP is reduced by the damage taken, and you gain that amount as temporary HP.', 'Life Drain', 68, 750, 4, '{"bm_life_funnel"}', '{"x": 1574, "y": 1876}', '{"damage": "10d8 necrotic", "debuff": "Reduce Max HP", "buff": "Gain Temp HP"}', '🧟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e238d70c-fed5-4045-8b80-2207c7c51cde', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_blood_harvest', 'Kan Hasadı', 'Blood Harvest', '20m yarıçapındaki tüm canlıların yaşam gücünü biçer. 8d10 nekrotik hasar verir ve verilen toplam hasarın %25''i kadar sizi iyileştirir.', 'Reaps the life force of all creatures in a 20m radius. Deals 8d10 necrotic damage, healing you for 25% of the total damage dealt.', 'Life Drain', 78, 850, 4, '{"bm_devour_vitality"}', '{"x": 1735, "y": 2068}', '{"damage": "8d10 necrotic", "heal": "25% of total damage", "area": "20m radius"}', '🌾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4aee7158-b6f6-4bec-89c8-bbd00ed3fcc5', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_immortal_leech', 'Ölümsüz Sülük', 'Immortal Leech', '3 tur boyunca 1 SP''nin altına düşemezsiniz. Bu etki sona erdiğinde, bu süre zarfında verdiğiniz tüm hasarın %50''si kadar iyileşirsiniz.', 'You cannot drop below 1 HP for 3 turns. When this effect ends, you heal for 50% of all damage you dealt during this time.', 'Life Drain', 88, 1200, 5, '{"bm_blood_harvest"}', '{"x": 1896, "y": 2259}', '{"buff": "Cannot die", "heal": "50% of damage dealt later", "duration": "3 turns"}', '♾️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('89184dff-9a4f-4502-8eac-6d2acfd70e12', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_vampire_lord_domain', 'Vampir Lordunun Bölgesi', 'Vampire Lord''s Domain', '5 tur boyunca 30m''lik bir karanlık bölge yaratır. Düşmanlar tur başına 6d12 hasar alır. Siz hasarın %100''ü, müttefikler ise %50''si kadar iyileşir.', 'Creates a 30m zone of darkness for 5 turns. Enemies take 6d12 damage per turn. You heal 100% of damage dealt, allies heal 50%.', 'Life Drain', 95, 1500, 5, '{"bm_immortal_leech"}', '{"x": 2056, "y": 2451}', '{"damage": "6d12 necrotic/turn", "heal": "100% self, 50% allies", "area": "30m radius", "duration": "5 turns"}', '🏰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ff583393-f726-4d96-bae9-b2932c0dedbc', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_blood_blade', 'Kan Kılıcı', 'Blood Blade', '10m içindeki bir düşmana 1d8+4 kesici hasar veren, havada süzülen kandan bir bıçak oluşturur.', 'Manifests a floating blade of blood that attacks an enemy within 10m for 1d8+4 slashing damage.', 'Hemomancy', 3, 110, 1, '{}', '{"x": -128, "y": 153}', '{"damage": "1d8+4 slashing", "range": "10m"}', '🔪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fd6bbe16-fe33-42f4-8a07-7016d4c918b4', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_crimson_shield', 'Kızıl Kalkan', 'Crimson Shield', 'Kalkan oluşturmak için kanınızı sertleştirir. 10 dakika boyunca +3 ZS kazandırır. Saldıranlar 1d4 delici hasar alır.', 'Hardens your blood to form a shield. Grants +3 AC for 10 minutes. Attackers take 1d4 piercing damage.', 'Hemomancy', 9, 140, 1, '{"bm_blood_blade"}', '{"x": -289, "y": 344}', '{"buff": "+3 AC", "damage": "1d4 piercing to attackers", "duration": "10 minutes"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7d52c5d9-2ca7-470c-852e-34f2e9858cbc', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_coagulate', 'Pıhtılaşma', 'Coagulate', 'Bir hedefin yaralarını kapanmaya veya sertleşmeye zorlar. Bir müttefiki 3d6 SP iyileştirir veya bir düşmanı 1 tur kısıtlar.', 'Forces a target''s wounds to close or harden. Heals an ally for 3d6 HP or restrains an enemy for 1 turn.', 'Hemomancy', 18, 150, 1, '{"bm_crimson_shield"}', '{"x": -449, "y": 536}', '{"heal": "3d6 to ally", "debuff": "Restrain enemy", "range": "15m"}', '🩹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c6972936-c333-4954-816d-604edd228be0', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_blood_puppets', 'Kan Kuklaları', 'Blood Puppets', '3 cesede kadar kanı kontrol altına alır ve onları 3 tur boyunca sizin için savaşacak kan zombileri olarak canlandırır.', 'Takes control of the blood in up to 3 corpses, animating them as blood zombies to fight for you for 3 turns.', 'Hemomancy', 25, 260, 2, '{"bm_coagulate"}', '{"x": -610, "y": 727}', '{"summon": "3 Blood Zombies", "duration": "3 turns"}', '🪆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9a88bbb0-d53b-417f-928c-4fea2988e557', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_hemotoxin', 'Hemotoksin', 'Hemotoxin', '15m içindeki bir hedefin kanına bulaşır. 3 tur boyunca tur başına 3d6 zehir hasarı verir ve hareketlerini 5m azaltır.', 'Infects a target''s blood within 15m. Deals 3d6 poison damage per turn for 3 turns and reduces their movement by 5m.', 'Hemomancy', 33, 290, 2, '{"bm_blood_puppets"}', '{"x": -771, "y": 919}', '{"damage": "3d6 poison/turn", "debuff": "-5m movement", "duration": "3 turns"}', '🧪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a3984876-1941-4ec5-a5b2-b79720ff6162', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_crimson_spikes', 'Kızıl Dikenler', 'Crimson Spikes', 'Pıhtılaşmış kandan dikenler 10m''lik bir alanda fışkırır. Düşmanlar 4d8 delici hasar alır ve 1 turluğuna yere sabitlenir.', 'Spikes of coagulated blood erupt in a 10m area. Enemies take 4d8 piercing damage and are rooted for 1 turn.', 'Hemomancy', 39, 300, 2, '{"bm_hemotoxin"}', '{"x": -932, "y": 1110}', '{"damage": "4d8 piercing", "debuff": "Rooted", "area": "10m radius"}', '📌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0a5fa44e-01d1-4d81-9bfd-3c6f8efec887', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_blood_whip', 'Kan Kırbacı', 'Blood Whip', '15m''lik bir kan kırbacıyla vurur. 5d6 kesici hasar verir ve hedefi size doğru 5m çeker.', 'Strikes with a 15m blood whip. Deals 5d6 slashing damage and pulls the target 5m towards you.', 'Hemomancy', 46, 410, 3, '{"bm_crimson_spikes"}', '{"x": -1092, "y": 1302}', '{"damage": "5d6 slashing", "utility": "Pull 5m", "range": "15m"}', '🪢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('35a79b10-92b6-45d1-97fb-893ca2ea515a', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_blood_prison', 'Kan Hapishanesi', 'Blood Prison', 'Bir hedefi kan küresine hapseder. Hedef kısıtlanır ve 3 tur boyunca tur başına 4d6 asit hasarı alır.', 'Traps a target in a sphere of blood. The target is restrained and takes 4d6 acid damage per turn for 3 turns.', 'Hemomancy', 54, 480, 3, '{"bm_blood_whip"}', '{"x": -1253, "y": 1493}', '{"damage": "4d6 acid/turn", "debuff": "Restrained", "duration": "3 turns"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8fa29460-5636-4083-a5fb-db9da51e54de', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_crimson_mist', 'Kızıl Sis', 'Crimson Mist', '3 tur boyunca kandan bir sise dönüşürsünüz. Büyülü olmayan hasarlara karşı bağışık olursunuz ve 5m''lik boşluklardan serbestçe geçebilirsiniz.', 'Transform into a mist of blood for 3 turns. You are immune to non-magical damage and can move through 5m spaces freely.', 'Hemomancy', 60, 500, 3, '{"bm_blood_prison"}', '{"x": -1414, "y": 1685}', '{"buff": "Immune to non-magical", "utility": "Pass through spaces", "duration": "3 turns"}', '🌫️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c4945ee4-31dc-46bc-b869-a0f325699139', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_marionette_control', 'Kukla Kontrolü', 'Marionette Control', '20m içindeki canlı bir yaratığın kanını kontrol eder. Hedef BİL kurtarması yapar veya 2 tur boyunca tamamen sizin tarafınızdan kontrol edilir.', 'Controls the blood of a living creature within 20m. Target makes a WIS save or is completely controlled by you for 2 turns.', 'Hemomancy', 70, 750, 4, '{"bm_crimson_mist"}', '{"x": -1574, "y": 1876}', '{"debuff": "Mind Control", "duration": "2 turns", "range": "20m"}', '🎭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('99e7daef-700b-4574-a8ca-c6769b336017', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_blood_storm', 'Kan Fırtınası', 'Blood Storm', '20m yarıçapında kan bıçaklarından oluşan bir girdap yaratır. 3 tur boyunca tur başına 10d6 kesici hasar verir.', 'Creates a vortex of blood blades in a 20m radius. Deals 10d6 slashing damage per turn for 3 turns.', 'Hemomancy', 80, 900, 4, '{"bm_marionette_control"}', '{"x": -1735, "y": 2068}', '{"damage": "10d6 slashing/turn", "area": "20m radius", "duration": "3 turns"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a1b929ab-566a-4efc-bea0-09c8edeb5a02', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_iron_maiden_blood', 'Kanlı Demir Bakire', 'Blood Iron Maiden', 'Bir hedefi sertleşmiş kandan yapılmış bir demir bakirenin içine hapseder. 12d10 delici hasar verir ve her tur 2d10 kanama hasarı verir.', 'Encases a target in an iron maiden made of hardened blood. Deals 12d10 piercing damage and bleeds them for 2d10 per turn.', 'Hemomancy', 86, 1200, 5, '{"bm_blood_storm"}', '{"x": -1896, "y": 2259}', '{"damage": "12d10 piercing", "damage_over_time": "2d10 bleed/turn", "range": "15m"}', '⚰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('032da0f1-8269-41ad-b900-a17cfffbba01', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_avatar_of_blood', 'Kan Avatarı', 'Avatar of Blood', '150 geçici SP kazanın. 5 tur boyunca boyutunuz iki katına çıkar ve saldırılarınız fazladan 6d12 nekrotik hasar verir.', 'Gain 150 temporary HP. For 5 turns, your size doubles, and your attacks deal an additional 6d12 necrotic damage.', 'Hemomancy', 95, 1500, 5, '{"bm_iron_maiden_blood"}', '{"x": -2056, "y": 2451}', '{"buff": "+150 Temp HP, Double Size", "damage": "+6d12 necrotic to attacks", "duration": "5 turns"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('52ea72f2-6317-4bac-9a40-cc3eb21463ca', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_blood_pact_weapon', 'Kan Anlaşması Silahı', 'Blood Pact Weapon', 'Kandan bir silah yaratmak için 15 SP feda eder. 4d8 kesici hasar verir ve 1 dakika boyunca zırhı yok sayar.', 'Sacrifices 15 HP to create a weapon of blood. It deals 4d8 slashing damage and ignores armor for 1 minute.', 'Cross-Branch', 30, 280, 2, '{"bm_boiling_blood", "bm_coagulate"}', '{"x": -173, "y": -100}', '{"summon": "4d8 Slashing Weapon", "buff": "Ignores Armor", "cost": "15 HP", "duration": "1 minute"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('edd0c365-31a0-4f73-ab89-ab5ff9b953b3', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_siphoning_spikes', 'Sömüren Dikenler', 'Siphoning Spikes', '15m''lik bir hatta kan dikenleri fırlatır. 5d6 delici hasar verir ve verilen hasarın yarısı kadar sizi iyileştirir.', 'Shoots blood spikes in a 15m line. Deals 5d6 piercing damage and heals you for half the damage dealt.', 'Cross-Branch', 35, 300, 2, '{"bm_siphon_life", "bm_coagulate"}', '{"x": -389, "y": -225}', '{"damage": "5d6 piercing", "heal": "50% of damage", "area": "15m line"}', '📍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f55d3c73-323b-436f-b764-c1f663b72300', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_vampiric_eruption', 'Vampirik Patlama', 'Vampiric Eruption', '25 SP bedeli vardır. 15m yarıçapındaki düşmanlardan kan fışkırmasına neden olur, 6d8 nekrotik hasar verir ve %50 iyileştirir.', 'Costs 25 HP. Causes blood to erupt from enemies in a 15m radius, dealing 6d8 necrotic damage and healing you for 50%.', 'Cross-Branch', 48, 420, 3, '{"bm_sacrifice_pact", "bm_feast_of_souls"}', '{"x": -606, "y": -350}', '{"damage": "6d8 necrotic", "heal": "50% of damage", "area": "15m radius", "cost": "25 HP"}', '🎇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e654df68-cddf-4d18-b37e-f0536ca7c475', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_bloody_vengeance', 'Kanlı İntikam', 'Bloody Vengeance', 'Tepki: Vurulduğunda, dökülen kanınızı anında bir mızrağa dönüştürmek için 20 SP feda eder ve saldırgana 8d6 delici hasar verirsiniz.', 'Reaction: When hit, sacrifice 20 HP to instantly shape your spilled blood into a spear, dealing 8d6 piercing damage to the attacker.', 'Cross-Branch', 55, 480, 3, '{"bm_sacrifice_pact", "bm_crimson_spikes"}', '{"x": -822, "y": -475}', '{"damage": "8d6 piercing", "cost": "20 HP", "type": "Reaction"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('23cecc7e-e5dd-490a-9363-6898ed6e7b88', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_leeching_shield', 'Sömüren Kalkan', 'Leeching Shield', '+4 ZS kazandıran süzülen bir kan kalkanı yaratır. Bir saldırıyı her engellediğinde, saldırgandan 3d6 SP sömürerek sizi iyileştirir.', 'Creates a floating blood shield granting +4 AC. Whenever it blocks an attack, it drains 3d6 HP from the attacker to heal you.', 'Cross-Branch', 58, 500, 3, '{"bm_feast_of_souls", "bm_crimson_spikes"}', '{"x": -1039, "y": -600}', '{"buff": "+4 AC", "heal": "3d6 per block", "duration": "10 minutes"}', '🔰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('996a4f35-b6c1-4a0a-bbca-671cfdfe8c77', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_crimson_execution', 'Kızıl İnfaz', 'Crimson Execution', '40 SP bedeli vardır. 10d10 kesici hasar veren devasa bir kan giyotini düşürür. Hedefi öldürürse, tam SP''ye iyileşirsiniz.', 'Costs 40 HP. Drops a massive blood guillotine dealing 10d10 slashing damage. If it kills the target, you heal to full HP.', 'Cross-Branch', 65, 750, 4, '{"bm_vital_surge", "bm_life_funnel"}', '{"x": -1255, "y": -725}', '{"damage": "10d10 slashing", "heal": "100% Max HP if target dies", "cost": "40 HP"}', '🪓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('26599cb5-4f09-4a6c-aef9-a2af013cd197', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_blood_golem', 'Kan Golemi', 'Blood Golem', '3 tur boyunca 200 SP''li bir Kan Golemi çağırır. Saldırıları 4d10 hasar verir ve yaşam gücünü size aktarır.', 'Summons a 200 HP Golem of blood for 3 turns. Its attacks deal 4d10 damage and transfer the life force to you.', 'Cross-Branch', 72, 800, 4, '{"bm_life_funnel", "bm_crimson_mist"}', '{"x": -1472, "y": -850}', '{"summon": "200 HP Golem", "damage": "4d10 per hit", "heal": "100% of golem''s damage", "duration": "3 turns"}', '🗿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5055dc11-ed00-401b-9473-2876dac57bf7', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_vein_shatter', 'Damar Parçalayan', 'Vein Shatter', 'Bir düşmanın damarlarını kristalleştirip parçalamak için 35 SP feda eder. 10d8 nekrotik hasar verir ve 1 tur sersemletir.', 'Sacrifices 35 HP to crystallize and shatter an enemy''s veins. Deals 10d8 necrotic damage and stuns them for 1 turn.', 'Cross-Branch', 78, 880, 4, '{"bm_vital_surge", "bm_crimson_mist"}', '{"x": -1688, "y": -975}', '{"damage": "10d8 necrotic", "debuff": "Stunned", "duration": "1 turn", "cost": "35 HP"}', '💔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('520034ab-0bf6-493e-969d-fe4962e7aea4', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_red_tide', 'Kızıl Gelgit', 'Red Tide', '50 SP bedeli vardır. 12d8 hasar veren, düşmanları 15m geriye iten ve sizi %50 iyileştiren 30m''lik bir kan dalgası serbest bırakır.', 'Costs 50 HP. Unleashes a 30m wave of blood dealing 12d8 damage, pushing enemies 15m back, and healing you for 50%.', 'Cross-Branch', 82, 1100, 5, '{"bm_blood_oath", "bm_blood_harvest", "bm_blood_storm"}', '{"x": -1905, "y": -1100}', '{"damage": "12d8 bludgeoning", "utility": "Push 15m", "heal": "50% of damage", "cost": "50 HP"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9296f430-f664-4d3d-a419-29191c84f2e1', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_vampiric_armada', 'Vampirik Donanma', 'Vampiric Armada', '10 uçan kan kılıcı çağırır. Her kılıç rastgele bir hedefe 2d8 hasar vermek için saldırır ve sizi 1d8 iyileştirir.', 'Summons 10 flying swords of blood. Each sword attacks a random target for 2d8 damage and heals you for 1d8.', 'Cross-Branch', 88, 1250, 5, '{"bm_blood_harvest", "bm_blood_storm"}', '{"x": -2121, "y": -1225}', '{"summon": "10 Flying Swords", "damage": "20d8 total", "heal": "10d8 total"}', '🦇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4db537d4-f153-4e25-b305-20ea1a3489da', 'f4de9c34-33e5-43ff-807d-80ddba9561f6', 'bm_omni_blood_eclipse', 'Mutlak Kan Tutulması', 'Omni Blood Eclipse', 'Mevcut SP''nizin %90''ını tüketir. 50m içindeki tüm düşmanlara harcanan SP''nin 10 katı kadar nekrotik hasar verir. Öldürülen düşmanlar kalıcı kan köleleri haline gelir.', 'Costs 90% of your current HP. Deals necrotic damage equal to 10 times the HP spent to all enemies within 50m. Enemies killed become permanent blood thralls.', 'Cross-Branch', 100, 1500, 5, '{"bm_blood_god_wrath", "bm_vampire_lord_domain", "bm_avatar_of_blood"}', '{"x": -2338, "y": -1350}', '{"damage": "10x HP spent", "area": "50m radius", "utility": "Raise killed as Thralls", "cost": "90% Current HP"}', '🌑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('957486af-d6bb-4eb4-8afa-22edf69fb4eb', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_tactics_mark', 'Hedef İşaretleme', 'Mark Target', '30m uzaklığa kadar bir düşmanı işaretlersiniz. Müttefikler işaretli hedefe karşı 3 tur boyunca fazladan 1d4 hasar vurur.', 'Mark an enemy up to 30m away. Allies gain +1d4 damage against the marked target for 3 turns.', 'Tactics', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d4 bonus", "range": "30m", "duration": "3 turns"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c83857a5-94c6-41b9-b223-7ce401751274', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_tactics_reposition', 'Taktiksel Geri Çekilme', 'Tactical Retreat', 'En fazla 3 müttefike fırsat saldırısı yemeden anında 10m hareket etme emri verirsiniz.', 'Command up to 3 allies to immediately move up to 10m without provoking attacks of opportunity.', 'Tactics', 5, 75, 1, '{}', '{"x": 389, "y": -224}', '{"range": "10m movement"}', '🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e472b4e0-853b-4c1b-8e00-62e00be1b822', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_tactics_strike', 'Koordineli Saldırı', 'Coordinated Strike', 'Siz ve 15m içindeki bir müttefikiniz aynı hedefe anında saldırı yapar, her biriniz fazladan 1d8 hasar verirsiniz.', 'You and one ally within 15m make an immediate attack against a single target, dealing an extra 1d8 damage each.', 'Tactics', 10, 100, 1, '{"cm_tactics_mark"}', '{"x": 606, "y": -349}', '{"damage": "1d8 bonus", "range": "15m"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c01aee1b-6e3f-41e6-8cb0-a8fee62c3cc0', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_tactics_flank', 'Kanat Manevrası', 'Flanking Maneuver', '20m içindeki müttefikler, bir düşmanın zıt taraflarında konumlandıklarında yakın dövüş saldırılarında avantaj kazanır.', 'Allies within 20m gain advantage on melee attacks when positioned on opposite sides of an enemy.', 'Tactics', 21, 175, 2, '{"cm_tactics_reposition"}', '{"x": 822, "y": -474}', '{"range": "20m"}', '🤺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a1e8caee-fda3-46fd-aabb-f5327a080f20', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_tactics_weakness', 'Zayıflığı Açığa Çıkarma', 'Expose Weakness', '15m yarıçapındaki zayıflıkları ortaya çıkarır. Düşmanların zırh sınıfını 2, dirençlerini %10 düşürür. 3 tur sürer.', 'Reveal vulnerabilities in a 15m radius. Reduces enemy armor class by 2 and resistance by 10% for 3 turns.', 'Tactics', 25, 200, 2, '{"cm_tactics_strike"}', '{"x": 1039, "y": -599}', '{"range": "15m radius", "duration": "3 turns"}', '🔍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2aa5e918-826d-4905-92d0-4a3ba62dabd8', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_tactics_ambush', 'Pusu Hazırlığı', 'Prepare Ambush', '20m alandaki müttefikler 1 tur görünmez olur. Sonraki saldırıları fazladan 3d6 hasar verir ve 1 tur sersemletir.', 'Allies in a 20m area become invisible for 1 turn. Their next attack deals an extra 3d6 damage and stuns for 1 turn.', 'Tactics', 35, 250, 2, '{}', '{"x": 1255, "y": -724}', '{"damage": "3d6 bonus", "range": "20m radius", "duration": "1 turn"}', '🌿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bb9c281d-b45b-45fd-8960-e28f629831a6', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_tactics_focus', 'Odaklanmış Ateş', 'Focus Fire', 'Ana bir hedef belirlersiniz. 40m içindeki bu hedefe yapılan tüm müttefik saldırıları zırhın %30''unu yok sayar ve 2 tur boyunca 2d8 ilave hasar verir.', 'Designate a primary target. All allied attacks against this target within 40m ignore 30% of their armor and deal 2d8 bonus damage for 2 turns.', 'Tactics', 41, 350, 3, '{"cm_tactics_weakness"}', '{"x": 1472, "y": -849}', '{"damage": "2d8 bonus", "range": "40m", "duration": "2 turns"}', '👁️‍🗨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3f68e2e4-75ff-4f29-acdd-fd21f6d07aa0', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_tactics_interrupt', 'Bozucu Emir', 'Disruptive Command', '20m yarıçaptaki düşman büyülerini ve odaklanmalarını kesen bir emir bağırırsınız. 2d10 psişik hasar verir.', 'Shout a command that interrupts enemy spellcasting and channelings within a 20m radius. Deals 2d10 psychic damage.', 'Tactics', 50, 400, 3, '{}', '{"x": 1688, "y": -974}', '{"damage": "2d10 psychic", "range": "20m radius"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ae2cd7b4-2bce-4bac-a30a-72a138f9da1c', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_tactics_vantage', 'Hakim Nokta', 'Vantage Point', 'Bir alan sahiplenirsiniz. 10m yarıçapta duran müttefikler 4 tur boyunca tüm menzilli saldırılarda +20m menzil ve isabet için +2 kazanır.', 'Claim an area. Allies standing in a 10m radius gain +20m range to all ranged attacks and +2 to hit for 4 turns.', 'Tactics', 55, 450, 3, '{"cm_tactics_ambush"}', '{"x": 1905, "y": -1099}', '{"range": "10m radius", "duration": "4 turns"}', '⛰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('aa18d4f7-9465-4bfb-bdb1-7ce85649ab1d', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_tactics_overwhelm', 'Ezici Güç', 'Overwhelming Force', '30m içindeki müttefikler bu tur ekstra bir eylem hakkı kazanır. Tüm saldırılar fazladan 4d6 hasar verir.', 'Allies within 30m gain an extra action this turn. All attacks deal an additional 4d6 damage.', 'Tactics', 61, 600, 4, '{"cm_tactics_focus"}', '{"x": 2121, "y": -1224}', '{"damage": "4d6 bonus", "range": "30m"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('388cc4a3-4555-43be-a3e3-f9d6d98ef2e2', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_tactics_blitz', 'Yıldırım Harekatı', 'Blitzkrieg', 'Takımınıza muazzam bir hız patlaması verirsiniz. Hareket hızı 20m artar ve bu tur yapılan ilk saldırı otomatik olarak kritik hasar verir.', 'Give your team a massive burst of speed. Movement speed increases by 20m and the first attack this turn is an automatic critical hit.', 'Tactics', 70, 700, 4, '{}', '{"x": 2338, "y": -1349}', '{"range": "20m movement bonus", "duration": "1 turn"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('285670ab-6ec9-4143-9d84-7119ad2efb5c', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_tactics_counter', 'Karşı Taarruz', 'Counter-Offensive', '2 tur boyunca, 25m içindeki bir müttefik saldırıya uğradığında, anında ücretsiz tepki olarak 3d10 hasar veren bir karşı saldırı yapabilir.', 'For 2 turns, whenever an ally within 25m is attacked, they can immediately make a counter-attack as a free reaction dealing 3d10 damage.', 'Tactics', 75, 800, 4, '{"cm_tactics_interrupt"}', '{"x": 2554, "y": -1474}', '{"damage": "3d10 counter", "range": "25m", "duration": "2 turns"}', '↩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b2994046-60a2-4de6-b60f-5814df23fbe0', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_tactics_mastermind', 'Taktik Dehası', 'Tactical Mastermind', 'Tüm savaş alanını analiz edersiniz. 3 tur boyunca düşman hareketlerini kusursuz tahmin ederek müttefiklere kaçınma ve kesin isabet sağlarsınız.', 'Analyze the entire battlefield. You perfectly predict enemy movements for 3 turns, giving all allies evasion and guaranteed hits against them.', 'Tactics', 81, 1000, 5, '{"cm_tactics_overwhelm"}', '{"x": 2771, "y": -1599}', '{"duration": "3 turns"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('86f3d57d-cb57-49f9-b7a8-dbf6d66b6261', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_tactics_checkmate', 'Şah Mat', 'Checkmate', 'Bir düşmanı taktiksel ağa hapsedersiniz. 30m içindeki tek bir hedef 2 tur boyunca hareket edemez, kaçınamaz, yetenek kullanamaz ve %50 daha fazla hasar alır.', 'Trap an enemy in a tactical web. A single target within 30m cannot move, dodge, or use abilities for 2 turns, and takes 50% more damage.', 'Tactics', 85, 1200, 5, '{"cm_tactics_blitz"}', '{"x": 2987, "y": -1724}', '{"range": "30m", "duration": "2 turns"}', '♟️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3b6f2ed2-1faf-406f-8a1b-349a9d189b8c', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_tactics_ultimate', 'Mutlak Zafer', 'Absolute Victory', 'TAKTİK ULTİSİ. Tüm müttefikler 1 tur boyunca sınırsız hareket kazanır, saldırıları tüm direnç ve bağışıklıkları aşar ve 10d10 ekstra gerçek hasar verir.', 'TACTICS ULTIMATE. All allies gain infinite movement for 1 turn, their attacks bypass all resistances and immunities, dealing 10d10 bonus true damage.', 'Tactics', 90, 1500, 5, '{"cm_tactics_mastermind", "cm_tactics_checkmate"}', '{"x": 3204, "y": -1849}', '{"damage": "10d10 true bonus", "duration": "1 turn"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3892bf7c-0f92-40ad-b6b1-3900dfbf4727', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_morale_rally', 'Toplanma Çağrısı', 'Rallying Cry', 'Bağırarak 15m içindeki tüm müttefiklerin 1d8+4 HP iyileşmesini sağlar ve korku etkilerini silersiniz.', 'Shout to restore 1d8+4 HP to all allies within 15m and cure fear effects.', 'Morale', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"healing": "1d8+4", "range": "15m radius"}', '🎺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1a5c90ca-3e7b-41b8-8b2e-41c3a12e009b', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_morale_courage', 'Cesaretlendirme', 'Bolster Courage', '20m içindeki bir müttefike 2d6 geçici HP ve 3 tur boyunca zihin değiştiren etkilere karşı bağışıklık kazandırırsınız.', 'Grant a single ally within 20m 2d6 temporary HP and immunity to mind-altering effects for 3 turns.', 'Morale', 5, 75, 1, '{}', '{"x": 289, "y": 344}', '{"healing": "2d6 temp HP", "range": "20m", "duration": "3 turns"}', '🦁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1196646c-a51c-4731-a6e4-2b80846d0f57', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_morale_charge', 'Hücum Emri', 'Charge Command', 'Müttefiklerinize hücum ilhamı verirsiniz. 20m içindeki müttefikler 2 tur boyunca +5m hareket hızı kazanır ve yakın dövüşte ekstra 1d6 hasar verir.', 'Inspire your allies to charge. Allies within 20m gain +5m movement speed and deal 1d6 extra damage on melee attacks for 2 turns.', 'Morale', 15, 125, 1, '{"cm_morale_rally"}', '{"x": 449, "y": 536}', '{"damage": "1d6 bonus", "range": "20m radius", "duration": "2 turns"}', '🏇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('04460a7e-6445-46e5-a669-99742342b777', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_morale_determination', 'Demir İrade', 'Iron Determination', '15m içindeki müttefiklerin Can Puanı sonraki tur boyunca 1''in altına düşemez.', 'Allies within 15m cannot have their HP reduced below 1 for the next turn.', 'Morale', 21, 175, 2, '{"cm_morale_courage"}', '{"x": 610, "y": 727}', '{"range": "15m radius", "duration": "1 turn"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2b80b671-37b0-41fc-9be3-16f02b771e86', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_morale_inspiration', 'İlham Verici Varlık', 'Inspiring Presence', 'Pasif aura. 10m yarıçaptaki müttefikler tüm kurtarma zarlarına +2 kazanır ve tur başına 2 HP yeniler.', 'Passive aura. Allies within a 10m radius gain +2 to all saving throws and regenerate 2 HP per turn.', 'Morale', 30, 225, 2, '{}', '{"x": 771, "y": 919}', '{"healing": "2 HP/turn", "range": "10m radius passive"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('baa78669-90d9-46a7-b37a-0cba8f01a1d1', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_morale_defiance', 'Meydan Okuyan Duruş', 'Defiant Stand', '20m içindeki bir müttefikin Can Puanı %30''un altına düştüğünde, anında 3d8 HP iyileşir ve 2 tur boyunca %20 hasar azaltma kazanır.', 'When an ally within 20m falls below 30% HP, they instantly heal for 3d8 HP and gain 20% damage reduction for 2 turns.', 'Morale', 35, 275, 2, '{"cm_morale_determination"}', '{"x": 932, "y": 1110}', '{"healing": "3d8", "range": "20m radius", "duration": "2 turns"}', '✊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ba2dc770-7c37-4689-93ca-9667bc761089', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_morale_frenzy', 'Savaş Çılgınlığı', 'Battle Frenzy', '15m içindeki müttefikler eylem başına iki kez saldırır ancak 3 tur boyunca her saldırdıklarında kendileri de 1d4 hasar alır.', 'Allies within 15m attack twice per action but take 1d4 damage themselves each time they attack for 3 turns.', 'Morale', 41, 350, 3, '{"cm_morale_charge"}', '{"x": 1092, "y": 1302}', '{"damage": "1d4 self damage", "range": "15m radius", "duration": "3 turns"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ac3ddebf-0d02-4a40-a701-df574e51c5fe', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_morale_surge', 'Adrenalin Patlaması', 'Adrenaline Surge', 'Hedef müttefik tüm zayıflatmalardan anında kurtulur ve eksik can ile dayanıklılığının %50''sini geri kazanır.', 'Target ally instantly recovers from all debuffs and restores 50% of their missing health and stamina.', 'Morale', 45, 400, 3, '{"cm_morale_inspiration"}', '{"x": 1253, "y": 1493}', '{"healing": "50% missing HP/Stamina"}', '💉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('61f72969-147d-4ca6-9115-751b8661f59f', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_morale_hope', 'Umut Işığı', 'Beacon of Hope', '20m parlayan bir aura yayarsınız. Bu alandaki müttefiklerin aldığı tüm iyileştirmeler ikiye katlanır ve 3 tur boyunca her tur 4d6 geçici HP kazanırlar.', 'Emit a glowing aura of 20m. All healing received by allies in this area is doubled, and they gain 4d6 temporary HP each turn for 3 turns.', 'Morale', 55, 450, 3, '{}', '{"x": 1414, "y": 1685}', '{"healing": "4d6 temp HP/turn", "range": "20m radius", "duration": "3 turns"}', '🕊️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f0ccdb80-0bf8-4e9f-bdc3-322a3046aa85', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_morale_unstoppable', 'Durdurulamaz Yürüyüş', 'Unstoppable March', '30m içindeki müttefikler 4 tur boyunca tüm kitle kontrol etkilerine ve hareket kısıtlamalarına karşı bağışıklık kazanır.', 'Allies within 30m become immune to all crowd control effects and movement impairments for 4 turns.', 'Morale', 61, 600, 4, '{"cm_morale_frenzy"}', '{"x": 1574, "y": 1876}', '{"range": "30m radius", "duration": "4 turns"}', '🚂');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('175de165-feb0-4707-9164-5b45efabeea9', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_morale_glory', 'Zafer Parıltısı', 'Blaze of Glory', 'Önümüzdeki 3 tur içinde bir müttefik ölecek olursa, bunun yerine 1 Can Puanında hayatta kalır, 1 tur hasar almaz olur ve iki kat hasar verir.', 'If an ally would die within the next 3 turns, they instead stay alive at 1 HP, becoming invulnerable for 1 turn and dealing double damage.', 'Morale', 65, 650, 4, '{"cm_morale_defiance"}', '{"x": 1735, "y": 2068}', '{"duration": "3 turns"}', '🌅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f33a0ffe-979c-4878-8c00-cccb0f2fec09', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_morale_resilience', 'Kırılmaz Direnç', 'Unbreakable Resilience', '25m içindeki tüm müttefiklere kırılana kadar süren 100 geçici Can Puanlık devasa bir kalkan sağlarsınız.', 'Grant a massive shield of 100 temporary HP to all allies within 25m, lasting until broken.', 'Morale', 75, 800, 4, '{}', '{"x": 1896, "y": 2259}', '{"healing": "100 temp HP", "range": "25m radius"}', '💎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e23b139d-b8a6-4945-9369-f197743f8338', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_morale_immortal', 'Ölümsüz İrade', 'Immortal Will', '15m içindeki düşmüş bir müttefiki %100 Can Puanı ile canlandırır ve onlara yakındaki düşmanlara her tur 5d10 hasar veren ateşten bir aura sağlarsınız.', 'Revive one fallen ally within 15m with 100% HP and grant them a fiery aura that burns nearby enemies for 5d10 damage per turn.', 'Morale', 81, 1000, 5, '{"cm_morale_glory"}', '{"x": 2056, "y": 2451}', '{"damage": "5d10 aura/turn", "healing": "100% Revive", "range": "15m"}', '🦅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('61cc715c-39dc-4c79-b0f3-53e46e56fd1c', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_morale_legend', 'Yaşayan Efsane', 'Living Legend', 'Sırf varlığınız mükemmelliğe ilham verir. 40m içindeki müttefikler çatışma sonuna dek tüm istatistiklerde +5 kazanır ve tur başına %10 azami HP yeniler.', 'Your mere presence inspires greatness. Allies within 40m gain +5 to all stats and regenerate 10% max HP per turn for the rest of the encounter.', 'Morale', 85, 1200, 5, '{"cm_morale_unstoppable"}', '{"x": 2217, "y": 2642}', '{"healing": "10% max HP/turn", "range": "40m radius"}', '📜');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('013d6c78-08f8-479b-8a20-631a3b3f1349', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_morale_ultimate', 'Lejyonun Kalbi', 'Heart of the Legion', 'MORAL ULTİSİ. 50m içindeki tüm müttefikler tamamen iyileşir, ölüler dirilir ve 5 tur boyunca etraflarındaki tüm düşmanlara 8d8 kutsal hasar veren devasa bir aura kazanırlar.', 'MORALE ULTIMATE. All allies within 50m are fully healed, revived if dead, and gain a massive aura dealing 8d8 holy damage to all enemies around them for 5 turns.', 'Morale', 90, 1500, 5, '{"cm_morale_immortal", "cm_morale_legend"}', '{"x": 2378, "y": 2834}', '{"damage": "8d8 holy aura", "healing": "100% Heal + Revive", "range": "50m radius", "duration": "5 turns"}', '❤️‍🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0ddce56e-6e4d-4bb2-a7e4-d2169ba3eb41', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_form_shield', 'Kalkan Duvarı', 'Shield Wall', 'Bitişik duran müttefikler +2 Zırh Sınıfı kazanır ve gelen fiziksel hasarı 3 azaltır.', 'Allies standing adjacent to each other gain +2 Armor Class and reduce incoming physical damage by 3.', 'Formation', 1, 50, 1, '{}', '{"x": -128, "y": 153}', '{"range": "Adjacent"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('01a2e8b1-7331-4dea-83b6-de8cd06f6d4a', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_form_phalanx', 'Falanks Duruşu', 'Phalanx Stance', 'Sıkı dizilişteki (2m içinde) müttefikler yakın dövüş silahlarında menzil kazanır ve yakın dövüşçülere 1d4 hasar yansıtır.', 'Allies in a tight formation (within 2m) gain reach with melee weapons and reflect 1d4 damage back to melee attackers.', 'Formation', 10, 100, 1, '{"cm_form_shield"}', '{"x": -289, "y": 344}', '{"damage": "1d4 reflect", "range": "2m"}', '🪖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dd65aa48-9d73-4def-924b-09c4cc966fe6', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_form_guard', 'Yakın Koruma', 'Close Guard', 'Bir müttefiki kendinize bağlarsınız. 5m içindeyken hasar aldıklarında, hasarın %50''sini siz üstlenirsiniz.', 'Bind an ally to you. Whenever they take damage within 5m, you intercept 50% of it.', 'Formation', 15, 125, 1, '{}', '{"x": -449, "y": 536}', '{"range": "5m"}', '🤝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('db33ede0-79d7-4776-8bba-7252b7641acb', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_form_turtle', 'Kaplumbağa Dizilişi', 'Turtle Formation', '5m yarıçapındaki müttefikler menzilli saldırılara ve büyü mermilerine karşı %50 direnç kazanır, ancak hareket hızları 3 tur yarıya düşer.', 'Allies within a 5m radius gain 50% resistance to ranged attacks and spell projectiles, but movement speed is halved for 3 turns.', 'Formation', 21, 175, 2, '{"cm_form_phalanx"}', '{"x": -610, "y": 727}', '{"range": "5m radius", "duration": "3 turns"}', '🐢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a9ca646d-06ef-498e-9799-a1628b05a7d7', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_form_wedge', 'Kama Dizilişi', 'Wedge Formation', 'Bir üçgen oluşturursunuz. Uçtaki müttefik saldırı zarlarına +4 kazanır ve fazladan 2d6 hasar verir, arkadakiler +2 AC kazanır.', 'Form a triangle. The ally at the tip gains +4 to attack rolls and deals 2d6 extra damage, while allies behind gain +2 AC.', 'Formation', 30, 225, 2, '{}', '{"x": -771, "y": 919}', '{"damage": "2d6 extra (tip)"}', '📐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('316ceb0f-2ed3-4291-b75f-0590c394f1aa', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_form_square', 'Boşluklu Kare', 'Hollow Square', 'Müttefikler savunma karesi oluşturur. Düşmanlar onları kanatlayamaz ve 5m''lik kareye giren her düşman 3d6 delici hasar alır.', 'Allies form a defensive square. Enemies cannot flank them, and any enemy entering the 5m square takes 3d6 piercing damage.', 'Formation', 35, 275, 2, '{"cm_form_turtle"}', '{"x": -932, "y": 1110}', '{"damage": "3d6 piercing", "range": "5m area"}', '🔲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('71a9f31f-73da-4b62-9a6c-7a56d15f75bd', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_form_aegis', 'Kalkan Aurası', 'Aegis Aura', '10m''lik savunma aurası yansıtırsınız. İçerdeki tüm müttefikler tüm kaynaklardan %20 daha az hasar alır ve onlara kritik vurulamaz.', 'Project a 10m defensive aura. All allies inside take 20% less damage from all sources and cannot be critically hit.', 'Formation', 41, 350, 3, '{"cm_form_guard"}', '{"x": -1092, "y": 1302}', '{"range": "10m aura"}', '❇️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('87853dc6-90d5-4ce5-9e0c-eacf6abb13bb', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_form_skirmish', 'Avcı Hattı', 'Skirmish Line', 'Dağınık diziliş. Diğer herhangi bir müttefikten 5m''den daha uzakta olan müttefikler +10m hareket hızı ve +3 Kaçınma kazanır.', 'Spread out formation. Allies who are more than 5m away from any other ally gain +10m movement speed and +3 Evasion.', 'Formation', 50, 400, 3, '{}', '{"x": -1253, "y": 1493}', '{"range": "Spread > 5m"}', '🏹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('57c50b96-0d5f-4183-9a3c-0177edc3fa3b', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_form_fortress', 'Yürüyen Kale', 'Moving Fortress', '3 tur boyunca 10m yarıçaptaki müttefikler ortak can havuzu paylaşır. Alınan hasar tüm katılımcılar arasında eşit dağıtılır.', 'For 3 turns, allies in a 10m radius share a collective health pool. Damage taken is distributed evenly among all participants.', 'Formation', 55, 450, 3, '{"cm_form_square"}', '{"x": -1414, "y": 1685}', '{"range": "10m radius", "duration": "3 turns"}', '🏰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bab9860f-5dc8-4d8c-9233-8d341aab89ec', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_form_bastion', 'Savunma Burcu', 'Bastion of Defense', '15m''lik alanı bir burca dönüştürürsünüz. İçerdeki müttefikler zorunlu harekete bağışıklıdır ve alana giren düşmanlar %70 yavaşlar.', 'Transform a 15m area into a bastion. Allies inside are immune to forced movement, and enemies entering the area are slowed by 70%.', 'Formation', 61, 600, 4, '{"cm_form_aegis"}', '{"x": -1574, "y": 1876}', '{"range": "15m radius"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3d3f893d-75dc-4b30-9218-bfd93080f710', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_form_pincer', 'Kıskaç Hareketi', 'Pincer Movement', 'İki grubu kuşatmaya yönlendirirsiniz. Aralarında en az 10m bulunan iki müttefikin arasında kalan düşmanlar her ikisinden de 2 tur çift hasar alır.', 'Command two groups to flank. Enemies caught between two allies who are at least 10m apart take double damage from both for 2 turns.', 'Formation', 70, 700, 4, '{"cm_form_wedge"}', '{"x": -1735, "y": 2068}', '{"range": "10m apart gap", "duration": "2 turns"}', '🦀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('87309850-75dc-4597-8042-977b3e4c357e', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_form_phalanx_adv', 'Demir Falanks', 'Iron Phalanx', 'Nihai savunma hattı. 10m içindeki müttefikler aşılmaz bir duvar haline gelir, tüm yakın dövüş ve büyü saldırılarını 1 tur saldıranlara yansıtır.', 'The ultimate defensive line. Allies within 10m become an impenetrable wall, reflecting all melee attacks and spells back at the attackers for 1 turn.', 'Formation', 75, 800, 4, '{"cm_form_fortress"}', '{"x": -1896, "y": 2259}', '{"range": "10m radius", "duration": "1 turn"}', '🦾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('90bac900-5eea-4726-9db6-81b32a6f48d6', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_form_impenetrable', 'Aşılmaz Hat', 'Impenetrable Line', 'Savaş alanına 20m genişliğinde bir çizgi çekersiniz. Hiçbir düşman 3 tur boyunca fiziksel veya büyülü yollarla bu çizgiyi geçemez.', 'Draw a 20m wide line on the battlefield. No enemy can cross this line by any means (physical or magical) for 3 turns.', 'Formation', 81, 1000, 5, '{"cm_form_bastion"}', '{"x": -2056, "y": 2451}', '{"range": "20m line", "duration": "3 turns"}', '🛑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d554d4cb-5d94-4953-8589-c1f91d4275cc', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_form_vanguard', 'Öncü Kalkanı', 'Vanguard''s Shield', 'Dizilişinizin önüne devasa bir ruhani kalkan çağırırsınız (15m genişliğinde). Kırılmadan önce 5000 hasara kadar emer.', 'Summon a colossal ethereal shield in front of your formation (15m wide). It absorbs up to 5000 damage before shattering.', 'Formation', 85, 1200, 5, '{"cm_form_phalanx_adv"}', '{"x": -2217, "y": 2642}', '{"healing": "5000 absorb", "range": "15m line"}', '🪬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b8b76753-94b4-4e3b-aeea-b0907fd251ff', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_form_ultimate', 'Yıkılmaz Hisar', 'Indestructible Citadel', 'DİZİLİŞ ULTİSİ. Siz ve 30m içindeki müttefikler 2 tur tüm hasar ve negatif etkilere karşı bağışık olursunuz. Gelen hasar sizi iyileştirir.', 'FORMATION ULTIMATE. You and allies within 30m become immune to all damage and negative effects for 2 turns. Incoming damage heals you instead.', 'Formation', 90, 1500, 5, '{"cm_form_impenetrable", "cm_form_vanguard"}', '{"x": -2378, "y": 2834}', '{"range": "30m radius", "duration": "2 turns"}', '🏛️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cc03dde8-b545-4e50-bae5-cdd0d86b0657', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_cross_tactics_morale', 'Savaş Narası', 'War Cry', 'Korkunç bir kükreme salarsınız. 20m içindeki düşmanlar korkar (10m kaçar) ve savunmaları %30 düşer. Müttefikler +3d6 hasar kazanır.', 'Unleash a terrifying roar. Enemies within 20m are frightened (run away 10m) and defense is lowered by 30%. Allies gain +3d6 damage.', 'Cross-Branch', 45, 450, 3, '{"cm_tactics_mark", "cm_morale_rally"}', '{"x": -173, "y": -100}', '{"damage": "3d6 bonus", "range": "20m radius"}', '📢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('120099cf-c6a5-4dfc-b740-7b601f5f09ae', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_cross_form_tactics', 'Stratejik Darboğaz', 'Strategic Chokepoint', 'Düşmanları 5m genişliğinde bir koridora zorlayan büyülü bariyerler yaratırsınız, müttefikler bu bölgeye %50 daha fazla alan hasarı verir.', 'Create magical barriers forcing enemies into a 5m wide corridor, and allies deal 50% more AoE damage in that zone.', 'Cross-Branch', 65, 700, 4, '{"cm_form_turtle", "cm_tactics_focus"}', '{"x": -389, "y": -225}', '{"range": "5m corridor"}', '🗜️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('98ab57d3-f513-43bb-b8b8-c16d64d084e4', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_cross_morale_form', 'Kan Kardeşliği', 'Brotherhood of Blood', '20m içindeki en fazla 5 müttefiki bağlarsınız. 3 tur boyunca biri iyileşirse diğerleri %50 iyileşir. Biri hasar alırsa diğerleri +%10 saldırı kazanır.', 'Link up to 5 allies within 20m. For 3 turns, whenever one heals, all others heal for 50%. If one takes damage, others gain +10% attack.', 'Cross-Branch', 70, 750, 4, '{"cm_morale_defiance", "cm_form_aegis"}', '{"x": -606, "y": -350}', '{"range": "20m radius", "duration": "3 turns"}', '🧬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7a8da030-15b6-4dc5-8ed7-0e74dfa685e1', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_cross_warlord', 'Savaş Beyinin Fermanı', 'Warlord''s Decree', 'Yüce bir emir verirsiniz. 3 tur boyunca 40m içindeki müttefikler düşman zırhını yok sayar, öldürülemezler ve tüm zayıflatmalardan arınırlar.', 'Issue a grand command. For 3 turns, all allies within 40m ignore enemy armor, cannot be killed, and immediately cleanse all debuffs.', 'Cross-Branch', 85, 1300, 5, '{"cm_tactics_overwhelm", "cm_morale_unstoppable", "cm_form_bastion"}', '{"x": -822, "y": -475}', '{"range": "40m radius", "duration": "3 turns"}', '📯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('24d2f4ac-1fc5-4f3a-8833-655720ed28fb', '00ef86dd-8278-42b0-98d8-322772dd8bff', 'cm_cross_grand_ultimate', 'Yüksek Komutan', 'Supreme Commander', 'BÜYÜK ULTİ. 1 dakika boyunca: müttefikler tur başına iki tam el oynar, düşmanların hızı %10''a düşer ve emirleriniz tüm düşmanlara 20d20 kutsal hasar verir.', 'GRAND ULTIMATE. For 1 minute: allies take two full turns per round, enemies'' speed is reduced to 10%, and commands deal 20d20 divine damage to all enemies.', 'Cross-Branch', 100, 1500, 5, '{"cm_tactics_ultimate", "cm_morale_ultimate", "cm_form_ultimate"}', '{"x": -1039, "y": -600}', '{"damage": "20d20 divine", "duration": "1 minute"}', '🌍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('af8f5234-1c00-47e1-9268-3db84cd3c039', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_trail_rations', 'Yol Kumanyası', 'Trail Rations', 'Temel yol kumanyası hazırlayın. 1d6+2 Can yeniler ve 1 saat boyunca tüm kurtarma zarlarına +1 bonus sağlayan bir güçlendirme verir.', 'Prepare basic trail rations. Heals 1d6+2 HP and provides a 1-hour buff granting +1 to all saving throws.', 'Meal', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"healing": "1d6+2", "duration": "1 hour", "buff": "+1 saves"}', '🥖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3ec5c518-deb3-4f35-9f9d-d0e1071f59cf', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_sugar_rush', 'Şeker Patlaması', 'Sugar Rush', 'Yüksek kafeinli, şekerli bir atıştırmalık tüketin. 2 tur boyunca +3m hareket hızı ve 1 ek eylem kazanın.', 'Consume a highly caffeinated, sugary treat. Gain +3m movement speed and 1 additional action for 2 turns.', 'Meal', 5, 70, 1, '{}', '{"x": 389, "y": -224}', '{"speed": "+3m", "actions": "+1 action", "duration": "2 turns"}', '🍬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('268c86ef-750c-4170-8cb7-045b84f637e7', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_hearty_stew', 'Doyurucu Yahni', 'Hearty Stew', 'Tüketene 15 geçici Can ve 1 saat boyunca soğuk hasarına karşı direnç sağlayan doyurucu bir yahni servis edin.', 'Serve a hearty stew that grants the consumer 15 temporary HP and resistance to cold damage for 1 hour.', 'Meal', 12, 100, 1, '{"ck_trail_rations"}', '{"x": 606, "y": -349}', '{"temp_hp": 15, "resistance": "cold", "duration": "1 hour"}', '🍲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6b15e161-7ee8-4277-8344-679c71ce1013', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_spicy_bite', 'Baharatlı Lokma', 'Spicy Bite', 'Ruhunuzu ateşlemek için acı bir biber yiyin. Sonraki 3 saldırınız fazladan 1d4 ateş hasarı verir.', 'Eat a spicy pepper to ignite your spirit. Your next 3 attacks deal an additional 1d4 fire damage.', 'Meal', 22, 200, 2, '{"ck_hearty_stew"}', '{"x": 822, "y": -474}', '{"damage": "1d4 fire", "duration": "3 attacks"}', '🌶️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e208c179-49ff-45c4-b9be-921a3acc0e8d', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_protein_bar', 'Protein Barı', 'Protein Bar', 'Yoğun bir protein barı oluşturun. Tüketen kişi 1 saat boyunca Güç zarlarına +2 bonus ve +5m taşıma kapasitesi kazanır.', 'Create a dense protein bar. Consumer gains +2 to Strength checks and saving throws, and +5m carrying capacity for 1 hour.', 'Meal', 30, 250, 2, '{"ck_sugar_rush"}', '{"x": 1039, "y": -599}', '{"buff": "+2 STR checks/saves", "capacity": "+5m", "duration": "1 hour"}', '🍫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1e3ac0c3-90ba-4770-9f29-d5b986b99d6f', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_revitalizing_tea', 'Canlandırıcı Çay', 'Revitalizing Tea', '1 durumu (zehir, felç veya körlük) anında kaldıran ve 2d6 Can yenileyen bir fincan bitki çayı demleyin.', 'Brew a cup of herbal tea that instantly removes 1 condition (poison, paralysis, or blind) and restores 2d6 HP.', 'Meal', 38, 280, 2, '{"ck_spicy_bite"}', '{"x": 1255, "y": -724}', '{"healing": "2d6", "cure": "1 condition"}', '🍵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e8399b9e-b9b6-4cf9-9553-a70eb665ad15', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_heroes_feast_lite', 'Maceracı Ziyafeti', 'Adventurer''s Banquet', '6 müttefike kadar maceracı ziyafeti hazırlayın. 4d8 Can yeniler, tüm hastalıkları iyileştirir ve 2 saat boyunca saldırı zarlarına +2 bonus verir.', 'Prepare an adventurer''s banquet for up to 6 allies. Heals 4d8 HP, cures all diseases, and grants +2 to attack rolls for 2 hours.', 'Meal', 45, 400, 3, '{"ck_revitalizing_tea"}', '{"x": 1472, "y": -849}', '{"healing": "4d8", "buff": "+2 attack", "targets": 6, "duration": "2 hours"}', '🍱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1e5b2ed4-551f-4ade-9c6b-60008cbb4f25', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_iron_ration', 'Demir Kumanya', 'Iron Ration', 'İnanılmaz derecede sert bir kumanya tüketin. 3 tur boyunca kesici, delici ve ezici hasarlara karşı direnç kazanın.', 'Consume an incredibly tough ration. Gain resistance to slashing, piercing, and bludgeoning damage for 3 turns.', 'Meal', 52, 450, 3, '{"ck_protein_bar"}', '{"x": 1688, "y": -974}', '{"resistance": "physical damage", "duration": "3 turns"}', '🥩');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('67615f67-fcc5-4a26-9334-9dd9f1a65e16', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_focus_mint', 'Odak Nanesi', 'Focus Mint', 'Keskin bir nane yiyin. 1 saat boyunca Odaklanma zarlarında avantaj ve Zeka ile Bilgelik zarlarına +2 bonus kazanın.', 'Eat a sharp mint. Gain advantage on Concentration checks and +2 to Intelligence and Wisdom checks for 1 hour.', 'Meal', 58, 480, 3, '{"ck_iron_ration"}', '{"x": 1905, "y": -1099}', '{"advantage": "Concentration", "buff": "+2 INT/WIS", "duration": "1 hour"}', '🌿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0e40b5c8-9be5-40c5-9000-321859da3e8c', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_miracle_biscuit', 'Mucizevi Bisküvi', 'Miracle Biscuit', 'Maksimum Canınızın %50''sini anında yenilemek için bonus eylem olarak sihirli bir bisküviyi hızla tüketin.', 'Quickly consume a magical biscuit as a bonus action to instantly restore 50% of your maximum HP.', 'Meal', 65, 700, 4, '{"ck_heroes_feast_lite"}', '{"x": 2121, "y": -1224}', '{"healing": "50% max HP", "action_type": "Bonus Action"}', '🍘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('074a1598-d8b3-4d55-abc2-2639738d9828', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_dragons_breath_chili', 'Ejder Nefesi Biberi', 'Dragon''s Breath Chili', 'Efsanevi bir acı biber yiyin. Bonus eylem olarak 5m koni şeklinde ateş üfleyerek 4d6 ateş hasarı verebilirsiniz. 1 dakika sürer.', 'Eat a legendary chili. You can exhale fire in a 5m cone as a bonus action, dealing 4d6 fire damage. Lasts 1 minute.', 'Meal', 72, 750, 4, '{"ck_focus_mint"}', '{"x": 2338, "y": -1349}', '{"damage": "4d6 fire", "range": "5m cone", "duration": "1 minute"}', '🐉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4ddaa625-6f3c-4f39-9f1a-4f5be9c3f707', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_elixir_of_vitality', 'Hayat İksiri', 'Elixir of Vitality', 'Mükemmel dengelenmiş bir iksir için. Maksimum Canınız 20 artar ve 8 saat boyunca her tur 2 Can yenilersiniz.', 'Drink a perfectly balanced elixir. Maximum HP increases by 20 and you regenerate 2 HP per turn for 8 hours.', 'Meal', 78, 850, 4, '{"ck_miracle_biscuit"}', '{"x": 2554, "y": -1474}', '{"max_hp": "+20", "regen": "2 HP/turn", "duration": "8 hours"}', '🍷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('67cbc548-eca1-4f69-b3d2-d0adc7615cbd', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_ambrosia_slice', 'Tanrıların Lokması', 'Ambrosia Slice', 'İlahi bir ambrosia dilimi servis edin. Hedefi tamamen iyileştirir ve 1 dakika boyunca tüm olumsuz durumlara karşı bağışıklık kazandırır.', 'Serve a slice of divine ambrosia. Fully heals the target and grants immunity to all negative status effects for 1 minute.', 'Meal', 85, 1200, 5, '{"ck_elixir_of_vitality"}', '{"x": 2771, "y": -1599}', '{"healing": "100%", "immunity": "Status effects", "duration": "1 minute"}', '🍰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b876a470-03c4-43ac-9112-269850510d56', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_feast_of_champions', 'Şampiyonlar Şöleni', 'Feast of Champions', 'Nihai ziyafeti yaratın. Tüm partiyi tamamen iyileştirir, +30 maksimum Can sağlar ve 24 saat boyunca tüm kurtarma zarlarında avantaj verir.', 'Conjure the ultimate feast. Fully heals the entire party, grants +30 maximum HP, and gives advantage on all saving throws for 24 hours.', 'Meal', 95, 1500, 5, '{"ck_ambrosia_slice"}', '{"x": 2987, "y": -1724}', '{"healing": "100% party", "max_hp": "+30", "advantage": "All saves", "duration": "24 hours"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8cd66f28-29ba-4c7b-9d82-addf3a3cef7e', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_boiling_splash', 'Kaynar Sıçrama', 'Boiling Splash', '5m içindeki bir düşmana kaynar su fırlatarak 1d8 ateş hasarı verin ve 1 tur boyunca kör edin.', 'Throw boiling hot water at an enemy within 5m, dealing 1d8 fire damage and blinding them for 1 turn.', 'Soup', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "1d8 fire", "status": "Blind", "duration": "1 turn", "range": "5m"}', '💧');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4ea1f266-0b6f-4508-bc6f-142dc94c4c8a', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_sticky_broth', 'Yapışkan Et Suyu', 'Sticky Broth', '10m''ye kadar yapışkan bir et suyu fırlatın. Hedefin hareket hızı yarıya düşer ve 2 tur boyunca atılamaz (dash).', 'Toss a viscous broth up to 10m. The target''s movement speed is halved and they cannot dash for 2 turns.', 'Soup', 6, 80, 1, '{}', '{"x": 289, "y": 344}', '{"speed": "-50%", "status": "Cannot dash", "duration": "2 turns", "range": "10m"}', '🥣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d2dfa92d-e324-4306-946b-fe94bb54d113', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_aromatic_steam', 'Aromatik Buhar', 'Aromatic Steam', '3m yarıçapında rahatlatıcı bir buhar bulutu salın. İçindeki müttefikler 3 tur boyunca her tur 1d4 Can yeniler.', 'Release a 3m radius cloud of soothing steam. Allies inside regain 1d4 HP per turn for 3 turns.', 'Soup', 14, 120, 1, '{"ck_boiling_splash"}', '{"x": 449, "y": 536}', '{"healing": "1d4/turn", "radius": "3m", "duration": "3 turns"}', '♨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6254bd50-63ed-4ad8-80d3-ada4c9feb297', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_acidic_soup', 'Asitli Çorba', 'Acidic Soup', 'Aşındırıcı çorba sıçratın. 2d6 asit hasarı verir ve hedefin Zırh Sınıfını kalıcı olarak 1 düşürür (en fazla 3 kez).', 'Splash corrosive soup. Deals 2d6 acid damage and permanently reduces the target''s Armor Class by 1 (max 3 times).', 'Soup', 24, 210, 2, '{"ck_aromatic_steam"}', '{"x": 610, "y": 727}', '{"damage": "2d6 acid", "debuff": "-1 AC (max -3)"}', '🧪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('843f80c2-4788-4494-a156-7e8387a6a582', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_soup_eruption', 'Çorba Patlaması', 'Soup Eruption', 'Kaynayan bir çorba tenceresini yere vurarak patlatın. Etrafınızdaki 3m yarıçapında 3d6 ateş hasarı verir.', 'Slam a pot of boiling soup, causing it to erupt. Deals 3d6 fire damage in a 3m radius around you.', 'Soup', 32, 260, 2, '{"ck_sticky_broth"}', '{"x": 771, "y": 919}', '{"damage": "3d6 fire", "radius": "3m"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c2fdf9ce-300f-430d-a653-07e5a99bd28c', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_grease_spill', 'Yağ Döküntüsü', 'Grease Spill', '5m''lik bir alana kaygan yemek yağı dökün. Giren veya turuna başlayan yaratıklar Çeviklik zarı atmalıdır, aksi takdirde yere düşerler. 5 tur sürer.', 'Spill slippery cooking grease in a 5m area. Creatures entering or starting their turn must pass a Dexterity save or fall prone. Lasts 5 turns.', 'Soup', 39, 290, 2, '{"ck_soup_eruption"}', '{"x": 932, "y": 1110}', '{"radius": "5m", "status": "Prone on failed save", "duration": "5 turns"}', '🧈');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1c69acc8-9ddc-4847-bd8d-7e9cc325b619', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_scalding_wave', 'Haşlayan Dalga', 'Scalding Wave', 'Kepçenizden 10m koni şeklinde haşlayıcı çorba gönderin. 5d6 ateş hasarı verir ve düşmanları 3m geriye iter.', 'Send a 10m cone of scalding soup from your ladle. Deals 5d6 fire damage and pushes enemies back 3m.', 'Soup', 44, 380, 3, '{"ck_acidic_soup"}', '{"x": 1092, "y": 1302}', '{"damage": "5d6 fire", "range": "10m cone", "knockback": "3m"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('313fa1fc-4637-44b7-9a91-76acadb48a85', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_healing_vapors', 'İyileştirici Buharlar', 'Healing Vapors', '5m yarıçapında bulut yayan kaynayan bir tencere yerleştirin. Müttefikleri 3d6 Can iyileştirir ve 3 tur boyunca düşmanların görüşünü engeller.', 'Place a boiling pot that emits a 5m radius cloud. Heals allies for 3d6 HP and obscures vision for enemies for 3 turns.', 'Soup', 54, 460, 3, '{"ck_grease_spill"}', '{"x": 1253, "y": 1493}', '{"healing": "3d6", "status": "Obscure vision", "radius": "5m", "duration": "3 turns"}', '🧖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b44c67d1-68f9-407f-8e00-108f6e33b1e0', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_chowder_bomb', 'Çorba Bombası', 'Chowder Bomb', '15m''ye kadar patlayan bir istiridye çorbası fırlatın. 4d8 ezici hasar verir ve hedefleri 2 tur boyunca %50 yavaşlatır.', 'Hurl an exploding clam chowder up to 15m. Deals 4d8 bludgeoning damage and slows targets by 50% for 2 turns.', 'Soup', 59, 490, 3, '{"ck_scalding_wave"}', '{"x": 1414, "y": 1685}', '{"damage": "4d8 bludgeoning", "status": "Slow 50%", "range": "15m", "duration": "2 turns"}', '💣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a05f7db8-0a35-413c-bd4f-6143272ec601', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_toxic_brew', 'Zehirli Karışım', 'Toxic Brew', 'Bir düşmanı zehirli bir karışım yutmaya zorlayın. 6d8 zehir hasarı verir ve 1 dakika boyunca zehirler (her tur 1d6 hasar).', 'Force an enemy to swallow a toxic brew. Deals 6d8 poison damage and poisons them for 1 minute (1d6 damage per turn).', 'Soup', 66, 650, 4, '{"ck_chowder_bomb"}', '{"x": 1574, "y": 1876}', '{"damage": "6d8 poison", "dot": "1d6 poison/turn", "duration": "1 minute"}', '☠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1f6315e4-1685-4d87-a907-137609f79281', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_magma_potage', 'Magma Çorbası', 'Magma Potage', 'O kadar sıcak bir çorba dökün ki lavı taklit eder, 4m''lik bir havuz oluşturur. İçindeki yaratıklar her tur 5d10 ateş hasarı alır. 4 tur sürer.', 'Pour out a soup so hot it mimics lava, creating a 4m pool. Creatures inside take 5d10 fire damage per turn. Lasts 4 turns.', 'Soup', 74, 780, 4, '{"ck_healing_vapors"}', '{"x": 1735, "y": 2068}', '{"damage": "5d10 fire/turn", "radius": "4m", "duration": "4 turns"}', '🫕');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('305d9994-e64b-436e-b260-31f240f9b3d3', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_nourishing_rain', 'Besleyici Yağmur', 'Nourishing Rain', 'Çorbayı gökyüzüne atarak 10m yarıçapında besleyici bir yağmur yaratın. Müttefikler 5 tur boyunca turlarının başında 10 Can yeniler.', 'Shoot soup into the sky, creating a 10m radius nourishing rain. Allies regain 10 HP at the start of their turns for 5 turns.', 'Soup', 79, 880, 4, '{"ck_toxic_brew"}', '{"x": 1896, "y": 2259}', '{"healing": "10 HP/turn", "radius": "10m", "duration": "5 turns"}', '🌧️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0571f697-bd74-4238-9e26-99620f8d003c', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_tsunami_of_stew', 'Yahni Tsunamisi', 'Tsunami of Stew', '15m genişliğinde devasa bir kaynar yahni dalgası serbest bırakın. Düşmanları 10m uzağa iter, yere düşürür ve 8d8 ateş/ezici hasar verir.', 'Unleash a massive 15m wide wave of boiling stew. Pushes enemies 10m away, knocks them prone, and deals 8d8 fire/bludgeoning damage.', 'Soup', 86, 1150, 5, '{"ck_magma_potage"}', '{"x": 2056, "y": 2451}', '{"damage": "8d8 fire/bludgeoning", "width": "15m", "knockback": "10m", "status": "Prone"}', '🍜');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('eb5e8d46-1ecc-4cc0-807b-4defeaccacb9', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_cauldron_of_disaster', 'Felaket Kazanı', 'Cauldron of Disaster', 'Şiddetle patlayan devasa spektral bir kazan çağırın. 3 tur boyunca her tur 20m yarıçapında 10d10 karışık ateş ve asit hasarı verir.', 'Summon a giant spectral cauldron that violently erupts. Deals 10d10 mixed fire and acid damage in a 20m radius every turn for 3 turns.', 'Soup', 96, 1500, 5, '{"ck_tsunami_of_stew"}', '{"x": 2217, "y": 2642}', '{"damage": "10d10 fire/acid per turn", "radius": "20m", "duration": "3 turns"}', '🥘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('68999e6b-127f-46da-b2be-e78ba8acd3ff', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_chop', 'Doğrama', 'Chop', 'Satırla temel bir yakın dövüş saldırısı. 1d8 kesici hasar verir ve 2 tur boyunca her tur 2 hasar veren bir kanama etkisi uygular.', 'A basic melee strike with a cleaver. Deals 1d8 slashing damage and inflicts a bleed effect for 2 damage per turn for 2 turns.', 'Cleaver', 2, 60, 1, '{}', '{"x": -128, "y": 153}', '{"damage": "1d8 slashing", "dot": "2 bleed/turn", "duration": "2 turns"}', '🔪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8c948414-06b9-4ec5-9dfc-6bd437ccd59c', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_tenderize', 'Yumuşatma', 'Tenderize', 'Bıçağın düz kısmıyla vurun. 1d6 ezici hasar verir ve hedefin bir sonraki saldırısında dezavantajlı olmasını sağlar.', 'Strike with the flat of the blade. Deals 1d6 bludgeoning damage and gives the target disadvantage on their next attack.', 'Cleaver', 8, 90, 1, '{}', '{"x": -289, "y": 344}', '{"damage": "1d6 bludgeoning", "debuff": "Disadvantage on next attack"}', '🔨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c3b581cd-9a49-412d-98d4-d43d42648389', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_quick_slice', 'Hızlı Kesik', 'Quick Slice', 'Bonus eylem olarak hızlı ve sığ bir kesik atın. 1d4 kesici hasar verir ve bir sonraki saldırınızın isabetliliğini +2 artırır.', 'Make a rapid, shallow cut as a bonus action. Deals 1d4 slashing damage and increases your next attack''s accuracy by +2.', 'Cleaver', 15, 130, 1, '{"ck_chop"}', '{"x": -449, "y": 536}', '{"damage": "1d4 slashing", "buff": "+2 accuracy next attack", "action_type": "Bonus Action"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('33d83f3c-d931-4a5a-b8c0-2bb6cf634cb7', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_butchers_hook', 'Kasap Kancası', 'Butcher''s Hook', '8m''ye kadar bir et kancası fırlatın. 1d6 delici hasar verir ve hedefi size doğru 5m çeker.', 'Throw a meat hook up to 8m. Deals 1d6 piercing damage and pulls the target 5m towards you.', 'Cleaver', 25, 220, 2, '{"ck_tenderize"}', '{"x": -610, "y": 727}', '{"damage": "1d6 piercing", "range": "8m", "pull": "5m"}', '🪝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f4a2cf04-7a39-4f6b-ae96-d330794a3146', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_filet', 'Fileto Çıkarma', 'Filet', 'Bir düşmanı hassas bir şekilde dilimleyin. 2d8 kesici hasar verir. Canavarlara ve yaratıklara iki kat hasar verir.', 'Precisely slice an enemy. Deals 2d8 slashing damage. Deals double damage to beasts and monstrosities.', 'Cleaver', 34, 270, 2, '{"ck_quick_slice"}', '{"x": -771, "y": 919}', '{"damage": "2d8 slashing", "bonus": "Double damage to beasts/monstrosities"}', '🥩');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d899fe14-6ff4-4598-97c2-97deb497487e', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_heavy_cleave', 'Ağır Satır Darbesi', 'Heavy Cleave', 'Güçlü bir iki elle doğrama. 3d6 kesici hasar verir ve yere düşmemek için bir Güç kurtarma zarı atılmasını zorunlu kılar.', 'A powerful two-handed chop. Deals 3d6 slashing damage and forces a Strength save to avoid being knocked prone.', 'Cleaver', 40, 300, 2, '{"ck_filet"}', '{"x": -932, "y": 1110}', '{"damage": "3d6 slashing", "status": "Prone on failed save"}', '🪓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7c1fb257-cfd1-41af-bbf5-164f7e2960ef', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_whirlwind_chop', 'Kasırga Doğrayışı', 'Whirlwind Chop', 'Satırlarınızla öfkeyle dönün. 2m yarıçapındaki tüm düşmanlara 4d6 kesici hasar verir.', 'Spin furiously with your cleavers. Deals 4d6 slashing damage to all enemies within a 2m radius.', 'Cleaver', 46, 410, 3, '{"ck_heavy_cleave"}', '{"x": -1092, "y": 1302}', '{"damage": "4d6 slashing", "radius": "2m"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5b6af8e4-8def-4e03-a4b4-16312f9490b9', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_sever_tendon', 'Tendon Kesme', 'Sever Tendon', 'Hayati bir hareket kasını hedef alın. 3d8 kesici hasar verir ve hedefin hareket hızını 1 tur boyunca 0''a düşürür.', 'Target a vital mobility muscle. Deals 3d8 slashing damage and reduces the target''s movement speed to 0 for 1 turn.', 'Cleaver', 55, 470, 3, '{"ck_butchers_hook"}', '{"x": -1253, "y": 1493}', '{"damage": "3d8 slashing", "speed": "0m", "duration": "1 turn"}', '✂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d8a6b83e-f2a9-4ccd-b75d-5ea989cc3ed4', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_meat_grinder', 'Kıyma Makinesi', 'Meat Grinder', 'Her biri 1d8 kesici hasar veren 3 hızlı vuruş yapın. Hedef 3 tur boyunca her tur 1d6 kanama hasarı alır.', 'Unleash 3 rapid strikes, each dealing 1d8 slashing damage. Target bleeds for 1d6 damage per turn for 3 turns.', 'Cleaver', 60, 500, 3, '{"ck_whirlwind_chop"}', '{"x": -1414, "y": 1685}', '{"damage": "3x 1d8 slashing", "dot": "1d6 bleed/turn", "duration": "3 turns"}', '⚙️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8bb46f5c-d6e2-4bb7-9878-a9f0210c9b38', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_jugular_strike', 'Şahdamar Vuruşu', 'Jugular Strike', 'Boyna ölümcül bir vuruş. 6d8 kesici hasar verir ve sihirle iyileştirilene kadar şiddetli kanamaya (her tur 2d8 hasar) neden olur.', 'A lethal strike to the neck. Deals 6d8 slashing damage and inflicts severe bleeding (2d8 damage per turn) until magically healed.', 'Cleaver', 68, 680, 4, '{"ck_meat_grinder"}', '{"x": -1574, "y": 1876}', '{"damage": "6d8 slashing", "dot": "2d8 bleed/turn"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2eccc4ee-2aad-42c9-9fb1-272089d5cb61', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_armor_carve', 'Zırh Yontma', 'Armor Carve', 'Düşmanın savunmasını metodik olarak parçalayın. 4d8 kesici hasar verir ve Zırh Sınıfını (AC) kalıcı olarak 2 düşürür.', 'Methodically dismantle the enemy''s defenses. Deals 4d8 slashing damage and permanently reduces their AC by 2.', 'Cleaver', 75, 800, 4, '{"ck_sever_tendon"}', '{"x": -1735, "y": 2068}', '{"damage": "4d8 slashing", "debuff": "-2 AC"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f19b2b3b-a33b-452b-84bf-bd392a3e1d7f', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_flying_cleaver', 'Uçan Satır', 'Flying Cleaver', 'Satırınızı 15m''ye kadar ölümcül bir hassasiyetle fırlatın. 5d10 kesici hasar verir, yarım siperi yok sayar ve sihirli bir şekilde elinize döner.', 'Throw your cleaver with deadly precision up to 15m. Deals 5d10 slashing damage, ignores half-cover, and magically returns to your hand.', 'Cleaver', 80, 900, 4, '{"ck_jugular_strike"}', '{"x": -1896, "y": 2259}', '{"damage": "5d10 slashing", "range": "15m", "bonus": "Returns to hand"}', '🪃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6ee48201-f7b9-49eb-9adb-3927cf20523b', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_decapitate', 'Boyun Vurma', 'Decapitate', 'Hedefin kafasını koparmaya çalışın. 10d10 kesici hasar verir. Hedefin 50 veya daha az Canı kalırsa, anında ölürler.', 'Attempt to take off the target''s head. Deals 10d10 slashing damage. If the target is left with 50 HP or less, they are instantly killed.', 'Cleaver', 88, 1250, 5, '{"ck_flying_cleaver"}', '{"x": -2056, "y": 2451}', '{"damage": "10d10 slashing", "status": "Instakill if HP <= 50"}', '💀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7871c715-9fff-4b1e-93d9-16720e1c4aa4', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_master_butcher', 'Usta Kasap', 'Master Butcher', 'Eşsiz bir kasaplık durumuna girin. 1 dakika boyunca tüm yakın dövüş saldırıları +3d8 kesici hasar verir, 18-20 arası zarlarda kritik vurur ve fiziksel dirençleri yok sayar.', 'Enter a state of unparalleled butchery. For 1 minute, all melee attacks deal +3d8 slashing damage, score critical hits on 18-20, and ignore physical resistances.', 'Cleaver', 98, 1500, 5, '{"ck_decapitate"}', '{"x": -2217, "y": 2642}', '{"damage": "+3d8 slashing", "buff": "Crit 18-20, ignore resistance", "duration": "1 minute"}', '👨‍🍳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('474cfc6e-2b4f-4035-a782-82cd54f76e81', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_spicy_meatball', 'Acılı Köfte', 'Spicy Meatball', '3m yarıçapında patlayan bir köfte fırlatın. Düşmanlara 2d6 ateş hasarı verir ve müttefikleri 1d6 iyileştirir.', 'Throw a meatball that explodes in a 3m radius. Deals 2d6 fire damage to enemies and heals allies for 1d6.', 'Cross-Branch', 28, 240, 2, '{"ck_hearty_stew", "ck_boiling_splash"}', '{"x": -173, "y": -100}', '{"damage": "2d6 fire", "healing": "1d6", "radius": "3m"}', '🧆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('98a5d880-c91f-4563-ae53-b833405a0d1b', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_blood_sausage', 'Kan Sosis', 'Blood Sausage', 'Kanayan düşmanların canlılığını em. Kanama hasarı verdiğinizde, 1d8 geçici Can kazanırsınız (1 saat sürer).', 'Drain the vitality of bleeding foes. Whenever you deal bleed damage, you gain 1d8 temporary HP (lasts 1 hour).', 'Cross-Branch', 36, 280, 2, '{"ck_spicy_bite", "ck_tenderize"}', '{"x": -389, "y": -225}', '{"buff": "1d8 Temp HP on bleed proc", "duration": "1 hour"}', '🌭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2441637e-c818-4a6a-bb2d-cccc9784fac5', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_flaming_cleaver', 'Alevli Satır', 'Flaming Cleaver', 'Satırınızı kaynayan yağa bulayın ve ateşleyin. Yakın dövüş saldırılarınız fazladan 2d6 ateş hasarı verir ve hedefleri 3 tur boyunca tutuşturur.', 'Coat your cleaver in boiling grease and ignite it. Your melee attacks deal an extra 2d6 fire damage and ignite targets for 3 turns.', 'Cross-Branch', 50, 430, 3, '{"ck_soup_eruption", "ck_heavy_cleave"}', '{"x": -606, "y": -350}', '{"damage": "+2d6 fire", "status": "Ignite", "duration": "3 turns"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9a948830-c47c-4c2f-9ed9-603acaba20ed', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_vampiric_feast', 'Vampir Ziyafeti', 'Vampiric Feast', 'Yeni yenilmiş bir düşmanın bir parçasını hızla toplayıp tüketin. 4d8 Can yeniler ve 1 saat boyunca +2 Güç verir.', 'Quickly harvest and consume a piece of a freshly defeated enemy. Restores 4d8 HP and grants +2 Strength for 1 hour.', 'Cross-Branch', 56, 480, 3, '{"ck_heroes_feast_lite", "ck_sever_tendon"}', '{"x": -822, "y": -475}', '{"healing": "4d8", "buff": "+2 STR", "duration": "1 hour"}', '🦇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d842d6e0-ea27-4756-b14c-0594dd75b242', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_iron_chef_stance', 'Demir Şef Duruşu', 'Iron Chef Stance', 'Etkileyici bir aşçı duruşu benimseyin. 1 dakika boyunca +2 ZS (AC) ve ateş hasarına bağışıklık kazanın, saldırılarınız 1d8 yanık uygular.', 'Adopt an imposing cooking stance. Gain +2 AC, immunity to fire damage, and your attacks inflict a 1d8 burn for 1 minute.', 'Cross-Branch', 70, 720, 4, '{"ck_focus_mint", "ck_toxic_brew", "ck_meat_grinder"}', '{"x": -1039, "y": -600}', '{"buff": "+2 AC, Fire Immunity", "damage": "+1d8 burn on hit", "duration": "1 minute"}', '🍳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('74016d01-850f-411e-bc1c-371a89740c1c', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_soup_tornado', 'Çorba Hortumu', 'Soup Tornado', 'Kaynar çorba püskürtürken satırlarınızla dönün. 2 tur boyunca her tur 6d6 kesici ve 4d6 ateş hasarı veren 5m''lik bir hortum yaratır.', 'Spin with your cleavers while spewing boiling soup. Creates a 5m tornado dealing 6d6 slashing and 4d6 fire damage per turn for 2 turns.', 'Cross-Branch', 76, 820, 4, '{"ck_scalding_wave", "ck_whirlwind_chop"}', '{"x": -1255, "y": -725}', '{"damage": "6d6 slashing, 4d6 fire per turn", "radius": "5m", "duration": "2 turns"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d76e8a9c-b273-4f2a-9640-128103d30a8a', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_banquet_of_carnage', 'Katliam Ziyafeti', 'Banquet of Carnage', 'Savaş alanında spektral bir ziyafet çağırın. 15m içinde öldürülen her düşman bir iyileştirme küresi düşürür (3d10 iyileştirir). Menzildeki müttefikler +2d8 hasar verir.', 'Summon a spectral feast on the battlefield. Any enemy killed within 15m drops a healing orb (heals 3d10). Allies within range deal +2d8 damage.', 'Cross-Branch', 82, 1100, 5, '{"ck_miracle_biscuit", "ck_armor_carve"}', '{"x": -1472, "y": -850}', '{"buff": "+2d8 ally damage", "healing": "3d10 per orb", "radius": "15m"}', '🍖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c4396966-905f-435c-aad7-deb6ee5bc4a1', 'e6a28b81-c07b-4777-bc36-7e559f229425', 'ck_hells_kitchen', 'Cehennem Mutfağı', 'Hell''s Kitchen', '30m yarıçapındaki tüm düşmanları 1 dakika boyunca şeytani bir mutfağa hapsedin. Düşmanlar her tur 5d10 ateş ve 5d10 kesici hasar alır, %50 yavaşlarlar ve aldıkları tüm hasar sizi ve müttefiklerinizi iyileştirir.', 'Trap all enemies within a 30m radius inside a demonic kitchen for 1 minute. Enemies take 5d10 fire and 5d10 slashing damage each turn, are slowed by 50%, and all damage they take heals you and your allies.', 'Grand Ultimate', 100, 2000, 5, '{"ck_feast_of_champions", "ck_cauldron_of_disaster", "ck_master_butcher"}', '{"x": 173, "y": -99}', '{"damage": "5d10 fire, 5d10 slashing per turn", "debuff": "50% slow", "healing": "100% lifesteal aura", "radius": "30m", "duration": "1 minute"}', '👹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2dff0e0c-17ed-4ce0-a551-a6cf00c53c6c', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_aura_initiation', 'Çekirdek Aurası Başlatma', 'Core Aura Initiation', 'Temel Coreplate aurasını aktifleştirerek 10 metrelik yarıçaptaki müttefiklere +5 Defans sağlar.', 'Activates the basic Coreplate aura, providing a 10m radius where allies gain +5 Defense.', 'Defense Aura', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"radius": "10m", "defense": "+5"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('54cfb7eb-f61a-497f-b541-d905d8060f83', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_aura_expansion', 'Genişleyen Varlık', 'Expanding Presence', 'Defans aurasının yarıçapını 5 metre genişletir ve müttefiklere fazladan +2 Defans kazandırır.', 'Expands the defense aura radius by 5m and grants allies an additional +2 Defense.', 'Defense Aura', 5, 75, 1, '{"cp_aura_initiation"}', '{"x": 389, "y": -224}', '{"radius": "+5m", "defense": "+2"}', '🌐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('782721d3-df21-4885-8db8-b4dbf446bde5', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_healing_resonance', 'İyileştirici Rezonans', 'Healing Resonance', 'Defans aurası artık 15 metre içindeki tüm müttefiklere tur başına 1d4 iyileşme sağlar.', 'The defense aura now grants 1d4 healing per turn to all allies within 15m.', 'Defense Aura', 10, 100, 1, '{"cp_aura_expansion"}', '{"x": 606, "y": -349}', '{"radius": "15m", "healing": "1d4/turn"}', '💖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bd8a4376-ea7f-41b6-89cc-1248157223e5', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_elemental_ward', 'Element Kalkanı', 'Elemental Ward', 'Aura, menzil içindeki tüm müttefiklerin aldığı element hasarını %15 azaltır.', 'The aura reduces incoming elemental damage by 15% for all allies within range.', 'Defense Aura', 21, 200, 2, '{"cp_aura_expansion"}', '{"x": 822, "y": -474}', '{"elemental_reduction": "15%", "radius": "15m"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e2974108-dc40-47be-b16d-6b418167d32d', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_thorny_presence', 'Dikenli Varlık', 'Thorny Presence', '15 metrelik aura içindeki düşmanlar, bir müttefike saldırdıkları her tur 1d6 delici hasar alırlar.', 'Enemies within the 15m aura take 1d6 piercing damage each turn they attack an ally.', 'Defense Aura', 25, 220, 2, '{"cp_elemental_ward"}', '{"x": 1039, "y": -599}', '{"damage": "1d6 piercing", "radius": "15m"}', '🌵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('26a7f2d5-d066-41f5-965c-b35a25dffc91', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_aura_density', 'Aura Yoğunluğu', 'Aura Density', 'Auranın çekirdek defans bonusunu +10''a çıkarır ve havayı düşmanlar için ağırlaştırarak hızlarını 2 metre düşürür.', 'Increases the core defense bonus of the aura to +10, making the air feel heavy for enemies, reducing their speed by 2m.', 'Defense Aura', 30, 250, 2, '{"cp_elemental_ward"}', '{"x": 1255, "y": -724}', '{"defense": "+10", "enemy_speed": "-2m"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('55dc2351-70d3-4416-a681-f1382f011d35', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_suppression_field', 'Baskılama Alanı', 'Suppression Field', 'Aura, 20 metrelik bir baskılama alanı yayarak düşmanların saldırı zarlarında dezavantaj almasına neden olur.', 'The aura emits a 20m suppression field, giving enemies disadvantage on attack rolls.', 'Defense Aura', 41, 350, 3, '{"cp_aura_density"}', '{"x": 1472, "y": -849}', '{"radius": "20m", "debuff": "disadvantage"}', '🛑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('989dc68a-4d25-4d90-a773-1e0f7254673d', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_cleansing_aura', 'Arındırıcı Aura', 'Cleansing Aura', 'Aura, her 3 turda bir 20 metre içindeki tüm müttefiklerden otomatik olarak bir negatif durum etkisini kaldırır.', 'Every 3 turns, the aura automatically removes one negative status effect from all allies within 20m.', 'Defense Aura', 45, 400, 3, '{"cp_suppression_field"}', '{"x": 1688, "y": -974}', '{"radius": "20m", "cleanse": "1 effect/3 turns"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('692c01e8-0712-422d-86cf-00390802d815', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_unyielding_presence', 'Boyun Eğmez Varlık', 'Unyielding Presence', '20 metrelik aura içindeki müttefikler yere düşürülemez ve kendi istekleri dışında hareket ettirilemez.', 'Allies in the 20m aura cannot be knocked prone or moved against their will.', 'Defense Aura', 50, 450, 3, '{"cp_suppression_field"}', '{"x": 1905, "y": -1099}', '{"radius": "20m", "immunity": "prone/forced movement"}', '🗿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2ed3520e-fb94-43dc-bdc4-abb77a3c771a', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_aura_overcharge', 'Aura Aşırı Yüklemesi', 'Aura Overcharge', 'Aurayı 3 turluğuna aşırı yükler. Defans bonusu +20''ye katlanır ve müttefikler seviyenize eşit geçici HP kazanır.', 'Overcharges the aura for 3 turns. The defense bonus doubles to +20, and allies gain temporary HP equal to your level.', 'Defense Aura', 61, 600, 4, '{"cp_unyielding_presence"}', '{"x": 2121, "y": -1224}', '{"duration": "3 turns", "defense": "+20", "temp_hp": "caster_level"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f1591775-5e6a-4d71-bd19-875886d7180a', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_sanctuary_field', 'Sığınak Alanı', 'Sanctuary Field', '25 metrelik mutlak bir güvenlik bölgesi yaratır. Bölge içinde eylem yapan düşmanlar 3d8 parlak hasar alır.', 'Creates a 25m zone of absolute safety. Enemies taking actions within it suffer 3d8 radiant damage.', 'Defense Aura', 65, 700, 4, '{"cp_aura_overcharge"}', '{"x": 2338, "y": -1349}', '{"radius": "25m", "damage": "3d8 radiant"}', '⛩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3d3e779d-dc65-4c6c-bc03-63b02669d2b2', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_repelling_aura', 'İtici Aura', 'Repelling Aura', 'Düşmanlar güç kurtarışında başarısız olursa, aura her turun sonunda onları sürekli olarak 5 metre uzağa iter.', 'The aura constantly pushes enemies 5m away at the end of their turn if they fail a strength save.', 'Defense Aura', 70, 800, 4, '{"cp_aura_overcharge"}', '{"x": 2554, "y": -1474}', '{"push": "5m", "save": "strength"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('41f4b182-6025-40fd-9656-f883c8ca0805', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_aura_mastery', 'Aura Ustalığı', 'Aura Mastery', 'Defans aurası mana harcamadan pasif ve kalıcı hale gelir. Yarıçapı 30 metreye çıkar.', 'The defense aura becomes passive and permanent without costing mana. Its radius increases to 30m.', 'Defense Aura', 81, 1100, 5, '{"cp_sanctuary_field", "cp_repelling_aura"}', '{"x": 2771, "y": -1599}', '{"cost": "0 mana", "radius": "30m"}', '🌟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('092f7547-b37f-4904-ab4e-ca2a490e64ee', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_ultimate_aegis_aura', 'Nihai Kalkan Aurası', 'Ultimate Aegis Aura', 'Auranın ulu tezahürü. 5 turluğuna 40 metre içindeki tüm müttefikler büyüsel olmayan hasarlara karşı bağışıklık kazanır ve tur başına 4d10 HP iyileşir.', 'Grand manifestation of the aura. For 5 turns, all allies in 40m become immune to non-magical damage and heal 4d10 HP per turn.', 'Defense Aura', 90, 1500, 5, '{"cp_aura_mastery"}', '{"x": 2987, "y": -1724}', '{"duration": "5 turns", "radius": "40m", "healing": "4d10/turn", "immunity": "non-magical"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3c00375a-b8fe-4ed9-8104-b0023e5537a0', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_core_barrier', 'Çekirdek Bariyeri', 'Core Barrier', 'Gelen saldırıları kesen 30 HP''ye sahip kişisel, büyüsel bir bariyer çağırır.', 'Summons a personal magical barrier with 30 HP that intercepts incoming attacks.', 'Core Shield', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"shield_hp": "30"}', '💠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('02b831c3-239e-40c2-818d-54c29291e03c', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_shield_bash', 'Kalkan Darbesi', 'Shield Bash', 'Çekirdek Bariyerini kullanarak 2 metredeki bir düşmana çarpar, 1d8 ezici hasar verir ve onları 3 metre geri iter.', 'Uses the Core Barrier to slam an enemy in 2m, dealing 1d8 bludgeoning damage and pushing them back 3m.', 'Core Shield', 5, 75, 1, '{"cp_core_barrier"}', '{"x": 289, "y": 344}', '{"range": "2m", "damage": "1d8 bludgeoning", "push": "3m"}', '🔨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2eccf32b-0f69-4999-9fe0-58b1ee0f784f', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_quick_recharge', 'Hızlı Yenilenme', 'Quick Recharge', 'Bir bonus eylem olarak aktif Çekirdek Bariyerinize anında 15 HP yeniler.', 'Instantly restores 15 HP to your active Core Barrier as a bonus action.', 'Core Shield', 10, 100, 1, '{"cp_core_barrier"}', '{"x": 449, "y": 536}', '{"heal_shield": "15 HP"}', '🔋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('54462569-a6fd-4ce9-9fcf-419107428e89', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_deflection_grid', 'Saptırma Ağı', 'Deflection Grid', 'Bariyeri, füzeleri saldıranlara geri yansıtacak şekilde güçlendirir ve orijinal hasarın %50''sini verir.', 'Enhances the barrier to reflect projectiles back at attackers, dealing 50% of the original damage.', 'Core Shield', 21, 200, 2, '{"cp_quick_recharge"}', '{"x": 610, "y": 727}', '{"reflect": "50%"}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ef65b803-a8d8-4dc4-a085-485b7e1b53e9', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_reactive_plating', 'Reaktif Kaplama', 'Reactive Plating', 'Bariyer yakın dövüş saldırısı aldığında dışa doğru patlayarak 3 metre içindeki düşmanlara 2d6 güç hasarı verir.', 'When the barrier is struck by melee, it explodes outward dealing 2d6 force damage to enemies within 3m.', 'Core Shield', 25, 220, 2, '{"cp_deflection_grid"}', '{"x": 771, "y": 919}', '{"radius": "3m", "damage": "2d6 force"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2e694211-d690-48c3-9fd7-72a908c06b95', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_shield_shatter', 'Kalkan Parçalama', 'Shield Shatter', 'Mevcut Çekirdek Bariyerinizi kasıtlı olarak patlatarak, kalan HP''sine eşit güç hasarını 5 metre içindeki tüm düşmanlara verir.', 'Detonates your current Core Barrier intentionally, dealing force damage equal to its remaining HP to all enemies in 5m.', 'Core Shield', 30, 250, 2, '{"cp_reactive_plating"}', '{"x": 932, "y": 1110}', '{"radius": "5m", "damage": "remaining_shield_hp"}', '🎇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1f48c11b-e7ee-473d-aa0a-2d32305c9acd', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_kinetic_absorber', 'Kinetik Emici', 'Kinetic Absorber', 'Çekirdek Bariyeri artık saldırılardan kinetik enerji emerek bir sonraki yakın dövüş saldırınızın hasarını 1d10 artırır.', 'The Core Barrier now absorbs kinetic energy from attacks, increasing your next melee attack''s damage by 1d10.', 'Core Shield', 41, 350, 3, '{"cp_reactive_plating"}', '{"x": 1092, "y": 1302}', '{"buff": "next melee +1d10"}', '📥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('413a8a20-0b4d-488d-9d4a-7e0a38295de3', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_heavy_core', 'Ağır Çekirdek', 'Heavy Core', 'Çekirdek Bariyerinin temel HP''sini 100''e çıkarır. Hareket hızınızı 3 metre düşürür ancak kritik vuruşlara karşı bağışıklık sağlar.', 'Increases Core Barrier base HP to 100. It now slows your movement by 3m but makes you immune to crits.', 'Core Shield', 45, 400, 3, '{"cp_kinetic_absorber"}', '{"x": 1253, "y": 1493}', '{"shield_hp": "100", "speed": "-3m", "immunity": "critical hits"}', '⚓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('62205da0-ff79-46bb-8c2d-8424372ccb9a', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_ally_tether', 'Kalkan Bağı', 'Shield Tether', 'Çekirdek Bariyerinizin bir kısmını 15 metre içindeki bir müttefike yansıtarak onlara 40 HP''lik bir kalkan sağlar.', 'Projects a portion of your Core Barrier to an ally within 15m, granting them a 40 HP shield.', 'Core Shield', 50, 450, 3, '{"cp_kinetic_absorber"}', '{"x": 1414, "y": 1685}', '{"range": "15m", "shield": "40 HP"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f7ff8e69-fb4e-4b06-bc55-b666244db326', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_perfect_guard', 'Kusursuz Koruma', 'Perfect Guard', 'Bir reaksiyon olarak tek bir saldırının hasarını tamamen yok eder. 3 tur bekleme süresi.', 'As a reaction, completely negate the damage of a single attack. 3 turn cooldown.', 'Core Shield', 61, 600, 4, '{"cp_heavy_core"}', '{"x": 1574, "y": 1876}', '{"negate": "1 attack", "cooldown": "3 turns"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('46995911-88be-4fa6-89b0-47707f299fc0', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_energy_discharge', 'Enerji Deşarjı', 'Energy Discharge', 'Çekirdek Bariyerinde biriken enerjiyi 15 metrelik bir koni şeklinde serbest bırakarak 6d6 yıldırım hasarı verir.', 'Release accumulated energy from the Core Barrier in a 15m cone, dealing 6d6 lightning damage.', 'Core Shield', 65, 700, 4, '{"cp_perfect_guard"}', '{"x": 1735, "y": 2068}', '{"shape": "15m cone", "damage": "6d6 lightning"}', '🌩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dcc9de83-6243-4e99-9c93-147e05bc00f1', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_core_overload', 'Çekirdek Aşırı Yüklemesi', 'Core Overload', 'Kalkanınızı aşırı yükler. 3 turluğuna aldığınız tüm hasarlar 0''a iner, ancak sonrasında kalkanınız tamamen kırılır.', 'Overloads your shield. For 3 turns, any damage you take is reduced to 0, but your shield breaks entirely afterward.', 'Core Shield', 70, 800, 4, '{"cp_perfect_guard"}', '{"x": 1896, "y": 2259}', '{"duration": "3 turns", "damage_reduction": "100%", "penalty": "shield break"}', '🧨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8e22a087-205d-409a-8b39-146d8b1da6d6', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_shield_mastery', 'Kalkan Ustalığı', 'Shield Mastery', 'Çekirdek Bariyeriniz tur başına otomatik olarak 20 HP yenilenir ve tüm hasar türlerine karşı direnç sağlar.', 'Your Core Barrier regenerates 20 HP per turn automatically and grants resistance to all damage types.', 'Core Shield', 81, 1100, 5, '{"cp_energy_discharge", "cp_core_overload"}', '{"x": 2056, "y": 2451}', '{"regen": "20 HP/turn", "resistance": "all"}', '🔰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c06fbde3-12d0-4505-8eaf-9e0ca599c90e', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_ultimate_core_bastion', 'Nihai Çekirdek Kalesi', 'Ultimate Core Bastion', 'Yaşayan bir kaleye dönüşürsünüz. Çekirdek Bariyeri HP''si 500 olur ve 10 metre içindeki tüm müttefikler bu devasa kalkan havuzunu paylaşır.', 'You become a living fortress. Core Barrier HP becomes 500, and all allies within 10m share this massive shield pool.', 'Core Shield', 90, 1500, 5, '{"cp_shield_mastery"}', '{"x": 2217, "y": 2642}', '{"shield_hp": "500", "radius": "10m", "share": "allies"}', '🏰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('116317c9-db4f-4ca8-a878-5fa39b783048', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_iron_reinforcement', 'Demir Güçlendirme', 'Iron Reinforcement', 'Fiziksel zırhınızı büyüsel demirle güçlendirerek 10 dakika boyunca +3 Zırh Sınıfı sağlar.', 'Reinforces your physical armor with magical iron, granting +3 AC for 10 minutes.', 'Reinforcement', 1, 50, 1, '{}', '{"x": -128, "y": 153}', '{"duration": "10 mins", "ac": "+3"}', '🦾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2fc5589e-99ff-49c7-bb1b-34ecd5b93ed9', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_ground_anchor', 'Zemin Çapası', 'Ground Anchor', 'Kendinizi yere sabitlersiniz. Hareket ettirilemezsiniz ve tüm güç kontrollerinde avantaj kazanırsınız.', 'You anchor yourself to the ground. You cannot be moved, and you gain advantage on all strength checks.', 'Reinforcement', 5, 75, 1, '{"cp_iron_reinforcement"}', '{"x": -289, "y": 344}', '{"immunity": "forced movement", "advantage": "strength checks"}', '⬇️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('110f8eba-dd81-4388-8074-63cb2c9115b1', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_minor_barricade', 'Küçük Barikat', 'Minor Barricade', 'Yarım siper sağlayan, 50 HP''ye sahip 2 metre genişliğinde ve 1 metre yüksekliğinde taştan bir barikat çağırır.', 'Summons a 2m wide, 1m tall stone barricade with 50 HP that provides half cover.', 'Reinforcement', 10, 100, 1, '{"cp_iron_reinforcement"}', '{"x": -449, "y": 536}', '{"size": "2mx1m", "hp": "50", "cover": "half"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c339bbf7-35dd-4aa4-8e92-50066e4d3aa4', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_steel_infusion', 'Çelik İnfüzyonu', 'Steel Infusion', 'Fiziksel güçlendirmeyi çeliğe yükselterek +5 Zırh Sınıfı ve kesici hasarlara karşı direnç sağlar.', 'Upgrades physical reinforcement to steel, granting +5 AC and resistance to slashing damage.', 'Reinforcement', 21, 200, 2, '{"cp_ground_anchor"}', '{"x": -610, "y": 727}', '{"ac": "+5", "resistance": "slashing"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3078e138-acf2-4b9e-9958-77b5da282bf6', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_guardian_wall', 'Muhafız Duvarı', 'Guardian Wall', 'Tam siper sağlayan, 150 HP''ye sahip 5 metre genişliğinde ve 3 metre yüksekliğinde büyüsel bir duvar çağırır.', 'Summons a 5m wide, 3m tall magical wall with 150 HP that provides full cover.', 'Reinforcement', 25, 220, 2, '{"cp_minor_barricade"}', '{"x": -771, "y": 919}', '{"size": "5mx3m", "hp": "150", "cover": "full"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1132e55c-2251-42bd-b502-e7faf9ff41d8', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_crushing_weight', 'Ezici Ağırlık', 'Crushing Weight', 'Kütlenizi dramatik bir şekilde artırır. Yakın dövüş saldırılarınız fazladan 1d10 hasar verir ve zıplamak 3 metrelik bir şok dalgası yaratır.', 'Increases your mass dramatically. Your melee attacks deal an extra 1d10 damage, and jumping creates a 3m shockwave.', 'Reinforcement', 30, 250, 2, '{"cp_steel_infusion"}', '{"x": -932, "y": 1110}', '{"bonus_damage": "1d10", "shockwave_radius": "3m"}', '🐘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7c99d974-aebf-4f8b-8c93-11ae7395f774', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_titanium_plating', 'Titanyum Kaplama', 'Titanium Plating', 'Zırhınız titanyum ile güçlendirilir. Kritik vuruşlara karşı bağışıklık kazanırsınız ve alınan tüm fiziksel hasarları 10 azaltırsınız.', 'Your armor is reinforced with titanium. You gain immunity to critical hits and reduce all incoming physical damage by 10.', 'Reinforcement', 41, 350, 3, '{"cp_crushing_weight"}', '{"x": -1092, "y": 1302}', '{"immunity": "critical hits", "damage_reduction": "10 physical"}', '🔘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('02328ad6-fcc9-4c9e-a717-2c556e41e3c6', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_tremor_stomp', 'Deprem Ezmesi', 'Tremor Stomp', 'Yere muazzam bir güçle basarak 8 metre içindeki tüm düşmanları yere serer ve 3d8 ezici hasar verir.', 'Stomp the ground with immense force, knocking all enemies within 8m prone and dealing 3d8 bludgeoning damage.', 'Reinforcement', 45, 400, 3, '{"cp_titanium_plating"}', '{"x": -1253, "y": 1493}', '{"radius": "8m", "damage": "3d8 bludgeoning", "status": "prone"}', '🥾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2ceb0bda-de20-49d6-adbf-3bf24e31b4d8', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_siege_defense', 'Kuşatma Savunması', 'Siege Defense', 'Çağırdığınız barikatlar ve duvarlar artık aldıkları hasarın %20''sini saldırgana geri yansıtır ve iki kat HP''ye sahip olur.', 'Barricades and walls you summon now reflect 20% of damage taken back to the attacker and have double HP.', 'Reinforcement', 50, 450, 3, '{"cp_guardian_wall"}', '{"x": -1414, "y": 1685}', '{"reflect": "20%", "hp_multiplier": "2x"}', '🏹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cfef5c46-3fcf-4196-ba79-8402fbbb6ab2', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_unbreakable_bulwark', 'Kırılmaz Siper', 'Unbreakable Bulwark', '1 dakika boyunca Zırh Sınıfınız 25''in altına düşemez ve dayanıklılık kurtarma zarlarında otomatik olarak başarılı olursunuz.', 'For 1 minute, your AC cannot drop below 25, and you automatically succeed on constitution saving throws.', 'Reinforcement', 61, 600, 4, '{"cp_titanium_plating"}', '{"x": -1574, "y": 1876}', '{"duration": "1 min", "min_ac": "25", "save": "auto-success CON"}', '🕋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('89199f85-8633-4481-8437-e724e2f01ea6', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_mass_fortification', 'Toplu Güçlendirme', 'Mass Fortification', '20 metre içindeki tüm müttefiklerin zırhını güçlendirerek onlara +4 Zırh Sınıfı ve ezici hasarlara karşı direnç sağlar.', 'Reinforces the armor of all allies within 20m, granting them +4 AC and resistance to bludgeoning damage.', 'Reinforcement', 65, 700, 4, '{"cp_unbreakable_bulwark"}', '{"x": -1735, "y": 2068}', '{"radius": "20m", "ac": "+4", "resistance": "bludgeoning"}', '👥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b2dd2dc9-d919-44cb-a96b-b5aa1e97491b', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_fortified_core', 'Güçlendirilmiş Çekirdek', 'Fortified Core', 'Ruhunuz güçlendirilir. Zihin değiştiren etkilere karşı bağışıklık kazanırsınız ve büyülere karşı avantaj elde edersiniz.', 'Your very soul is fortified. You become immune to mind-altering effects and gain advantage against spells.', 'Reinforcement', 70, 800, 4, '{"cp_unbreakable_bulwark"}', '{"x": -1896, "y": 2259}', '{"immunity": "mind-altering", "advantage": "vs spells"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9f365386-fab2-4afa-b6c2-c1cca43417f1', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_reinforcement_mastery', 'Güçlendirme Ustalığı', 'Reinforcement Mastery', 'Fiziksel formunuz kusursuz bir şekilde güçlendirilir. Temel Zırh Sınıfı kalıcı olarak +5 artar ve ağırlığınız büyüyle kaydırılamaz.', 'Your physical form is perfectly reinforced. Base AC increases by +5 permanently, and your weight cannot be shifted by magic.', 'Reinforcement', 81, 1100, 5, '{"cp_mass_fortification", "cp_fortified_core"}', '{"x": -2056, "y": 2451}', '{"ac": "+5 permanent", "immunity": "magical push"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('efba9edc-9802-42ba-9a14-e02d5a42c5f0', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_ultimate_impenetrable_fortress', 'Nihai Aşılmaz Kale', 'Ultimate Impenetrable Fortress', '50 metrelik savaş alanını ağır tahkimatlı bir bölgeye çevirir. Müttefikler +10 ZS kazanır, %50 daha az hasar alır ve düşmanların hızı yarıya iner.', 'Transforms the battlefield within 50m into a heavily fortified zone. Allies gain +10 AC, take 50% less damage, and enemies'' speed is halved.', 'Reinforcement', 90, 1500, 5, '{"cp_reinforcement_mastery"}', '{"x": -2217, "y": 2642}', '{"radius": "50m", "ac": "+10", "damage_reduction": "50%", "enemy_speed": "halved"}', '🏔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c4a4762a-4bc7-4869-aca1-1915e44628e4', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_shining_core_aura', 'Parlayan Çekirdek Aurası', 'Shining Core Aura', 'Çekirdek Bariyeri enerjisini auranızla birleştirir. 15 metre içindeki müttefikler tur başına 10 HP yenilenen küçük bir kalkan kazanır.', 'Merges Core Barrier energy with your aura. Allies within 15m gain a small regenerating shield of 10 HP per turn.', 'Cross-Branch', 35, 300, 2, '{"cp_aura_expansion", "cp_core_barrier"}', '{"x": -173, "y": -100}', '{"radius": "15m", "shield_regen": "10 HP/turn"}', '💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a1939713-735a-42a8-bd0b-88ab3106351d', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_shielded_barricade', 'Kalkanlı Barikat', 'Shielded Barricade', 'Fiziksel duvarlarınızı Çekirdek Kalkanı enerjisiyle doldurur. Duvar, tur başına 20 HP yenilenen 100 HP''lik bir enerji kalkanı kazanır.', 'Imbues your physical walls with Core Shield energy. The wall gains a 100 HP energy shield that regenerates 20 HP per turn.', 'Cross-Branch', 55, 500, 3, '{"cp_reactive_plating", "cp_guardian_wall"}', '{"x": -389, "y": -225}', '{"shield_hp": "100", "shield_regen": "20 HP/turn"}', '🔰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8aebf5fc-7322-490f-961b-b3a7a7199241', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_reinforced_aura', 'Güçlendirilmiş Aura', 'Reinforced Aura', 'Defans aurası artık müttefiklere fiziksel ağırlık da sağlayarak onları 20 metre içinde zorunlu harekete karşı bağışık hale getirir.', 'Your defense aura now also grants physical weight to allies, making them immune to forced movement within 20m.', 'Cross-Branch', 55, 500, 3, '{"cp_aura_density", "cp_steel_infusion"}', '{"x": -606, "y": -350}', '{"radius": "20m", "immunity": "forced movement"}', '🌐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2f1c7579-6fe2-4e23-8a30-df223b18952a', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_core_pulse_shield', 'Çekirdek Nabız Kalkanı', 'Core Pulse Shield', 'Çekirdek Bariyeriniz hasar aldığında auranız nabız atarak 20 metre içindeki tüm müttefikleri 2d6 HP iyileştirir.', 'Whenever your Core Barrier takes damage, your aura pulses, healing all allies within 20m for 2d6 HP.', 'Cross-Branch', 75, 900, 4, '{"cp_suppression_field", "cp_ally_tether"}', '{"x": -822, "y": -475}', '{"radius": "20m", "healing": "2d6 HP"}', '💓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('14d9cd49-229c-4660-a7f5-a24a49f961ab', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_wall_of_core_energy', 'Çekirdek Enerjisi Duvarı', 'Wall of Core Energy', 'Görüş hattını, büyüleri ve fiziksel saldırıları engelleyen, 20 metre uzunluğunda ve 5 metre yüksekliğinde devasa saf çekirdek enerjisi bariyeri çağırır.', 'Summons a massive 20m long, 5m high barrier of pure core energy that blocks line of sight, spells, and physical attacks.', 'Cross-Branch', 75, 900, 4, '{"cp_perfect_guard", "cp_unbreakable_bulwark"}', '{"x": -1039, "y": -600}', '{"size": "20mx5m", "blocks": "sight, spells, physical"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d044b10d-5ee9-465f-829c-6bfe8c4ef34f', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_fortress_aura', 'Kale Aurası', 'Fortress Aura', '25 metrelik auranızdaki müttefikler açık alanı tam siper olarak değerlendirir, +5 ZS ve çeviklik kurtarışlarında avantaj kazanır.', 'Allies within your 25m aura treat the open ground as full cover, gaining +5 AC and advantage on dexterity saves.', 'Cross-Branch', 75, 900, 4, '{"cp_unyielding_presence", "cp_mass_fortification"}', '{"x": -1255, "y": -725}', '{"radius": "25m", "cover": "full", "ac": "+5"}', '🏯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('289ca5e3-e8db-4123-8163-bcb86e00706b', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_coreplate_juggernaut', 'Coreplate Juggernaut', 'Coreplate Juggernaut', '1 dakika boyunca devasa bir savunma avatarı olursunuz. 500 Geçici HP, +10 ZS kazanırsınız ve aura yarıçapınız iki katına çıkar.', 'For 1 minute, you become a giant avatar of defense. You gain 500 Temp HP, +10 AC, and your aura radius doubles.', 'Cross-Branch', 85, 1300, 5, '{"cp_aura_overcharge", "cp_core_overload", "cp_fortified_core"}', '{"x": -1472, "y": -850}', '{"duration": "1 min", "temp_hp": "500", "ac": "+10"}', '🤖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cb380c9b-e402-4cec-b77d-1eebd2afa9d3', 'fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'cp_absolute_core_defense', 'Mutlak Çekirdek Savunması', 'Absolute Core Defense', 'Coreplate büyüsünün zirvesi. 3 tur boyunca siz ve 100 metre içindeki tüm müttefikler hiçbir kaynaktan hasar almaz (0 hasar). Bu sürede hareket edemezsiniz.', 'The pinnacle of Coreplate magic. For 3 turns, you and all allies within 100m take exactly 0 damage from any source. You cannot act during this time.', 'Cross-Branch', 100, 1500, 5, '{"cp_ultimate_aegis_aura", "cp_ultimate_core_bastion", "cp_ultimate_impenetrable_fortress"}', '{"x": -1688, "y": -975}', '{"duration": "3 turns", "radius": "100m", "damage_reduction": "100%"}', '🌍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0c3b206e-cae3-42a1-9811-659521b6b3e3', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_scan', 'İnceleme', 'Scan', '15m menzildeki bir hedefi tarayarak HP, MP ve temel dirençlerini ortaya çıkarır.', 'Scans a target within 15m, revealing HP, MP, and basic resistances.', 'Observe', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"range": "15m"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7d587bba-0cc1-4694-8675-940fdd76dabd', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_keen_eye', 'Keskin Göz', 'Keen Eye', '30 saniye boyunca açıklar bularak kritik vuruş şansını %10 artıran bir yetenek.', 'Increases critical hit chance by 10% for 30s by finding small openings.', 'Observe', 5, 75, 1, '{"cr_scan"}', '{"x": 389, "y": -224}', '{"duration": "30s", "crit_chance": "+10%"}', '🔍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fa5e0938-d579-4f7c-92d2-ef3cbcb3a139', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_weakness_spot', 'Zayıf Nokta', 'Weakness Spot', '20m menzildeki bir hedefi işaretler. Hedef 15 saniye boyunca tüm kaynaklardan %15 daha fazla hasar alır.', 'Marks a target at 20m. Target takes 15% more damage from all sources for 15s.', 'Observe', 10, 100, 1, '{"cr_keen_eye"}', '{"x": 606, "y": -349}', '{"range": "20m", "duration": "15s", "damage_taken": "+15%"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b9b91f28-e1bc-4215-8bde-421fc8f50ab2', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_aura_read', 'Aura Okuma', 'Aura Read', '1 dakika boyunca görünmez düşmanları ve büyülü tuzakları ortaya çıkaran 20m gerçek görüş kazandırır.', 'Grants 20m true sight, revealing invisible enemies and magical traps for 1 minute.', 'Observe', 22, 200, 2, '{"cr_weakness_spot"}', '{"x": 822, "y": -474}', '{"range": "20m", "duration": "60s", "true_sight": "true"}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0ea54a7c-9fa9-48bd-b831-2424f8babd57', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_predict_movement', 'Hareket Tahmini', 'Predict Movement', '10 saniye içinde gelecek ilk 3 saldırıya karşı %50 kaçınma şansı verir.', 'Gives a 50% dodge chance against the next 3 incoming attacks within 10s.', 'Observe', 28, 250, 2, '{"cr_aura_read"}', '{"x": 1039, "y": -599}', '{"duration": "10s", "dodge_chance": "50%"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c258d46e-af73-431c-a4b2-e22b14c475d6', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_anatomy_study', 'Anatomi Çalışması', 'Anatomy Study', '20 saniye boyunca saldırılarınız hedefin fiziksel zırhının %25''ini görmezden gelir.', 'Attacks ignore 25% of the target''s physical armor for 20s.', 'Observe', 35, 300, 2, '{"cr_predict_movement"}', '{"x": 1255, "y": -724}', '{"duration": "20s", "armor_penetration": "25%"}', '🧬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('199ea812-29c6-4aed-9abf-972c26e2eb15', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_piercing_gaze', 'Delici Bakış', 'Piercing Gaze', '15m içindeki bir hedefe 4d8 psişik hasar verir ve onu 3 saniyeliğine sersemletir.', 'Deals 4d8 psychic damage and stuns a target for 3s within 15m.', 'Observe', 42, 400, 3, '{"cr_anatomy_study"}', '{"x": 1472, "y": -849}', '{"range": "15m", "damage": "4d8", "stun": "3s"}', '👁️‍🗨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8e30ba36-2dc8-4f54-9a71-52437ca06a3f', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_flaw_exploitation', 'Kusur Sömürüsü', 'Flaw Exploitation', 'Zayıf Nokta ile işaretlenmiş hedefe 6d10 gerçek hasar verir. Menzil 10m.', 'Deals 6d10 true damage if the target is marked by Weakness Spot. Range 10m.', 'Observe', 48, 450, 3, '{"cr_piercing_gaze"}', '{"x": 1688, "y": -974}', '{"range": "10m", "damage": "6d10"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0f0f43cc-563a-4d4a-b9f7-e206248686ff', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_clairvoyance', 'Durugörü', 'Clairvoyance', 'Duvarları yok sayarak 500m uzaklığa kadar herhangi bir konumu 1 dakika boyunca izlemenizi sağlar.', 'View any location up to 500m away for 1 minute, ignoring walls.', 'Observe', 55, 500, 3, '{"cr_flaw_exploitation"}', '{"x": 1905, "y": -1099}', '{"range": "500m", "duration": "60s"}', '🔭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('43699df4-f43a-4fde-aa25-f0cd264f74c9', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_absolute_focus', 'Mutlak Odak', 'Absolute Focus', '12 saniye boyunca zaman algınızı yavaşlatır; eylem hızınızı %100 ve hareket hızınızı %50 artırır.', 'Slows down time for the user; increases action speed by 100% and movement speed by 50% for 12s.', 'Observe', 62, 700, 4, '{"cr_clairvoyance"}', '{"x": 2121, "y": -1224}', '{"duration": "12s", "action_speed": "+100%", "movement_speed": "+50%"}', '⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5eaf7ad2-d33f-4879-a192-65c157ec06b8', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_omniscience_glimpse', 'Her Şeyi Bilme Belirtisi', 'Omniscience Glimpse', '8 saniye boyunca %100 kaçınma şansı ve sürpriz saldırılara karşı bağışıklık kazandırır.', 'Gain 100% dodge chance and immunity to surprise attacks for 8s.', 'Observe', 70, 800, 4, '{"cr_absolute_focus"}', '{"x": 2338, "y": -1349}', '{"duration": "8s", "dodge_chance": "100%"}', '🌟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f30bed73-cf44-479d-8076-b461795f5fbe', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_vital_strike', 'Hayati Vuruş', 'Vital Strike', 'Kesinlikle kritik vuran, 12d10 fiziksel hasar veren ve 5 saniye boyunca saniyede 2d10 kanama uygulayan hesaplanmış bir yakın dövüş saldırısı.', 'A calculated melee strike that guarantees a critical hit and deals 12d10 physical damage, causing massive bleeding (2d10 per sec for 5s).', 'Observe', 78, 900, 4, '{"cr_omniscience_glimpse"}', '{"x": 2554, "y": -1474}', '{"damage": "12d10", "bleed": "2d10/s", "duration": "5s"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0826c4ce-ada4-4f98-9051-c8e43f3af39b', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_perfect_analysis', 'Kusursuz Analiz', 'Perfect Analysis', '30m menzildeki bir hedefin tüm bağışıklıklarını ve dirençlerini 15 saniyeliğine ortadan kaldırır.', 'Strips a target of all immunities and resistances for 15s. Range 30m.', 'Observe', 85, 1200, 5, '{"cr_vital_strike"}', '{"x": 2771, "y": -1599}', '{"range": "30m", "duration": "15s", "strip_resistances": "true"}', '📈');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5981c850-0e86-495f-9cfe-7901efa36a49', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_all_seeing_eye', 'Her Şeyi Gören Göz', 'All-Seeing Eye', '30 saniyeliğine savaş alanının üzerinde devasa ruhani bir göz çağırır. Tüm müttefiklere 100m gerçek görüş, %50 kritik şansı verir ve müttefik başına ilk 5 saldırıdan otomatik kaçınma sağlar.', 'Summons a massive ethereal eye over the battlefield for 30s. Grants 100m true sight to all allies, increases their crit chance by 50%, and automatically dodges the first 5 attacks per ally.', 'Observe', 95, 1500, 5, '{"cr_perfect_analysis"}', '{"x": 2987, "y": -1724}', '{"duration": "30s", "range": "100m", "crit_chance": "+50%"}', '🧿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9bac4ac5-156e-40d2-a91b-eadbc2093a0c', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_minor_catalyst', 'Küçük Katalizör', 'Minor Catalyst', '3m yarıçapında 2d6 rastgele element hasarı veren bir şişe fırlatır.', 'Throws a flask dealing 2d6 random elemental damage in a 3m radius.', 'Experiment', 2, 50, 1, '{}', '{"x": 128, "y": 153}', '{"range": "3m", "damage": "2d6"}', '🧪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6e27d6a4-c0a4-4e61-82d8-95bfaaa92ace', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_volatile_flask', 'Uçucu Şişe', 'Volatile Flask', '5m yarıçapında 3d6 ateş hasarı veren dengesiz bir şişe fırlatır. %10 ihtimalle elde patlayarak yarı hasar verir.', 'Throws an unstable flask dealing 3d6 fire damage in a 5m radius. Has a 10% chance to explode in hand for half damage.', 'Experiment', 6, 80, 1, '{"cr_minor_catalyst"}', '{"x": 289, "y": 344}', '{"range": "5m", "damage": "3d6"}', '🏺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8edc99e0-03f1-4ed0-b2cd-d4de88cdfdbb', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_random_spark', 'Rastgele Kıvılcım', 'Random Spark', '8m içindeki 2 rastgele hedefe seken 2d8 yıldırım hasarı veren bir enerji oku ateşler.', 'Shoots a bolt dealing 2d8 lightning damage that bounces to 2 random targets within 8m.', 'Experiment', 12, 120, 1, '{"cr_volatile_flask"}', '{"x": 449, "y": 536}', '{"range": "8m", "damage": "2d8", "bounces": "2"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('83758db4-79af-49f9-83a4-eef23d9b2019', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_mutated_element', 'Mutasyona Uğramış Element', 'Mutated Element', '20m menzilde 4d6 hasar veren ve zırhı 5 saniyeliğine 10 azaltan ateş ve asit karışımı fırlatır.', 'Combines fire and acid to shoot a glob dealing 4d6 damage, reducing armor by 10 for 5s. Range 20m.', 'Experiment', 24, 200, 2, '{"cr_random_spark"}', '{"x": 610, "y": 727}', '{"range": "20m", "damage": "4d6", "armor_reduction": "10", "duration": "5s"}', '🦠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('91dffb1a-21db-4a25-b68f-aec2c62bafa2', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_unstable_concoction', 'Kararsız Karışım', 'Unstable Concoction', '15 saniyeliğine devasa bir rastgele güçlendirme (+%50 hasar, hız veya zırh) kazanmak için içilir, ancak saniyede 1d10 zehir hasarı alınır.', 'Drink to gain a random massive buff (+50% dmg, +50% speed, or +50% armor) for 15s, but take 1d10 poison damage per second.', 'Experiment', 30, 250, 2, '{"cr_mutated_element"}', '{"x": 771, "y": 919}', '{"duration": "15s", "buff": "+50%", "self_damage": "1d10/s"}', '🍸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f13e57a8-a401-41d6-9a4e-48d825cb322f', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_bouncing_jolt', 'Sıçrayan Çarpma', 'Bouncing Jolt', '4d8 hasar veren ve 5 defaya kadar seken yıldırım atar. Menzil 20m.', 'Lightning that deals 4d8 damage and bounces up to 5 times. Range 20m.', 'Experiment', 38, 300, 2, '{"cr_unstable_concoction"}', '{"x": 932, "y": 1110}', '{"range": "20m", "damage": "4d8", "bounces": "5"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0dd5030b-a191-45b1-bd5c-7ee0b24c0498', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_chaotic_infusion', 'Kaotik İnfüzyon', 'Chaotic Infusion', 'Silahınızı kaosla güçlendirir. Sonraki 5 vuruş fazladan 3d8 rastgele element hasarı verir ve rastgele bir zayıflatma uygular.', 'Infuse your weapon. Next 5 hits deal an extra 3d8 damage of a random element and apply a random debuff.', 'Experiment', 44, 400, 3, '{"cr_bouncing_jolt"}', '{"x": 1092, "y": 1302}', '{"hits": "5", "bonus_damage": "3d8"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('38ef2999-c620-4432-ba99-ddf80b9691ab', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_hazardous_brew', 'Tehlikeli Karışım', 'Hazardous Brew', '15 saniye boyunca her 3 saniyede bir mutasyona uğrayan, değişen türlerde 4d6 hasar veren ve farklı durum efektleri uygulayan 10m yarıçapında bir su birikintisi yaratır.', 'Creates a 10m radius puddle that mutates every 3s, dealing 4d6 damage of changing types and applying different status effects for 15s.', 'Experiment', 50, 450, 3, '{"cr_chaotic_infusion"}', '{"x": 1253, "y": 1493}', '{"radius": "10m", "duration": "15s", "damage": "4d6/3s"}', '☣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d6409e09-f17d-46c9-a9a9-cdba165cbf1c', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_wild_surge', 'Vahşi Dalgalanma', 'Wild Surge', 'Bir sonraki büyünün etkisini ikiye katlama şansı %50, 30m içindeki rastgele bir varlığı hedef alma şansı %50''dir.', 'Next spell cast has a 50% chance to double its effects, and a 50% chance to target a random entity within 30m.', 'Experiment', 58, 500, 3, '{"cr_hazardous_brew"}', '{"x": 1414, "y": 1685}', '{"double_chance": "50%", "range": "30m"}', '🎲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3edede56-2a29-43cf-bfd4-7c0ae8bc624e', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_chain_reaction', 'Zincirleme Reaksiyon', 'Chain Reaction', 'Bir hedefi 15 saniyeliğine lanetler. Etki altındayken ölürlerse patlayarak 10m yarıçapında 8d10 hasar verir ve laneti başkalarına yayarlar.', 'Curses a target for 15s. If they die under this effect, they explode dealing 8d10 damage in a 10m radius, spreading the curse to others.', 'Experiment', 64, 700, 4, '{"cr_wild_surge"}', '{"x": 1574, "y": 1876}', '{"duration": "15s", "radius": "10m", "damage": "8d10"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fead3581-df53-4290-ae19-3f6db3d1c0d2', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_anomalous_burst', 'Anormal Patlama', 'Anomalous Burst', '10d10 saf hasar veren 15m yarıçapında bir patlama. Hedefleri susturma, sersemletme veya silahsızlandırma şansı %20''dir.', 'A 15m radius explosion dealing 10d10 pure damage. Has a 20% chance to silence, stun, or disarm targets.', 'Experiment', 72, 800, 4, '{"cr_chain_reaction"}', '{"x": 1735, "y": 2068}', '{"radius": "15m", "damage": "10d10"}', '🎇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ca2272d3-d449-43f3-a48e-744cab2b9a12', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_reality_warp', 'Gerçeklik Bükülmesi', 'Reality Warp', '40m içindeki en fazla 5 düşmanın yerlerini rastgele değiştirir, 6d10 uzay hasarı verir ve onları 3 saniyeliğine sersemletir.', 'Randomly swaps the positions of up to 5 enemies within 40m, dealing 6d10 space damage and confusing them for 3s.', 'Experiment', 80, 900, 4, '{"cr_anomalous_burst"}', '{"x": 1896, "y": 2259}', '{"range": "40m", "damage": "6d10", "stun": "3s"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('38c28729-f441-4a04-90da-94dad6020724', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_quantum_state', 'Kuantum Durumu', 'Quantum State', '20 saniyeliğine süperpozisyon durumuna girer. Saldırıların %50''sinden kaçınırsınız ve yaptığınız her büyü otomatik olarak ikinci bir hedefe kopyalanır.', 'Enter a state of superposition for 20s. You evade 50% of all attacks, and every spell you cast is duplicated automatically at a second target.', 'Experiment', 88, 1200, 5, '{"cr_reality_warp"}', '{"x": 2056, "y": 2451}', '{"duration": "20s", "dodge_chance": "50%", "duplicate_spells": "true"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('039c8536-cf17-45b2-bfa5-aa6972336514', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_eureka_moment', 'Evreka Anı', 'Eureka Moment', 'Deneylerin zirvesi. 20 saniye süren 30m''lik bir anomali yaratır. Her saniye düşmanlara 15d10 rastgele element hasarı verir, müttefikleri 5d10 iyileştirir ve onlara rastgele güçlü güçlendirmeler kazandırır.', 'The pinnacle of experimentation. Create a 30m anomaly that lasts 20s. Every second, it deals 15d10 random elemental damage to enemies and heals allies for 5d10 while granting them random powerful buffs.', 'Experiment', 95, 1500, 5, '{"cr_quantum_state"}', '{"x": 2217, "y": 2642}', '{"radius": "30m", "duration": "20s", "damage": "15d10/s", "heal": "5d10/s"}', '💡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('193be4a8-8dc9-4822-9b48-c155e3187e3c', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_trailblazer', 'Öncü', 'Trailblazer', '30 saniye boyunca hareket hızını %20 artırır ve müttefiklerin aynı güçlendirme için takip edebileceği parlayan bir iz bırakır.', 'Increases movement speed by 20% and leaves a glowing trail that allies can follow for the same buff. Lasts 30s.', 'Discovery', 3, 60, 1, '{}', '{"x": -128, "y": 153}', '{"duration": "30s", "movement_speed": "+20%"}', '🛤️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d539ece2-5fcd-40c6-b018-1002c38d5a36', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_hidden_step', 'Gizli Adım', 'Hidden Step', 'Görebildiğiniz boş bir alana 8m''ye kadar anında ışınlanın.', 'Instantly teleport up to 8m to an unoccupied space you can see.', 'Discovery', 8, 90, 1, '{"cr_trailblazer"}', '{"x": -289, "y": 344}', '{"range": "8m"}', '👣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fb378970-d674-44a4-b708-8e5b203d24f0', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_object_reading', 'Nesne Okuma', 'Object Reading', 'Bir nesneye dokunarak onu son tutan kişinin ve son 24 saatteki kullanımının vizyonunu görün.', 'Touch an object to receive a vision of the last person who held it and its use in the past 24 hours.', 'Discovery', 15, 130, 1, '{"cr_hidden_step"}', '{"x": -449, "y": 536}', '{"duration": "24h_history"}', '📜');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8b435410-5d39-476e-b961-a16de8f401ef', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_phase_shift', 'Evre Geçişi', 'Phase Shift', '4 saniyeliğine soyutlaşarak 2m kalınlığa kadar katı nesnelerin içinden geçebilir ve fiziksel saldırılara karşı bağışıklık kazanırsınız.', 'Become intangible for 4s, able to pass through solid objects up to 2m thick and immune to physical attacks.', 'Discovery', 25, 220, 2, '{"cr_object_reading"}', '{"x": -610, "y": 727}', '{"duration": "4s", "intangible": "true"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('79337342-a39b-4aa3-bad2-c967b20e45c0', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_secret_path', 'Gizli Yol', 'Secret Path', '30m''ye kadar uzaklıktaki iki nokta arasında 1 dakika süren bir portal oluşturur.', 'Creates a portal between two points up to 30m apart that lasts for 1 minute.', 'Discovery', 32, 260, 2, '{"cr_phase_shift"}', '{"x": -771, "y": 919}', '{"range": "30m", "duration": "60s"}', '🚪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4191144f-353f-43ef-8662-8a18b5939712', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_archaeologist_touch', 'Arkeolog Dokunuşu', 'Archaeologist''s Touch', 'Kilitli bir kapıya veya sandığa dokunarak mekanizmasını ortaya çıkarır, kilidini açmak veya büyülü tuzakları atlatmak için +10 bonus kazandırır.', 'Touch a locked door or chest to reveal its mechanism, granting a +10 bonus to unlocking it or bypassing magical traps.', 'Discovery', 40, 300, 2, '{"cr_secret_path"}', '{"x": -932, "y": 1110}', '{"bonus": "+10"}', '⛏️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('04d7cb53-78a7-4a29-a32a-c91d9adf4a1d', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_wormhole_step', 'Solucandeliği Adımı', 'Wormhole Step', 'Anında 30m''ye kadar ışınlanır ve yakındaki düşmanları ayrılış noktanıza 3m çeken bir vakum yaratır.', 'Teleport up to 30m instantly, creating a vacuum that pulls nearby enemies 3m towards your departure point.', 'Discovery', 45, 400, 3, '{"cr_archaeologist_touch"}', '{"x": -1092, "y": 1302}', '{"range": "30m", "pull_radius": "3m"}', '🕳️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8b8c73f1-7ae4-4d55-9700-95d178658fc5', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_relic_activation', 'Kalıntı Aktivasyonu', 'Relic Activation', '3 kez titreşen kadim ruhani bir eser çağırır. Her titreşim düşmanları 5m geriye iter ve 3d10 kuvvet hasarı verir.', 'Summon an ancient ethereal artifact that pulses 3 times, each pulse pushing enemies back 5m and dealing 3d10 force damage.', 'Discovery', 52, 450, 3, '{"cr_wormhole_step"}', '{"x": -1253, "y": 1493}', '{"pulses": "3", "pushback": "5m", "damage": "3d10"}', '🏺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('07a61ed1-2f1d-45c0-bd91-dc20530644f3', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_gravity_tweak', 'Yerçekimi Ayarı', 'Gravity Tweak', '20 saniye boyunca düşmanların yarı hızda hareket ettiği ve müttefiklerin üç kat yükseğe zıplayabildiği 15m''lik bir bölge yaratır.', 'Create a 15m zone for 20s where enemies move at half speed and allies can jump triple height.', 'Discovery', 60, 500, 3, '{"cr_relic_activation"}', '{"x": -1414, "y": 1685}', '{"radius": "15m", "duration": "20s", "enemy_speed": "-50%"}', '🪐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6369505a-3653-4093-9215-7bb55e2afe36', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_spatial_fold', 'Uzamsal Katlanma', 'Spatial Fold', 'Uzayı katlayarak 40m uzaklıktaki bir hedefi anında yakın dövüş menziline getirir ve onları 1 saniyeliğine sersemletir.', 'Folds space, bringing a target up to 40m away instantly into melee range, stunning them for 1s.', 'Discovery', 65, 700, 4, '{"cr_gravity_tweak"}', '{"x": -1574, "y": 1876}', '{"range": "40m", "stun": "1s"}', '📐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6e7f5e3b-a2ef-431b-bef0-d15327c362fc', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_lost_knowledge', 'Kayıp Bilgi', 'Lost Knowledge', 'Diğer herhangi bir sınıftan rastgele bir Aşama 4 büyüsü yapma yeteneği kazandırır. Sonraki 10 dakika içinde bir kez kullanılabilir.', 'Gain the ability to cast one random Tier 4 spell from any other class. Usable once within the next 10 minutes.', 'Discovery', 75, 800, 4, '{"cr_spatial_fold"}', '{"x": -1735, "y": 2068}', '{"duration": "10m", "uses": "1"}', '📚');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fc068cce-0b3f-4c50-b182-a885f432e2a6', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_time_skip', 'Zaman Atlaması', 'Time Skip', 'Zamanı 3 saniye ileri atlatır. Ortadan kaybolur ve yeniden ortaya çıkarsınız, o süre zarfında size çarpacak olan her türlü hasarı veya etkiyi geçersiz kılarsınız.', 'Skips time forward by 3s. You vanish and reappear, negating any damage or effects that would have hit you during that window.', 'Discovery', 82, 900, 4, '{"cr_lost_knowledge"}', '{"x": -1896, "y": 2259}', '{"duration": "3s", "invulnerability": "true"}', '⏱️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d998d807-5649-4395-8f9e-746be46c0572', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_ancient_secret', 'Kadim Sır', 'Ancient Secret', '20m içindeki tüm düşmanlara çıldırtıcı kozmik bir gerçeği açıklar. 12d10 psişik hasar verir ve büyü dirençlerini kalıcı olarak %20 azaltır.', 'Reveal a maddening cosmic truth to all enemies within 20m. Deals 12d10 psychic damage and permanently reduces their magic resistance by 20%.', 'Discovery', 90, 1200, 5, '{"cr_time_skip"}', '{"x": -2056, "y": 2451}', '{"range": "20m", "damage": "12d10", "magic_resist": "-20%"}', '🗝️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ea82ddf4-9f78-437c-aede-85073ce7e9e7', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_world_walker', 'Dünya Gezgini', 'World Walker', '30 saniyeliğine dünyalar arasındaki boşluğa tamamen adım atarsınız. Her 2 saniyede bir 100m içindeki herhangi bir yere ışınlanabilirsiniz ve her ışınlanma dokunanlara 10d10 kuvvet hasarı veren uzaysal bir yırtık bırakır.', 'Step fully into the spaces between worlds for 30s. You can teleport anywhere within 100m every 2s, and each teleport leaves behind a spatial tear that deals 10d10 force damage to anyone touching it.', 'Discovery', 95, 1500, 5, '{"cr_ancient_secret"}', '{"x": -2217, "y": 2642}', '{"duration": "30s", "teleport_range": "100m", "damage": "10d10"}', '🗺️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d0367580-0b45-4aa7-baa1-e5e99224d82a', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_calculated_risk', 'Hesaplanmış Risk', 'Calculated Risk', 'Kimyasal bir karışımı mükemmel şekilde analiz ederek, 10m yarıçapında 6d8 ateş hasarı veren ancak müttefiklerden akıllıca kaçınan bir bomba yaratır.', 'Analyze a chemical mixture perfectly, creating a bomb that deals 6d8 fire damage in a 10m radius but intelligently avoids all allies.', 'Observe, Experiment', 35, 300, 2, '{"cr_anatomy_study", "cr_unstable_concoction"}', '{"x": 173, "y": -99}', '{"radius": "10m", "damage": "6d8"}', '📊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d442f657-811a-41b2-b0aa-26fa1c6aec58', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_scout_probe', 'Gözlem Sondası', 'Scout Probe', '200m uzağa kadar seyahat edebilen, görüşünü size aktaran ve 2 dakika boyunca gizli geçitleri tespit eden büyülü uçan bir göz yerleştirir.', 'Deploy a magical floating eye that travels up to 200m away, streaming its vision back to you and detecting hidden passages for 2 minutes.', 'Observe, Discovery', 38, 300, 2, '{"cr_aura_read", "cr_secret_path"}', '{"x": 173, "y": -99}', '{"range": "200m", "duration": "120s"}', '🛰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('93b8efc8-8bf5-4eb9-90ae-d69acf392530', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_field_testing', 'Saha Testi', 'Field Testing', 'Arka arkaya hızlıca 3 kez 15m''ye kadar rastgele atılın. Her durma noktasında, 4d8 yıldırım hasarı veren dengesiz bir mayın bırakın.', 'Dash randomly up to 15m three times in quick succession. At each stopping point, drop an unstable mine that deals 4d8 lightning damage.', 'Experiment, Discovery', 55, 500, 3, '{"cr_hazardous_brew", "cr_wormhole_step"}', '{"x": 173, "y": -99}', '{"dashes": "3", "range": "15m", "damage": "4d8"}', '🚀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5b14d9e2-699c-407f-870c-d169f20545ec', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_theory_proven', 'Kanıtlanmış Teori', 'Theory Proven', 'Bir düşmanın zayıf noktasını tam olarak savunmasız oldukları elementle hedefleyerek 8d8 özelleştirilmiş hasar verir ve hızlarını 5 saniyeliğine %30 azaltır.', 'Target an enemy''s weakness with the exact element they are vulnerable to, dealing 8d8 customized damage and reducing their speed by 30% for 5s.', 'Observe, Experiment', 58, 500, 3, '{"cr_flaw_exploitation", "cr_wild_surge"}', '{"x": 389, "y": -224}', '{"damage": "8d8", "speed": "-30%", "duration": "5s"}', '📐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('32fdcffa-1e6b-407f-bf90-07df63ce1ebf', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_dimensional_breach', 'Boyutsal Yırtık', 'Dimensional Breach', '20m içindeki tüm düşmanları içine çeken 5m''lik dengesiz bir portal açar. 10d10 uzay hasarı verir ve onları ağır bir şekilde mutasyona uğratarak 3 rastgele zayıflatma uygular.', 'Tear a 5m unstable portal that sucks in all enemies within 20m. Deals 10d10 space damage and heavily mutates them, applying 3 random debuffs.', 'Experiment, Discovery', 74, 800, 4, '{"cr_anomalous_burst", "cr_spatial_fold"}', '{"x": 389, "y": -224}', '{"radius": "20m", "damage": "10d10", "debuffs": "3"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5c0c7847-ce7f-4284-97a5-57908974ffe1', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_truth_unveiled', 'Ortaya Çıkan Gerçek', 'Truth Unveiled', '50m yarıçapında devasa bir aydınlanma dalgası yayar. Tüm illüzyonları ortadan kaldırır, tüm görünmezlikleri açığa çıkarır, yakındaki tüm gizli kapıların kilidini açar ve düşmanları 4 saniyeliğine kör eder.', 'Release a massive pulse of revelation in a 50m radius. Dispels all illusions, reveals all invisibility, unlocks all nearby hidden doors, and blinds enemies for 4s.', 'Observe, Discovery', 79, 900, 4, '{"cr_omniscience_glimpse", "cr_lost_knowledge"}', '{"x": 389, "y": -224}', '{"radius": "50m", "blind": "4s"}', '👁️‍🗨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4d36258e-6b0c-4570-8216-4b2a1693c5b0', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_paradigm_shift', 'Paradigma Kayması', 'Paradigm Shift', 'Bir hedefin etrafındaki temel kuralları 15 saniyeliğine değiştirir. En yüksek dirençleri en düşük dirençleri haline gelir ve verdikleri herhangi bir hasarın sizi iyileştirme şansı %50 olur.', 'Alter the fundamental rules around a target for 15s. Their highest resistance becomes their lowest, and any damage they deal has a 50% chance to heal you instead.', 'Observe, Experiment', 92, 1200, 5, '{"cr_perfect_analysis", "cr_quantum_state"}', '{"x": 606, "y": -349}', '{"duration": "15s", "lifesteal_chance": "50%"}', '🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0f0de4b8-89dd-47f3-bdc9-b27ce7a9bd3f', '8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'cr_universal_theorem', 'Evrensel Teorem', 'Universal Theorem', 'Merakın nihai gerçekleşmesi. Zamanı 5 saniyeliğine tamamen durdurur. Her düşmanı kusursuzca analiz edin, 5 anormal enerji küresi yerleştirin ve anında konumlanın. Zaman devam ettiğinde, küreler patlayarak her biri 30d10 gerçek hasar verir.', 'The ultimate realization of curiosity. Stop time completely for 5s. Perfectly analyze every enemy, deploy 5 anomalous energy spheres, and instantly reposition. When time resumes, the spheres detonate for 30d10 true damage each.', 'Observe, Experiment, Discovery', 100, 2000, 5, '{"cr_all_seeing_eye", "cr_eureka_moment", "cr_world_walker"}', '{"x": 173, "y": -99}', '{"duration": "5s", "spheres": "5", "damage": "30d10"}', '💠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3df5316f-165c-4bf2-a52a-16ad10dfde06', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_shadow_bolt', 'Gölge Mermisi', 'Shadow Bolt', 'Saf gölgeden bir mermi fırlatarak nekrotik hasar verir.', 'Hurls a bolt of pure shadow, dealing necrotic damage.', 'Shadow', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d10 necrotic", "range": "20m"}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f958d6dc-21cd-4b05-a2ac-b22c53737122', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_cloak_of_shadows', 'Gölgeler Pelerini', 'Cloak of Shadows', 'Büyücüyü gölgelerle sararak Zırh Sınıfını artırır ve gizlilik avantajı sağlar.', 'Wreathes the caster in shadows, increasing AC and granting stealth advantage.', 'Shadow', 5, 80, 1, '{"dm_shadow_bolt"}', '{"x": 389, "y": -224}', '{"bonus_ac": "+2", "duration": "10 min"}', '🧥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('984f8c9b-b006-4d83-8075-2ad8e563d4ce', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_shadow_step', 'Gölge Adımı', 'Shadow Step', 'Menzil içindeki bir gölgeden diğerine anında ışınlanmayı sağlar.', 'Instantly teleport from one shadow to another within range.', 'Shadow', 15, 120, 1, '{"dm_cloak_of_shadows"}', '{"x": 606, "y": -349}', '{"range": "15m", "type": "teleportation"}', '👣');
