INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9f9c65b4-1e78-49bd-9de8-f9e0bc7332cf', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_nightfall', 'Gece Çöküşü', 'Nightfall', 'İçindeki tüm düşmanları kör eden büyülü bir karanlık alanı çağırır.', 'Summons an area of magical darkness that blinds all enemies inside.', 'Shadow', 48, 420, 3, '{"dm_shadow_clone"}', '{"x": 1688, "y": -974}', '{"radius": "20m", "status": "blinded", "duration": "4 turns"}', '🌌');
