INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7bd1032e-e538-404a-b69d-17f2a0fa3dbb', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_dark_whispers', 'Karanlık Fısıltılar', 'Dark Whispers', 'Bir hedefin zihnine çıldırtıcı fısıltılar yerleştirerek korkuya neden olur.', 'Injects maddening whispers into a target''s mind, causing fear.', 'Forbidden', 10, 100, 1, '{"dm_blood_tribute"}', '{"x": -289, "y": 344}', '{"status": "frightened", "duration": "2 turns", "range": "15m"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0aeb5456-8209-4846-9940-716ed3d11aaa', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_necrotic_touch', 'Nekrotik Dokunuş', 'Necrotic Touch', 'Saf nekrotik enerjiyi yönlendiren ölümcül bir yakın dövüş dokunuşu.', 'A deadly melee touch that channels raw necrotic energy.', 'Forbidden', 20, 150, 1, '{"dm_dark_whispers"}', '{"x": -449, "y": 536}', '{"damage": "3d10 necrotic", "range": "melee"}', '🧟‍♂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a537aebd-df3b-49e4-8c68-92db0362dc4b', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_soul_harvest', 'Ruh Hasadı', 'Soul Harvest', 'Kendinize geçici sağlık kazandırmak için ölen bir düşmanın ruhunu hasat eder.', 'Harvests the fleeting soul of a dying enemy to grant yourself temporary health.', 'Forbidden', 26, 210, 2, '{"dm_necrotic_touch"}', '{"x": -610, "y": 727}', '{"temp_hp": "20", "range": "20m"}', '🌾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9406048e-5a82-46ca-8b3c-9873f2c100c1', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_defile_ground', 'Toprağı Yozlaştırma', 'Defile Ground', 'Toprağı yozlaştırarak düşmanlara hasar verir ve zorlu arazi yaratır.', 'Corrupts the earth itself, damaging enemies and creating difficult terrain.', 'Forbidden', 32, 260, 2, '{"dm_soul_harvest"}', '{"x": -771, "y": 919}', '{"radius": "10m", "damage_per_turn": "2d8 necrotic", "terrain": "difficult"}', '☣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('67375fe9-35d7-4ff6-b6cf-3572e168c5ea', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_forbidden_pact', 'Yasak Anlaşma', 'Forbidden Pact', 'Kendi yaşam gücünüz pahasına devasa bir güç için karanlık bir anlaşma yapar.', 'Make a dark pact for immense power at the cost of your own life force.', 'Forbidden', 40, 300, 2, '{"dm_defile_ground"}', '{"x": -932, "y": 1110}', '{"buff": "advantage on next 3 attacks", "self_damage": "10 per turn for 3 turns"}', '📜');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c12cc3bd-6701-4624-ab5e-97d2d2a95eb0', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_blood_boil', 'Kan Kaynatma', 'Blood Boil', 'Hedefin kanını kaynatarak ciddi hasar verir ve maksimum sağlığını azaltır.', 'Boils the target''s blood, dealing severe damage and reducing maximum health.', 'Forbidden', 46, 400, 3, '{"dm_forbidden_pact"}', '{"x": -1092, "y": 1302}', '{"damage": "6d6 necrotic", "max_hp_reduction": "equal to damage dealt"}', '🌡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a5050fb5-bba4-4ba7-8898-fc4667caac29', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_necrotic_wave', 'Nekrotik Dalga', 'Necrotic Wave', 'Düşmanlara hasar veren ve onları geri iten geniş bir ölüm büyüsü dalgası salar.', 'Releases a wide wave of death magic that damages and repels foes.', 'Forbidden', 52, 460, 3, '{"dm_blood_boil"}', '{"x": -1253, "y": 1493}', '{"damage": "8d6 necrotic", "line": "30m", "knockback": "5m"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('04ebbf95-55bb-4a78-a7fd-e803daf65de4', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_sacrifice', 'Kurban', 'Sacrifice', 'Çağırılmış bir müttefiki patlatarak güçlü bir nekrotik patlamaya neden olur.', 'Detonates a summoned ally, causing a powerful necrotic explosion.', 'Forbidden', 60, 500, 3, '{"dm_necrotic_wave"}', '{"x": -1414, "y": 1685}', '{"radius": "10m", "damage": "equal to minion''s max HP"}', '🔪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('44ff23c5-ab22-4d06-925d-0490c21dd24c', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_lich_form', 'Lich Formu', 'Lich Form', 'Geçici olarak bir Lich formuna bürünerek ölümsüz bağışıklıkları ve geçici sağlık kazanır.', 'Temporarily assume the form of a Lich, gaining undead immunities and temporary health.', 'Forbidden', 68, 700, 4, '{"dm_sacrifice"}', '{"x": -1574, "y": 1876}', '{"temp_hp": "40", "immunity": "poison and charm", "duration": "10 min"}', '💀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e1fb54e5-6ffe-40a3-9a76-ba4c50fe789e', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_soul_shatter', 'Ruh Parçalama', 'Soul Shatter', 'Hedefin ruhunu çatlatarak devasa hasar verir ve tüm iyileşmeleri engeller.', 'Cracks the target''s soul, dealing immense damage and preventing all healing.', 'Forbidden', 75, 800, 4, '{"dm_lich_form"}', '{"x": -1735, "y": 2068}', '{"damage": "10d8 necrotic", "debuff": "cannot be healed", "duration": "3 turns"}', '💔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bf7ee1ad-732e-4615-8932-ea1c1c14f02b', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_forbidden_ritual', 'Yasak Ritüel', 'Forbidden Ritual', 'Güçlü bir iblis çağırmak için tehlikeli bir kan ritüeli gerçekleştirir.', 'Perform a dangerous blood ritual to summon a powerful demon.', 'Forbidden', 80, 900, 4, '{"dm_soul_shatter"}', '{"x": -1896, "y": 2259}', '{"self_damage": "25% max HP", "summon": "greater demon", "duration": "5 min"}', '🕯️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7bb7df12-fe69-4e14-8c31-74e1a53cbae8', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_gate_of_the_abyss', 'Hiçliğin Kapısı', 'Gate of the Abyss', 'Hiçliğe bir portal açarak yakında yakalanan her şeyi mahveder.', 'Tears open a portal to the abyss, devastating anything caught nearby.', 'Forbidden', 86, 1150, 5, '{"dm_forbidden_ritual"}', '{"x": -2056, "y": 2451}', '{"damage": "12d10 necrotic", "radius": "20m"}', '🕳️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7a1d64bd-6ada-4571-820f-d1161c9cf47f', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_apocalypse', 'Kıyamet', 'Apocalypse', 'Nihai yasaklı büyü. Devasa bir alanı yok etmek için nekrotik ateş meteorları yağdırır.', 'The ultimate forbidden spell. Calls down meteors of necrotic fire to decimate a massive area.', 'Forbidden', 98, 1500, 5, '{"dm_gate_of_the_abyss"}', '{"x": -2217, "y": 2642}', '{"damage": "4x 10d6 necrotic fire", "radius": "50m"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a500da5e-6c58-4ac0-ad2c-2e06e7372bb2', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_shadow_curse', 'Gölge Laneti', 'Shadow Curse', 'Hedefi gölgelerin güvenliğinden lanetleyerek hasar verir ve onları kör eder.', 'Curses the target from the safety of the shadows, dealing damage and blinding them.', 'Cross-Branch', 25, 250, 2, '{"dm_shadow_step", "dm_curse_of_pain"}', '{"x": -173, "y": -100}', '{"damage": "4d6 necrotic", "status": "blinded", "duration": "2 turns"}', '🦇');
