INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1fbef5a2-7c95-4616-b85e-60a136161d8b', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_trinity_of_darkness', 'Karanlık Üçleme', 'Trinity of Darkness', 'Üç karanlık sanatı birleştirerek tek bir hedefi hasar, körlük ve sessizlikle mahveder.', 'Combines the three dark arts to devastate a single target with damage, blindness, and silence.', 'Cross-Branch', 85, 1100, 5, '{"dm_avatar_of_shadow", "dm_curse_of_the_damned", "dm_gate_of_the_abyss"}', '{"x": -1472, "y": -850}', '{"damage": "15d10 necrotic", "status": "blinded, silenced", "max_hp_reduction": "equal to damage"}', '👁️‍🗨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5aa7919e-5c19-4f6a-9665-77e42acab12d', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_absolute_void', 'Mutlak Hiçlik', 'Absolute Void', 'Büyük nihai büyü. Tüm ışığı emen ve zayıfları anında yok eden korkutucu bir hiçlik yaratır.', 'The grand ultimate. Creates a terrifying void that absorbs all light and instantly annihilates the weak.', 'Cross-Branch', 100, 1500, 5, '{"dm_eternal_night", "dm_word_of_death", "dm_apocalypse"}', '{"x": -1688, "y": -975}', '{"damage": "30d12 necrotic", "radius": "100m", "instakill_threshold": "15% max HP"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2028abb9-72c0-4eb0-b933-b162fc0ad33a', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_shadow_dash', 'Gölge Atılımı', 'Shadow Dash', 'Gölge izi bırakarak 10m''ye kadar atılın.', 'Dash up to 10m, leaving a trailing shadow.', 'Shadowstep', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"range": "10m", "duration": "Instant"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('67ebe626-c438-43d5-b57e-2d54ddea0718', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_fade', 'Soluş', 'Fade', '3 saniyeliğine görünmez olun. Bir eylem yapmak görünmezliği bozar.', 'Turn invisible for 3 seconds. Taking an action breaks it.', 'Shadowstep', 5, 75, 1, '{}', '{"x": 389, "y": -224}', '{"duration": "3s", "status": "Invisible"}', '🫥');
