INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f9cc296f-809e-4650-a32d-d9b3e1a014bd', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_evasive_shadows', 'Kaçak Gölgeler', 'Evasive Shadows', 'Pasif. Loş ışıkta veya karanlıkta +%15 kaçınma şansı kazanın.', 'Passive. Gain +15% dodge chance while in dim light or darkness.', 'Shadowstep', 30, 225, 2, '{"dc_fade"}', '{"x": 1039, "y": -599}', '{"dodge_chance": "+15%"}', '🥷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b1e7d27c-5d4b-47d1-a84b-7a13e4fbc116', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_shadow_swap', 'Gölge Takası', 'Shadow Swap', 'Bulunduğunuz konuma bir gölge kopyası bırakın. 15m uzaklığa kadar yer değiştirmek için 10s içinde tekrar etkinleştirin.', 'Leave a shadow clone in your current position. Activate again within 10s to swap places up to 15m away.', 'Shadowstep', 35, 250, 2, '{"dc_phantom_step"}', '{"x": 1255, "y": -724}', '{"range": "15m", "duration": "10s"}', '🔄');
